// Detailed prompt format: structured, compact, label-driven.
// The target generator's description field responds best to clear declarative lines, not
// flowing prose. Each line is a self-contained instruction. No meta-
// commentary about what the AI should aim for — just facts.
function buildDetailedSentences(state, lyricsOn, mode) {
  const slots = state.slots.filter(Boolean);
  const primary = slots[0];
  const bpm = inferBPM(state);
  const sentences = [];

  // ── LINE 1: GENRE HEADLINE ──────────────────────────────────────────
  if (slots.length === 1) {
    const s = slots[0];
    const path = [s.genre, s.sub, s.micro].filter(Boolean).join(", ");
    sentences.push({ priority: 1, text: `Genre: ${path.toLowerCase()}.` });
  } else if (slots.length === 2) {
    const a = [slots[0].genre, slots[0].sub].filter(Boolean).join(" ").toLowerCase();
    const b = [slots[1].genre, slots[1].sub].filter(Boolean).join(" ").toLowerCase();
    sentences.push({ priority: 1, text: `Genre: ${a} crossed with ${b}.` });
  } else if (slots.length === 3) {
    const labels = slots.map(s => [s.genre, s.sub].filter(Boolean).join(" ").toLowerCase());
    sentences.push({ priority: 1, text: `Genre: ${labels[0]}, blended with ${labels[1]} and ${labels[2]}.` });
  }

  // ── LINE 2: TEMPO + GROOVE (single compact tempo line) ─────────────
  // Omit the tempo sentence entirely if the user hasn't set a BPM —
  // prevents Suno from anchoring to a random number we invented.
  const groove = useField(state.toggles.groove, state.groove !== "default" ? state.groove : null);
  if (bpm != null) {
    const tempoBits = [`${bpm} BPM`];
    if (groove) tempoBits.push(`${groove.toLowerCase()} groove`);
    sentences.push({ priority: 2, text: `Tempo: ${tempoBits.join(", ")}.` });
  } else if (groove) {
    // BPM unspecified but groove is set — still communicate the rhythmic feel.
    sentences.push({ priority: 2, text: `Groove: ${groove.toLowerCase()}.` });
  }

  // ── LINE 3: VOCALS (explicit and early — critical for the generator) ────────
  if (lyricsOn) {
    const vocal = useField(state.toggles.vocalist, state.vocalist) || "clear lead vocal, confident and forward in the mix";
    const langLabel = state.toggles.language !== "off"
      ? (LANGUAGES.find(l => l.code === state.language)?.label || state.language || "English")
      : null;
    const langBit = langLabel ? `, ${langLabel.toLowerCase()} lyrics` : "";
    sentences.push({ priority: 3,
      text: `Vocals: ${vocal.toLowerCase()}${langBit}.` });
  } else {
    sentences.push({ priority: 3,
      text: `Vocals: none. Fully wordless arrangement, melody carried by instruments.` });
  }

  // ── LINE 4: LYRICAL VIBE (only when lyrics on) ─────────────────────
  if (lyricsOn) {
    const vibe = useField(state.toggles.lyricalVibe, state.lyricalVibe);
    if (vibe) sentences.push({ priority: 4,
      text: `Lyrical tone: ${vibe.toLowerCase()}, using concrete imagery over abstract emotional labels.` });
  }

  // ── LINE 5: MOOD + ENERGY (combined, short) ────────────────────────
  const mood = useField(state.toggles.mood, state.mood);
  const energy = useField(state.toggles.energy, state.energy);
  if (mood || energy) {
    const bits = [];
    if (mood)   bits.push(mood.toLowerCase());
    if (energy) bits.push(`${energy.toLowerCase()} energy arc`);
    sentences.push({ priority: 5, text: `Mood: ${bits.join(", ")}.` });
  }

  // ── LINE 6: INSTRUMENTATION (explicit list, generator-parseable) ────────
  const si = resolveSpecificInstruments(state);
  if (si.length) {
    const detailed = si.map(it =>
      it.articulation
        ? `${it.name.toLowerCase()} with ${it.articulation.toLowerCase()}`
        : it.name.toLowerCase()
    ).join(", ");
    sentences.push({ priority: 6, text: `Instrumentation: ${detailed}.` });
  }

  // ── LINE 7: HARMONY ────────────────────────────────────────────────
  const harm = useField(state.toggles.harmonic, state.harmonic);
  if (harm) sentences.push({ priority: 7,
    text: `Harmony: ${harm.toLowerCase()} voicings and melodic contour.` });

  // ── LINE 8: TEXTURE + MIX (combined) ───────────────────────────────
  const tex = useField(state.toggles.texture, state.texture);
  const mix = useField(state.toggles.mix, state.mix);
  if (tex || mix) {
    const bits = [];
    if (tex) bits.push(tex.toLowerCase());
    if (mix) bits.push(`${mix.toLowerCase()} mix`);
    sentences.push({ priority: 8, text: `Sound: ${bits.join(", ")}.` });
  }

  // ── LINE 9: STRUCTURE HINT (brief, the generator responds to this) ──────────
  if (lyricsOn) {
    sentences.push({ priority: 10,
      text: `Structure: intro, verse, chorus, verse, chorus, bridge, chorus, outro.` });
  } else {
    sentences.push({ priority: 10,
      text: `Structure: intro, main theme, development, climax, resolution.` });
  }

  // ── LINE 10: PRODUCTION DIRECTIVES (concrete, generator-actionable) ─────
  sentences.push({ priority: 11,
    text: `Production: modern, professional, radio-ready, cohesive mix, full frequency balance.` });

  // ── LINE 11: AVOID LIST (Negatives that improve output) ───────
  if (primary) {
    const genreLow = primary.genre.toLowerCase();
    sentences.push({ priority: 12,
      text: `Avoid: generic ${genreLow} tropes, MIDI-stock presets, thin mixing, loop-based repetition without variation.` });
  }

  // ── CHAOS MODE — unhinged creative injections ───────────────────────
  // Pick one atmosphere + one texture + one character angle. Each adds a
  // jarring imaginative frame the generator will try to interpret — which pushes
  // the generation toward weirder, more distinctive results.
  if (mode === "chaos") {
    const atm = CHAOS_ATMOSPHERES[Math.floor(Math.random() * CHAOS_ATMOSPHERES.length)];
    const tex = CHAOS_TEXTURES[Math.floor(Math.random() * CHAOS_TEXTURES.length)];
    sentences.push({ priority: 13, text: `Atmosphere: ${atm}.` });
    sentences.push({ priority: 14, text: `Texture: ${tex}.` });
    if (lyricsOn) {
      const chr = CHAOS_CHARACTERS[Math.floor(Math.random() * CHAOS_CHARACTERS.length)];
      sentences.push({ priority: 15, text: `Narrative frame: ${chr}.` });
    }
  }

  return sentences.sort((a, b) => a.priority - b.priority);
}

function packSentencesToLimit(sentences, limit) {
  let current = "";
  for (const s of sentences) {
    const cand = current ? `${current}\n${s.text}` : s.text;
    if (cand.length <= limit) current = cand;
  }
  if (!current && sentences.length > 0) return safeTruncate(sentences[0].text, limit);
  return current;
}
function safeTruncate(text, limit) {
  if (text.length <= limit) return text;
  const slice = text.slice(0, limit);
  const lp = slice.lastIndexOf(".");
  const lc = slice.lastIndexOf(",");
  const ls = slice.lastIndexOf(" ");
  const cutAt = lp > limit - 60 ? lp + 1 : lc > limit - 30 ? lc : ls > limit - 15 ? ls : limit;
  return slice.slice(0, cutAt).trim();
}
// ── Grammar sanitizer ────────────────────────────────────────────────
// AI music generators parse commas, periods, and plain words
// well. Em-dashes, semicolons, parentheticals, and bracket notation can
// cause prompt drift. This pass normalizes to generator-friendly punctuation.
// Note: hyphens inside words (Hip-Hop, TR-808, Lo-Fi, 12-string) are kept
// because they are part of proper names — removing them would damage meaning.
// Sanitizer: normalize punctuation to generator-friendly forms, but
// preserve structural newlines and label colons that generators use to parse
// directives. Only convert mid-sentence em/en-dashes and semicolons.
// ─────────────────────────────────────────────────────────────────────────
// SUNO VOCAL-TRIGGER SANITIZATION
// When the user wants vocals (lyricsOn=true), certain words in the style
// prompt will cause Suno to generate an instrumental instead. Research
// sources (jackrighteous, hookgenius, undetectr, musicsmith) agree on the
// following high-confidence triggers:
//   - "instrumental" (primary trigger)
//   - "no vocals" / "no voice" / "no singing" / "no rapping"
//   - "wordless" / "voiceless" / "without lyrics" / "without vocals"
//   - "a cappella" (inverse trigger — may confuse model about vocal-only)
// This map is applied ONLY when lyricsOn=true, so instrumental prompts
// still work correctly when the user explicitly wants an instrumental.
// ─────────────────────────────────────────────────────────────────────────
const SUNO_VOCAL_KILLERS = [
  // Phrase-level strips — full patterns with context
  { pat: /\binstrumental\s+only\b/gi,              replace: "" },
  { pat: /\bno\s+vocals?\b/gi,                     replace: "" },
  { pat: /\bno\s+singing\b/gi,                     replace: "" },
  { pat: /\bno\s+rapping\b/gi,                     replace: "" },
  { pat: /\bno\s+voice(s)?\b/gi,                   replace: "" },
  { pat: /\bno\s+lyrics\b/gi,                      replace: "" },
  { pat: /\bno\s+choir\b/gi,                       replace: "" },
  { pat: /\bno\s+oohs?\b/gi,                       replace: "" },
  { pat: /\bno\s+humming\b/gi,                     replace: "" },
  { pat: /\bno\s+voice\s+samples\b/gi,             replace: "" },
  { pat: /\bwithout\s+lyrics\b/gi,                 replace: "" },
  { pat: /\bwithout\s+vocals?\b/gi,                replace: "" },
  // Single-word killers — more dangerous, need careful replacements
  { pat: /\bwordless\s+arrangement\b/gi,           replace: "" },
  { pat: /\bwordless\b/gi,                         replace: "" },
  { pat: /\bvoiceless\b/gi,                        replace: "" },
  { pat: /\ba\s+cappella\b/gi,                     replace: "" },
  { pat: /\bacappella\b/gi,                        replace: "" },
  // The big one — "instrumental" standalone. Replace with safer synonyms.
  // "instrumental epic" (Post-Rock microgenre) → "epic"
  // "contemporary instrumental" (Smooth Jazz) → "contemporary"
  { pat: /\binstrumental\s+(epic|ballad|piece|track)\b/gi, replace: "$1" },
  { pat: /\b(contemporary|cinematic|ambient|orchestral)\s+instrumental\b/gi, replace: "$1" },
  // Bare "instrumental" as adjective — strip it
  { pat: /\binstrumental\b/gi,                     replace: "" },
];

function sanitizeVocalKillers(text) {
  if (!text) return text;
  let out = text;
  for (const { pat, replace } of SUNO_VOCAL_KILLERS) {
    out = out.replace(pat, replace);
  }
  // Cleanup from removed words: collapse whitespace, strip stray commas
  out = out
    .replace(/\s+/g, " ")
    .replace(/,\s*,+/g, ",")
    .replace(/,\s*$/g, "")
    .replace(/^\s*,\s*/g, "")
    .replace(/\s+,/g, ",")
    .trim();
  return out;
}

function sunoSanitize(text, lyricsOn = true) {
  if (!text) return text;
  let out = text
    .replace(/\s*—\s*/g, ", ")          // em-dash → comma
    .replace(/\s*–\s*/g, ", ")          // en-dash → comma
    .replace(/\s*;\s*/g, ", ")          // semicolon → comma
    .replace(/\(([^)]*)\)/g, "$1")      // strip parentheses, keep contents
    .replace(/\s*,\s*,+/g, ", ")        // collapse duplicate commas
    .replace(/[ \t]{2,}/g, " ")         // collapse spaces/tabs but NOT newlines
    .replace(/ *\n *\n+/g, "\n")        // collapse 2+ blank lines to 1
    .replace(/ *\n */g, "\n")           // trim each line
    .replace(/,\s*\./g, ".")            // ", ." → "."
    .replace(/,\s*\n/g, "\n")           // trailing comma before newline
    .replace(/,\s*$/g, "")              // trailing comma at end
    .replace(/\.\s*\./g, ".")           // double period
    .trim();
  // Banned-words guard: words Bubble has banned from prompts. Case-
  // insensitive removal — keeps surrounding context clean. Currently
  // just "heirloom"; extend as needed.
  out = out.replace(/\bheirloom\b/gi, "family");
  // When vocals are requested, strip words that would cause Suno to
  // generate an instrumental by mistake.
  if (lyricsOn) out = sanitizeVocalKillers(out);
  return out;
}

function compressDetailedPrompt(state, lyricsOn, limit, mode) {
  const sentences = buildDetailedSentences(state, lyricsOn, mode);
  const packed = packSentencesToLimit(sentences, limit);
  // ── STRUCTURE INJECTION ──────────────────────────────────────────
  // If the state carries a structure array (from a recipe, mimic pack,
  // or admin tool), append it as square-bracket section tags. Suno &
  // Udio respond strongly to these arrangement markers — they turn a
  // vague sonic prompt into a producer-grade roadmap with intro /
  // verse / pre-chorus / chorus / bridge / outro beats.
  // Structure tags bypass sunoSanitize's em-dash replacement because
  // they're purely bracketed metadata, not prose. We assemble before
  // truncation so structure has priority if the limit bites.
  let withStructure = packed;
  if (Array.isArray(state.structure) && state.structure.length > 0) {
    const tags = state.structure.map(s => `[${s}]`).join(" ");
    // Prefer newline separator so the model reads structure as a
    // distinct block from the sonic prose above it.
    withStructure = packed ? `${packed}\n\n${tags}` : tags;
  }
  // ── ARTIST VOCABULARY INJECTION ──────────────────────────────────
  // If the state carries an artistVocabulary object (set by
  // applyMimicPack when a curated pack has a vocabulary entry in
  // ARTIST_VOCABULARY), flatten it into a "[sonic DNA: …]" block and
  // append as a third, distinct section. This tells the model which
  // production-technique vocabulary to target without naming the
  // artist. Placed AFTER structure so the model reads arrangement
  // first, then sonic fingerprint — matches how a producer would
  // brief a session.
  let withVocabulary = withStructure;
  if (state.artistVocabulary) {
    const vocabTag = formatArtistVocabulary(state.artistVocabulary);
    if (vocabTag) {
      withVocabulary = withStructure ? `${withStructure}\n\n${vocabTag}` : vocabTag;
    }
  }
  const raw = withVocabulary.length > limit ? safeTruncate(withVocabulary, limit) : withVocabulary;
  const finalText = sunoSanitize(raw, lyricsOn);
  return {
    text: finalText, length: finalText.length,
    compressed: finalText.length < sentences.reduce((a, s) => a + s.text.length + 1, 0),
    level: 0,
  };
}
const SHORT_FILLERS = ["modern production","full arrangement","cohesive mix","detailed sonics","clean master"];
function padShortToBudget(text, limit, state) {
  let result = text;
  const candidates = [];
  if (state.harmonic && !text.toLowerCase().includes(state.harmonic.toLowerCase())) candidates.push(state.harmonic.toLowerCase());
  if (state.texture && !text.toLowerCase().includes(state.texture.toLowerCase())) candidates.push(state.texture.toLowerCase());
  if (state.energy && !text.toLowerCase().includes(state.energy.toLowerCase())) candidates.push(state.energy.toLowerCase());
  candidates.push(...SHORT_FILLERS);
  for (const extra of candidates) {
    if (result.length >= limit - 10) break;
    const cand = result + ", " + extra;
    if (cand.length <= limit) result = cand; else break;
  }
  return result;
}
function compressShortPrompt(state, lyricsOn, limit) {
  const cands = [shortPromptL0, shortPromptL1, shortPromptL2, shortPromptL3, shortPromptL4]
    .map((fn, i) => ({ text: fn(state, lyricsOn), level: i }));
  const fitting = cands.filter(c => c.text.length <= limit);
  if (fitting.length === 0) return { text: sunoSanitize(safeTruncate(cands[cands.length - 1].text, limit), lyricsOn), compressed: true, level: 5 };
  const best = fitting.sort((a, b) => b.text.length - a.text.length)[0];
  let text = best.text;
  if (text.length < limit - 10) text = padShortToBudget(text, limit, state);
  if (text.length > limit) text = safeTruncate(text, limit);
  text = sunoSanitize(text, lyricsOn);
  return { text, compressed: best.level > 0 || text !== best.text, level: best.level };
}

// ── Pop-hit probability scorer ───────────────────────────────────────────
// Rule-based 0–100 score reflecting how closely the current selection
// matches contemporary worldwide pop-hit characteristics (chart-friendly
// genre, production norms, BPM window, vocal accessibility).
const POP_HIT_SCORE = {
  GENRE_TOP:   ["Pop","Hip-Hop","R&B / Soul","Latin","Electronic","Country","K-Pop","Afrobeats"],
  GENRE_HIGH:  ["Trap","Melodic Rap","Dance-Pop","Synth-Pop","Hyperpop","Alt R&B","Trap Soul","Reggaeton","Afrobeats","Amapiano","Dancehall"],
  GENRE_MID:   ["Indie","Alternative","Rock","House","EDM","Dance","Disco"],
  GENRE_NICHE: ["Jazz","Classical","Folk","Ambient","Experimental","Noise","Drone","Free Jazz","Gabber","Breakcore","Industrial","Metal","Black Metal","Doom","Drum & Bass","Hardcore","Grindcore","Post-Rock","Post-Punk","Math Rock","Krautrock"],
  MOOD_HIT: ["Euphoric","Uplifting","Catchy","Summery","Romantic","Confident","Sensual","Playful","Hopeful","Dreamy","Nostalgic"],
  MOOD_OK:  ["Melancholic","Tender","Pensive","Mysterious","Moody"],
  MOOD_LOW: ["Abrasive","Unsettling","Hostile","Dissonant","Chaotic","Bleak","Tortured","Nihilistic"],
  LANG_HIGH: ["en","es","pt","ko","hi","zh"],
  LANG_MID:  ["fr","ja","id","ar","tr","de","it","ru","bn"],
  VIBE_HIT: ["Party celebration","Romantic devotion","Braggadocio flex","Confessional diary","Nostalgic storytelling","Coming-of-age narrative","Hedonistic escapism","Heartbreak elegy"],
  VIBE_LOW: ["Surreal dreamscape","Abstract poetry","Mythic / allegorical","Political protest","Spiritual seeking","Existential questioning"],
};

function calcPopHitScore(state, lyricsOn) {
  let score = 50;
  const notes = [];

  const slots = (state.slots || []).filter(Boolean);
  if (slots.length > 0) {
    let gScore = 0;
    slots.forEach(slot => {
      const g = slot.genre || "";
      if (POP_HIT_SCORE.GENRE_TOP.includes(g))         gScore += 10;
      else if (POP_HIT_SCORE.GENRE_HIGH.includes(g))   gScore += 7;
      else if (POP_HIT_SCORE.GENRE_MID.includes(g))    gScore += 2;
      else if (POP_HIT_SCORE.GENRE_NICHE.includes(g))  gScore -= 10;
      else gScore += 1;
    });
    gScore = Math.max(-15, Math.min(22, gScore));
    score += gScore;
    if (gScore >= 15)       notes.push("Mainstream genre mix");
    else if (gScore >= 7)   notes.push("Commercial genre lean");
    else if (gScore <= -8)  notes.push("Niche genre for mass pop");
  } else {
    score -= 8;
    notes.push("No genre anchor selected");
  }

  const bpm = inferBPM(state);
  if (bpm != null) {
    if (bpm >= 95 && bpm <= 130)       { score += 10; notes.push("BPM in pop sweet spot"); }
    else if (bpm >= 80 && bpm <= 140)  { score += 5; }
    else if (bpm < 70 || bpm > 170)    { score -= 8; notes.push("BPM outside mass appeal"); }
  }

  if (lyricsOn) {
    score += 10;
    const langCode = state.language;
    if (POP_HIT_SCORE.LANG_HIGH.includes(langCode))     { score += 6; notes.push("Top streaming language"); }
    else if (POP_HIT_SCORE.LANG_MID.includes(langCode)) { score += 2; }
    else if (langCode && langCode !== "en")             { notes.push("Less commercial language"); }
    const vibe = state.lyricalVibe || "";
    if (POP_HIT_SCORE.VIBE_HIT.includes(vibe))          { score += 2; }
    else if (POP_HIT_SCORE.VIBE_LOW.includes(vibe))     { score -= 6; notes.push("Abstract lyric framing"); }
  } else {
    score -= 14;
    notes.push("Modern hits are vocal driven");
  }

  const mood = state.mood || "";
  if (POP_HIT_SCORE.MOOD_HIT.includes(mood))       { score += 8; notes.push("Chart friendly mood"); }
  else if (POP_HIT_SCORE.MOOD_OK.includes(mood))   { score += 2; }
  else if (POP_HIT_SCORE.MOOD_LOW.includes(mood))  { score -= 10; notes.push("Mood skews uncommercial"); }

  const groove = state.groove || "";
  const POP_GROOVE = ["4-on-the-floor","reggaeton","dembow","trap","afrobeats","amapiano","halftime"];
  if (POP_GROOVE.some(g => groove.toLowerCase().includes(g))) score += 4;

  const mix = (state.mix || "").toLowerCase();
  if (mix.includes("polished") || mix.includes("clean") || mix.includes("radio")) score += 3;
  if (mix.includes("lo-fi") || mix.includes("distressed") || mix.includes("raw")) score -= 3;

  score = Math.max(3, Math.min(99, Math.round(score)));

  let verdict;
  if (score >= 85)      verdict = "Very high hit potential";
  else if (score >= 70) verdict = "Strong commercial potential";
  else if (score >= 55) verdict = "Moderate chart chance";
  else if (score >= 40) verdict = "Niche / cult appeal";
  else if (score >= 25) verdict = "Low mainstream potential";
  else                  verdict = "Deliberately uncommercial";

  return { score, verdict, notes: notes.slice(0, 4) };
}

// ────────────────────────────────────────────────────────────────────────────
// UTILITIES
// ────────────────────────────────────────────────────────────────────────────
function pickOne(arr) { return arr[Math.floor(Math.random() * arr.length)]; }
function pickMany(arr, n) { return [...arr].sort(() => Math.random() - 0.5).slice(0, Math.min(n, arr.length)); }

function copyToClipboard(text) {
  return new Promise((resolve) => {
    if (typeof navigator !== "undefined" && navigator.clipboard?.writeText) {
      navigator.clipboard.writeText(text).then(() => resolve(true)).catch(() => resolve(fallbackCopy(text)));
    } else resolve(fallbackCopy(text));
  });
}
function fallbackCopy(text) {
  try {
    const ta = document.createElement("textarea");
    ta.value = text;
    ta.style.cssText = "position:fixed;top:-9999px;opacity:0";
    document.body.appendChild(ta);
    ta.select();
    const ok = document.execCommand("copy");
    document.body.removeChild(ta);
    return ok;
  } catch { return false; }
}

// ════════════════════════════════════════════════════════════════════════════
// UI PRIMITIVES — Linear-inspired design system components
// ════════════════════════════════════════════════════════════════════════════

// Mono label — small uppercase tracking label (section headers, status)
function Label({ children, color = T.textTer, size = T.fs_xs, style }) {
  return (
    <span style={{
      fontFamily: T.font_mono, fontSize: size,
      letterSpacing: "0.08em", color, textTransform: "uppercase",
      fontWeight: 500, ...style,
    }}>{children}</span>
  );
}

// Button primitive — primary and secondary variants only
function Button({ children, variant = "secondary", size = "md", onClick, disabled, type = "button", style, title }) {
  const sizes = {
    sm: { padding: "6px 10px", fontSize: T.fs_sm, height: 28 },
    md: { padding: "8px 14px", fontSize: T.fs_md, height: 32 },
    lg: { padding: "10px 18px", fontSize: T.fs_base, height: 40 },
  };
  const variants = {
    primary: {
      background: T.text, color: T.bg,
      border: `1px solid ${T.text}`,
    },
    secondary: {
      background: T.elevated, color: T.text,
      border: `1px solid ${T.border}`,
    },
    ghost: {
      background: "transparent", color: T.textSec,
      border: "1px solid transparent",
    },
    danger: {
      background: "transparent", color: T.danger,
      border: `1px solid ${T.border}`,
    },
  };
  const [hover, setHover] = useState(false);
  const base = variants[variant];
  const hoverStyle = hover && !disabled ? (
    variant === "primary"   ? { background: "#FFFFFF" } :
    variant === "secondary" ? { background: T.hover, borderColor: T.borderHi } :
    variant === "ghost"     ? { background: T.hover, color: T.text } :
    variant === "danger"    ? { background: "rgba(239,68,68,0.08)", borderColor: T.danger } : {}
  ) : {};
  return (
    <button type={type}
      onClick={disabled ? undefined : (e) => { playSwitchSound(); onClick && onClick(e); }}
      disabled={disabled} title={title}
      onMouseEnter={() => setHover(true)} onMouseLeave={() => setHover(false)}
      style={{
        ...sizes[size], ...base, ...hoverStyle,
        fontFamily: T.font_sans, fontWeight: 500,
        cursor: disabled ? "not-allowed" : "pointer",
        opacity: disabled ? 0.4 : 1,
        borderRadius: T.r_md, userSelect: "none",
        display: "inline-flex", alignItems: "center", gap: 6,
        transition: `all ${T.dur_fast} ${T.ease}`,
        outline: "none",
        ...style,
      }}>{children}</button>
  );
}

// obfuscateLabel — Given a real genre/option name, return a block-char string
// of roughly proportional length. Used to scrub tier-locked labels so the
// real name never reaches the DOM. Not cryptographically secure — a paranoid
// "keeps casual inspection from exposing premium content" measure only.
// True content protection requires a backend; see Task 4 discussion.
function obfuscateLabel(name) {
  if (!name || typeof name !== "string") return "████";
  // Map char count to block count with a floor + ceiling so very short or
  // very long names still look plausible as blurred chips.
  const len = Math.min(20, Math.max(4, Math.ceil(name.length * 0.8)));
  // Split with a mid-word space to mimic how real labels wrap
  if (len > 7) {
    const firstWord = Math.floor(len * 0.45);
    return "█".repeat(firstWord) + " " + "█".repeat(len - firstWord);
  }
  return "█".repeat(len);
}

// Chip — single select / multi-select option. Casino outline randomly applied during rolling.
// tierLocked: option exists in the catalog but is hidden behind a tier gate. Displayed
// with the label blurred AND scrubbed (real name never enters the rendered DOM).
// Non-interactive UNLESS onLockedClick is provided — in which case clicking the locked
// chip fires the redirect handler (e.g. opens SalesModal).
function Chip({ label, selected, onClick, onDoubleClick, onLockToggle, favorite, locked, disabled, size = "md", casinoOutline, tierLocked, onLockedClick, titleOverride }) {
  const [hover, setHover] = useState(false);
  const { layout } = useLayout();
  const isMobile = layout === "mobile";
  // A tier-locked chip is inactive UNLESS it has a redirect click handler,
  // in which case it's clickable (only that one gesture — no fav, no lock).
  const hasLockedRedirect = tierLocked && onLockedClick;
  const inactive = disabled || (tierLocked && !onLockedClick);
  // Chip sizing: use minHeight (not height) so long labels with descenders
  // (like "Screamed verse / melodic chorus") always fit vertically without
  // clipping 'y' 'g' 'p' tails. lineHeight 1.4 gives glyph descenders room
  // inside the padding box. Line-height + padding combine to the displayed
  // total, so minHeight just acts as the floor for uniformity between rows.
  const sizes = isMobile ? {
    sm: { padding: "9px 14px", fontSize: T.fs_md, minHeight: 40 },
    md: { padding: "11px 16px", fontSize: T.fs_md, minHeight: 44 },
  } : {
    sm: { padding: "5px 10px", fontSize: T.fs_sm, minHeight: 26 },
    md: { padding: "7px 12px", fontSize: T.fs_md, minHeight: 30 },
  };
  const borderColor = casinoOutline
    ? casinoOutline
    : locked
      ? V.neonGold
      : selected
        ? T.accentBorder
        : T.border;
  const base = {
    background: selected ? T.accentBg : (hover && !inactive ? T.hover : "transparent"),
    color: selected ? T.accentHi : (hover && !inactive ? T.text : T.textSec),
    border: `1px solid ${tierLocked ? T.border : borderColor}`,
    boxShadow: tierLocked
      ? "none"
      : casinoOutline
        ? `0 0 0 1px ${casinoOutline}, 0 0 12px ${casinoOutline}66`
        : locked
          ? `0 0 0 1px ${V.neonGold}, 0 0 10px ${V.neonGold}55`
          : "none",
  };
  return (
    <span
      onClick={
        hasLockedRedirect
          ? (e) => { e.stopPropagation(); playSwitchSound(); onLockedClick(); }
          : inactive ? undefined : (e) => { playSwitchSound(); onClick && onClick(e); }
      }
      onDoubleClick={inactive ? undefined : onDoubleClick}
      onContextMenu={inactive ? undefined : (e) => {
        if (onLockToggle) { e.preventDefault(); onLockToggle(); }
      }}
      onMouseEnter={() => (!inactive || hasLockedRedirect) && setHover(true)} onMouseLeave={() => setHover(false)}
      title={titleOverride
        ? titleOverride
        : tierLocked
        ? (hasLockedRedirect ? "Locked — click to upgrade" : "Upgrade tier to unlock this option")
        : onLockToggle
          ? "Click: select · Double-click: favorite · Right-click: lock"
          : onDoubleClick
            ? "Click: select · Double-click: favorite"
            : undefined}
      style={{
        ...sizes[size], ...base,
        fontFamily: T.font_sans,
        fontWeight: 450,
        lineHeight: 1.4,
        whiteSpace: "nowrap",
        cursor: hasLockedRedirect ? "pointer" : (inactive ? "not-allowed" : "pointer"),
        borderRadius: T.r_md, userSelect: "none",
        display: "inline-flex", alignItems: "center", gap: 6,
        transition: `background ${T.dur_fast} ${T.ease}, color ${T.dur_fast} ${T.ease}, border-color ${T.dur_fast} ${T.ease}, box-shadow ${T.dur_fast} ${T.ease}`,
        opacity: tierLocked ? 0.7 : disabled ? 0.35 : 1,
        position: "relative", overflow: "hidden",
        pointerEvents: (tierLocked && !hasLockedRedirect) ? "none" : "auto",
      }}
      aria-label={tierLocked ? (hasLockedRedirect ? "Locked option — click to upgrade" : "Locked option — upgrade tier to unlock") : undefined}>
      {/* Diagonal-stripe overlay for locked state — visually distinct from loading */}
      {tierLocked && (
        <span aria-hidden="true" style={{
          position: "absolute", inset: 0,
          backgroundImage: `repeating-linear-gradient(135deg,
            rgba(148,158,182,0.06) 0 4px,
            transparent 4px 8px)`,
          pointerEvents: "none",
        }} />
      )}
      {locked && !tierLocked && (
        <span style={{
          color: V.neonGold, fontSize: T.fs_xs, lineHeight: 1,
          textShadow: `0 0 6px ${V.neonGold}`,
        }}>🔒</span>
      )}
      {favorite && !locked && !tierLocked && (
        <span style={{ color: T.warning, fontSize: T.fs_xs, lineHeight: 1 }}>●</span>
      )}
      {tierLocked && (
        <span aria-hidden="true" style={{
          color: T.accentHi, fontSize: T.fs_xs, lineHeight: 1,
          fontFamily: T.font_mono, fontWeight: 700, letterSpacing: "0.08em",
          padding: "1px 4px", borderRadius: 2,
          background: `${T.accent}22`,
          border: `1px solid ${T.accent}55`,
          textShadow: `0 0 4px ${T.accent}66`,
          position: "relative", zIndex: 1,
          flexShrink: 0,
        }}>🔒 PRO</span>
      )}
      <span
        aria-hidden={tierLocked ? "true" : undefined}
        style={{
          filter: tierLocked ? "blur(5px)" : "none",
          transition: "filter 180ms ease-out",
          userSelect: tierLocked ? "none" : "auto",
          position: "relative", zIndex: 1,
          flexShrink: 0,
        }}>
        {tierLocked ? obfuscateLabel(label) : label}
      </span>
    </span>
  );
}

// AddCustomChip — renders as a "+" button that expands into an inline input
// when clicked. Enter commits, Escape/blur cancels. Pro+ tier only; for Free
// users, it renders a tier-locked placeholder that navigates to the Shop.
function AddCustomChip({ sectionId, onLockedClick }) {
  const { features } = useTier();
  const { addCustomOption } = useCustomOptions();
  const { layout } = useLayout();
  const isMobile = layout === "mobile";
  const [editing, setEditing] = useState(false);
  const [value, setValue] = useState("");
  const [hover, setHover] = useState(false);
  const inputRef = useRef(null);

  // Tier gate: feature is Pro+ only. We piggyback on presets as our Pro-gate
  // indicator since custom options are a similar "power user" feature.
  const allowed = features?.presets === true;

  useEffect(() => {
    if (editing && inputRef.current) inputRef.current.focus();
  }, [editing]);

  const commit = () => {
    addCustomOption(sectionId, value);
    setValue("");
    setEditing(false);
  };
  const cancel = () => { setValue(""); setEditing(false); };

  const baseStyle = {
    padding: isMobile ? "9px 12px" : "4px 10px",
    fontSize: isMobile ? T.fs_md : T.fs_sm,
    minHeight: isMobile ? 40 : 24,
    height: isMobile ? undefined : 24,
    fontFamily: T.font_sans,
    fontWeight: 500,
    borderRadius: T.r_md,
    userSelect: "none",
    display: "inline-flex",
    alignItems: "center",
    gap: 4,
    transition: `all ${T.dur_fast} ${T.ease}`,
    cursor: "pointer",
  };

  // FREE TIER: blue-highlighted locked chip, opens SalesModal on click
  if (!allowed) {
    return (
      <span
        onClick={() => { playSwitchSound(); onLockedClick && onLockedClick(); }}
        onMouseEnter={() => setHover(true)}
        onMouseLeave={() => setHover(false)}
        title="Custom options are a Pro feature — click to upgrade"
        style={{
          ...baseStyle,
          background: hover ? "#3B82F622" : "#3B82F615",
          border: `1px solid ${hover ? "#3B82F6" : "#3B82F688"}`,
          color: "#3B82F6",
          fontWeight: 600,
          boxShadow: hover
            ? "0 0 0 3px #3B82F622, 0 2px 8px #3B82F633"
            : "0 0 0 1px #3B82F622",
          transition: `all ${T.dur_fast} ${T.ease}`,
        }}
      >
        <span style={{ fontSize: 11 }}>🔒</span>
        <span>+ add custom</span>
      </span>
    );
  }

  // INPUT MODE
  if (editing) {
    return (
      <span style={{
        ...baseStyle,
        background: T.elevated,
        border: `1px solid ${T.accentBorder}`,
        padding: isMobile ? "4px 8px" : "2px 6px",
      }}>
        <input
          ref={inputRef}
          value={value}
          onChange={(e) => setValue(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter") { e.preventDefault(); commit(); }
            else if (e.key === "Escape") { e.preventDefault(); cancel(); }
          }}
          onBlur={() => {
            // Commit on blur if there's content, otherwise cancel
            if (value.trim()) commit(); else cancel();
          }}
          placeholder="your own option…"
          style={{
            width: isMobile ? 140 : 120,
            border: "none", outline: "none",
            background: "transparent",
            color: T.text,
            fontFamily: T.font_sans,
            fontSize: isMobile ? 16 : T.fs_sm,  // 16px prevents iOS zoom
            padding: isMobile ? "4px 2px" : "0 2px",
          }}
        />
      </span>
    );
  }

  // IDLE MODE — plus button
  return (
    <span
      onClick={() => { playSwitchSound(); setEditing(true); }}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      title="Add your own option — Enter to save, right-click to delete custom chips"
      style={{
        ...baseStyle,
        background: hover ? T.hover : "transparent",
        border: `1px dashed ${hover ? T.accentBorder : T.border}`,
        color: hover ? T.text : T.textSec,
      }}
    >
      <span style={{ fontSize: 14, lineHeight: 1, fontWeight: 700 }}>+</span>
      <span>custom</span>
    </span>
  );
}


function TriToggle({ value, onChange }) {
  const { features } = useTier();
  const onAllowed = features ? features.hasOnToggle !== false : true;
  const states = [
    { id: "off",  label: "Off",  locked: false },
    { id: "auto", label: "Auto", locked: false },
    { id: "on",   label: "On",   locked: !onAllowed },
  ];
  // If current value is "on" but tier blocks it, fall back to auto
  useEffect(() => {
    if (!onAllowed && value === "on") onChange("auto");
  }, [onAllowed, value]);

  const activeIdx = states.findIndex(s => s.id === value);
  return (
    <div style={{
      display: "inline-flex", position: "relative",
      background: T.bg, border: `1px solid ${T.border}`,
      borderRadius: T.r_md, padding: 2, height: 26,
    }}>
      <div style={{
        position: "absolute",
        top: 2, bottom: 2,
        left: `calc(${activeIdx * 33.333}% + 2px)`,
        width: "calc(33.333% - 4px)",
        background: value === "on"
          ? "#10b981"
          : (value === "off" ? "#ef4444" : T.elevated),
        borderRadius: T.r_sm,
        transition: `all ${T.dur_norm} ${T.ease}`,
        boxShadow: value === "on"
          ? "0 0 8px #10b98166"
          : (value === "off" ? "0 0 6px #ef444466" : "none"),
      }} />
      {states.map(s => {
        const active = s.id === value;
        return (
          <button key={s.id} type="button"
            onClick={() => {
              if (s.locked) return;
              if (s.id !== value) playSwitchSound();
              onChange(s.id);
            }}
            disabled={s.locked}
            title={s.locked ? "Upgrade to Pro to use the On state" : undefined}
            style={{
              position: "relative", zIndex: 1,
              background: "transparent", border: "none",
              color: s.locked
                ? T.textMuted
                : active
                    ? ((s.id === "on" || s.id === "off") ? "#FFFFFF" : T.text)
                    : T.textTer,
              padding: "0 12px", fontSize: T.fs_xs, minWidth: 46,
              fontFamily: T.font_sans, fontWeight: 500,
              cursor: s.locked ? "not-allowed" : "pointer",
              transition: `color ${T.dur_fast} ${T.ease}`,
              display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 3,
            }}>
            {s.label}
            {s.locked && <span style={{ fontSize: 8, opacity: 0.6 }}>🔒</span>}
          </button>
        );
      })}
    </div>
  );
}

// Section — wraps a group of options. Single consistent shell.
function Section({ title, children, hint, toggle, onToggleChange, extra, filled }) {
  const disabled = toggle === "off";
  // LED shows when a section is active (toggle not "off"). Green = user has
  // picked at least one element in this section; red = section still empty.
  const showLed = !disabled && filled !== undefined;
  const ledGreen = filled === true;
  return (
    <div style={{ paddingTop: T.s5, paddingBottom: T.s1 }}>
      <style>{`
        @keyframes sectionLedPulseGreen {
          0%, 100% {
            background: #10b981;
            box-shadow: 0 0 3px #10b98166, 0 0 0 0 #10b98133;
          }
          50% {
            background: #34d399;
            box-shadow: 0 0 6px #10b981bb, 0 0 0 2px #10b98111;
          }
        }
        @keyframes sectionLedPulseRed {
          0%, 100% {
            background: #ef4444;
            box-shadow: 0 0 3px #ef444466, 0 0 0 0 #ef444433;
          }
          50% {
            background: #f87171;
            box-shadow: 0 0 6px #ef4444bb, 0 0 0 2px #ef444411;
          }
        }
      `}</style>
      <div style={{
        display: "flex", alignItems: "center", justifyContent: "space-between",
        gap: T.s4, marginBottom: T.s4, flexWrap: "wrap",
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: T.s3 }}>
          {showLed && (
            <span
              aria-label={ledGreen ? "section has selection" : "section empty"}
              style={{
                display: "inline-block",
                width: 9, height: 9, borderRadius: "50%",
                animation: `${ledGreen ? "sectionLedPulseGreen" : "sectionLedPulseRed"} 1.8s ease-in-out infinite`,
                flexShrink: 0,
              }} />
          )}
          <Label color={disabled ? T.textMuted : T.textSec} size={T.fs_sm}>{title}</Label>
          {hint && <span style={{ fontSize: T.fs_sm, color: T.textTer, fontFamily: T.font_sans }}>{hint}</span>}
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: T.s3 }}>
          {extra}
          {toggle !== undefined && onToggleChange && (
            <TriToggle value={toggle} onChange={onToggleChange} />
          )}
        </div>
      </div>
      <div style={{
        opacity: disabled ? 0.35 : 1,
        pointerEvents: disabled ? "none" : "auto",
        transition: `opacity ${T.dur_norm} ${T.ease}`,
        padding: `${T.s3}px ${T.s4}px`,
        background: filled === true ? `${T.accent}06` : T.surface,
        border: `1px solid ${filled === true ? T.accentBorder : T.border}`,
        borderRadius: T.r_md,
        boxShadow: filled === true
          ? `0 0 0 1px ${T.accentBorder}22, 0 2px 8px ${T.accent}10`
          : `0 1px 2px rgba(0,0,0,0.04)`,
      }}>{children}</div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// CUBICLE — compact collapsible tile for the engine element grid.
// When closed: shows name + LED + value preview in a uniform box.
// When open: same tile but expands to full-width row below, revealing
// the full section content (chips, toggles, reroll, lock, etc.).
// Only ONE cubicle is open at a time — click another to swap.
// ════════════════════════════════════════════════════════════════════════════
function Cubicle({ id, icon, title, description, valuePreview, filled, isOpen, onToggle, toggle, children, extra, hint, alwaysOpen = false }) {
  const disabled = toggle === "off";
  const showLed = !disabled && filled !== undefined;
  const ledGreen = filled === true;
  const { layout } = useLayout();
  const isMobile = layout === "mobile";
  // Suppress the chevron and click handlers when the cubicle is always open
  // (e.g. BPM which lives below the grid and never collapses).
  const headerClickable = !disabled && !alwaysOpen;

  // ── POPOVER DROP-DOWN MODEL ──────────────────────────────────────────
  // Cubicle tile STAYS IN PLACE in the grid — never repositions, never
  // resizes. When opened, the content panel is absolute-positioned
  // OUTSIDE the grid cell: it drops from the bottom of the tile, spans
  // the full grid-row width, and overlays sibling cubicles below without
  // disturbing layout. The tile itself gets a crisp white outline so the
  // user can see which one is active. This is the real "drop-down"
  // pattern — content appears, layout stays put.

  const WHITE_OUTLINE = "#FFFFFF";

  // ── OUTSIDE-CLICK TO CLOSE ───────────────────────────────────────────
  // While the popover is open, any click that lands OUTSIDE both the tile
  // header and the popover panel closes the cubicle. Scroll is unaffected
  // (no scrim). On mobile the ✕ button is the primary dismiss target; this
  // listener is the belt-and-suspenders backup for taps in the margins.
  const cubicleRootRef = useRef(null);
  useEffect(() => {
    if (!isOpen) return;
    const handler = (e) => {
      const root = cubicleRootRef.current;
      if (!root) return;
      // If the click is inside the tile itself (header/icon/LED) do nothing
      // — header's own onClick handles toggle. Same for the popover content.
      if (root.contains(e.target)) return;
      // Also ignore clicks inside any element marked as popover (handles
      // the mobile fixed-bottom panel that's outside the tile's DOM tree).
      const popover = e.target.closest?.('[data-cubicle-popover="true"]');
      if (popover) return;
      // Outside click — close the cubicle.
      onToggle(id);
    };
    // Use capture phase so we see the click before downstream handlers
    // inside other cubicles can re-open something else in the same tick.
    // setTimeout defer prevents the opening click itself from triggering
    // an immediate close (event bubbles after the cubicle has rendered).
    const t = setTimeout(() => {
      document.addEventListener("mousedown", handler, true);
      document.addEventListener("touchstart", handler, true);
    }, 0);
    return () => {
      clearTimeout(t);
      document.removeEventListener("mousedown", handler, true);
      document.removeEventListener("touchstart", handler, true);
    };
  }, [isOpen, id, onToggle]);

  const borderColor = isOpen
    ? WHITE_OUTLINE
    : (filled === true ? V.neonGold + "66" : T.border);
  const shadowGlow = isOpen
    ? `0 0 20px rgba(255,255,255,0.28), 0 0 2px rgba(255,255,255,0.6), 0 4px 16px rgba(0,0,0,0.1)`
    : (filled === true
        ? `0 0 12px ${V.neonGold}22, 0 2px 8px rgba(0,0,0,0.06)`
        : `0 1px 3px rgba(0,0,0,0.06), inset 0 1px 0 rgba(255,255,255,0.02)`);
  const surfaceGradient = filled === true
    ? `linear-gradient(145deg, ${V.neonGold}12 0%, ${T.surface} 40%, ${T.surface} 100%)`
    : (isOpen
        ? `linear-gradient(145deg, rgba(255,255,255,0.04) 0%, ${T.surface} 50%, ${T.surface} 100%)`
        : `linear-gradient(145deg, ${T.surface} 0%, ${T.elevated} 100%)`);

  // alwaysOpen cubicles (BPM) render as a traditional expand-in-place
  // panel since they live below the grid on their own row.
  if (alwaysOpen) {
    return (
      <div
        style={{
          background: surfaceGradient,
          border: `1px solid ${borderColor}`,
          borderRadius: T.r_md,
          boxShadow: shadowGlow,
          overflow: "hidden",
          transition: `all 240ms cubic-bezier(0.16, 1, 0.3, 1)`,
          opacity: disabled ? 0.5 : 1,
          position: "relative",
        }}>
        <style>{`
          @keyframes cubicleLedPulseGreen {
            0%, 100% { box-shadow: 0 0 0 0 #10b98100, 0 0 6px #10b981aa; }
            50%      { box-shadow: 0 0 0 4px #10b98122, 0 0 10px #10b981ee; }
          }
          @keyframes cubicleLedPulseRed {
            0%, 100% { box-shadow: 0 0 0 0 #ef444400, 0 0 5px #ef4444aa; }
            50%      { box-shadow: 0 0 0 3px #ef444422, 0 0 8px #ef4444cc; }
          }
        `}</style>
        <CubicleHeader
          id={id} icon={icon} title={title} description={description}
          valuePreview={valuePreview} filled={filled} isOpen={true}
          disabled={disabled} showLed={showLed} ledGreen={ledGreen}
          headerClickable={false}
          onClick={() => {}}
        />
        <div style={{
          padding: `${T.s3}px ${T.s4}px ${T.s4}px`,
          borderTop: `1px solid ${filled === true ? V.neonGold + "33" : T.border}`,
          background: `linear-gradient(180deg, ${T.surface} 0%, ${T.elevated}40 100%)`,
        }}>
          {(extra || hint) && (
            <div style={{
              display: "flex", alignItems: "center", justifyContent: "space-between",
              gap: T.s2, flexWrap: "wrap", marginBottom: T.s3,
            }}>
              {hint && <span style={{ fontSize: T.fs_sm, color: T.textTer, fontFamily: T.font_sans }}>{hint}</span>}
              {extra && <div style={{ display: "flex", alignItems: "center", gap: T.s3, marginLeft: "auto" }}>{extra}</div>}
            </div>
          )}
          {children}
        </div>
      </div>
    );
  }

  // Collapsible cubicle: tile stays in place (closed) OR tile stays in
  // place + absolute-positioned popover panel drops beneath (open).
  return (
    <div style={{ position: "relative" }}>
      {/* The tile itself — always rendered in its grid slot, always this size */}
      <div
        ref={cubicleRootRef}
        style={{
          background: surfaceGradient,
          border: `${isOpen ? 2 : 1}px solid ${borderColor}`,
          borderRadius: T.r_md,
          boxShadow: shadowGlow,
          overflow: "hidden",
          transition: `all 240ms cubic-bezier(0.16, 1, 0.3, 1)`,
          opacity: disabled ? 0.5 : 1,
          position: "relative",
          zIndex: isOpen ? 5 : 1,
        }}>
        <style>{`
          @keyframes cubicleLedPulseGreen {
            0%, 100% { box-shadow: 0 0 0 0 #10b98100, 0 0 6px #10b981aa; }
            50%      { box-shadow: 0 0 0 4px #10b98122, 0 0 10px #10b981ee; }
          }
          @keyframes cubicleLedPulseRed {
            0%, 100% { box-shadow: 0 0 0 0 #ef444400, 0 0 5px #ef4444aa; }
            50%      { box-shadow: 0 0 0 3px #ef444422, 0 0 8px #ef4444cc; }
          }
          @keyframes cubicleBorderShimmer {
            0%, 100% { opacity: 0.5; }
            50%      { opacity: 1; }
          }
          @keyframes cubiclePopoverIn {
            from { opacity: 0; transform: translateY(-6px) scale(0.995); }
            to   { opacity: 1; transform: translateY(0) scale(1); }
          }
        `}</style>
        {filled === true && (
          <div style={{
            position: "absolute", top: 0, left: 0, right: 0, height: 1,
            background: `linear-gradient(90deg, transparent 0%, ${V.neonGold} 50%, transparent 100%)`,
            animation: "cubicleBorderShimmer 3.2s ease-in-out infinite",
            pointerEvents: "none",
          }} />
        )}
        <CubicleHeader
          id={id} icon={icon} title={title} description={description}
          valuePreview={valuePreview} filled={filled} isOpen={isOpen}
          disabled={disabled} showLed={showLed} ledGreen={ledGreen}
          headerClickable={headerClickable}
          onClick={() => {
            if (!headerClickable) return;
            playSwitchSound();
            onToggle(id);
          }}
        />
      </div>

      {/* ── DROP-DOWN POPOVER ─ anchored to the tile's bottom edge.
          Spans the full grid-row width so chips have room to breathe.
          Does NOT push sibling cubicles — they stay where they were.
          On mobile: anchors to viewport left/right edges so content
          reads across the full narrow screen (no side gutters eating
          real estate). Capped at a viewport-proportional max-height
          with internal scroll for very long option lists.
          SCROLL BEHAVIOR: no blocking scrim — page scroll passes through.
          A document-level listener closes the popover on click-outside
          and (on desktop) when the user scrolls the page so the anchor
          tile moves significantly. Mobile popover is fixed-bottom so it
          stays put while the user scrolls the config above. */}
      {isOpen && (
        <>
          {/* No scrim — scroll freely. Dismiss via click-outside handler
              registered by the popover below. */}
          <div
            role="region"
            aria-label={`${title} options`}
            data-cubicle-popover="true"
            style={{
              position: isMobile ? "fixed" : "absolute",
              ...(isMobile
                ? {
                    // Mobile: fixed position, edge-to-edge (minus 8px gutter).
                    // Stays docked while user scrolls the config page.
                    left: 8,
                    right: 8,
                    top: "auto",
                    bottom: 12,
                    width: "auto",
                    maxHeight: "72vh",
                  }
                : {
                    // Desktop: anchored below the tile, centered horizontally.
                    top: "calc(100% + 10px)",
                    left: "50%",
                    transform: "translateX(-50%)",
                    width: "min(920px, calc(100vw - 48px))",
                    maxWidth: "calc(100vw - 48px)",
                    maxHeight: "min(600px, 68vh)",
                  }),
              zIndex: 6,
              background: `linear-gradient(180deg, ${T.surface} 0%, ${T.elevated}F0 100%)`,
              border: `1px solid ${filled === true ? V.neonGold + "44" : T.border}`,
              borderTop: `2px solid ${WHITE_OUTLINE}`,
              borderRadius: T.r_md,
              boxShadow: `
                0 24px 64px rgba(0,0,0,0.55),
                0 10px 24px rgba(0,0,0,0.35),
                0 0 0 1px rgba(255,255,255,0.06),
                inset 0 1px 0 rgba(255,255,255,0.06)
              `,
              animation: "cubiclePopoverIn 180ms cubic-bezier(0.16, 1, 0.3, 1)",
              backdropFilter: "blur(20px) saturate(140%)",
              display: "flex",
              flexDirection: "column",
              overflow: "hidden",
            }}>
            {/* Pointer arrow — small triangle linking popover to its tile
                origin (desktop only; hidden on mobile since the popover
                docks to the bottom of the viewport). */}
            {!isMobile && (
              <div
                aria-hidden="true"
                style={{
                  position: "absolute",
                  top: -7, left: "50%",
                  transform: "translateX(-50%) rotate(45deg)",
                  width: 12, height: 12,
                  background: T.surface,
                  borderTop: `2px solid ${WHITE_OUTLINE}`,
                  borderLeft: `1px solid ${filled === true ? V.neonGold + "44" : T.border}`,
                }}
              />
            )}
            {/* Mobile header with close button — easier than reaching for
                the scrim on a small screen. Desktop doesn't need this since
                the layout is less cramped. */}
            {isMobile && (
              <div style={{
                display: "flex", alignItems: "center", justifyContent: "space-between",
                padding: `${T.s3}px ${T.s4}px`,
                borderBottom: `1px solid ${T.border}`,
                background: `linear-gradient(180deg, ${T.elevated} 0%, ${T.surface} 100%)`,
                flexShrink: 0,
              }}>
                <div style={{
                  display: "flex", alignItems: "center", gap: T.s2,
                }}>
                  {icon && <span style={{ fontSize: 18, lineHeight: 1 }}>{icon}</span>}
                  <span style={{
                    fontSize: T.fs_md, fontWeight: 600, color: T.text,
                    fontFamily: T.font_sans,
                  }}>{title}</span>
                </div>
                <button
                  type="button"
                  onClick={() => { playSwitchSound(); onToggle(id); }}
                  aria-label="Close options"
                  style={{
                    background: "transparent",
                    border: `1px solid ${T.border}`,
                    color: T.textSec,
                    width: 32, height: 32,
                    borderRadius: T.r_sm,
                    cursor: "pointer",
                    fontSize: 18, lineHeight: 1,
                    display: "grid", placeItems: "center",
                    fontFamily: T.font_mono,
                  }}>×</button>
              </div>
            )}
            {/* Scrollable content area — if chips overflow, they scroll
                inside the panel instead of forcing the whole page. */}
            <div style={{
              flex: 1,
              overflowY: "auto",
              overflowX: "hidden",
              padding: isMobile
                ? `${T.s3}px ${T.s4}px ${T.s4}px`
                : `${T.s3}px ${T.s5}px ${T.s4}px`,
              // Improve chip readability inside with consistent min sizing:
              // we can't reach into children but we set CSS vars they can use.
              fontSize: T.fs_md,
            }}>
              {(extra || hint) && (
                <div style={{
                  display: "flex", alignItems: "center", justifyContent: "space-between",
                  gap: T.s2, flexWrap: "wrap", marginBottom: T.s3,
                }}>
                  {hint && <span style={{ fontSize: T.fs_sm, color: T.textTer, fontFamily: T.font_sans }}>{hint}</span>}
                  {extra && <div style={{ display: "flex", alignItems: "center", gap: T.s3, marginLeft: "auto" }}>{extra}</div>}
                </div>
              )}
              {children}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

// Reusable cubicle header — the collapsed-state clickable tile top.
// Extracted so both the alwaysOpen variant and the collapsible variant
// render identical headers. (Previously the header JSX was inlined twice.)
function CubicleHeader({ id, icon, title, description, valuePreview, filled, isOpen, disabled, showLed, ledGreen, headerClickable, onClick }) {
  return (
    <div
      onClick={onClick}
      style={{
        display: "flex", alignItems: "flex-start", justifyContent: "space-between",
        gap: T.s2, padding: `${T.s3}px ${T.s3}px`,
        cursor: disabled ? "not-allowed" : (headerClickable ? "pointer" : "default"),
        userSelect: "none",
        minHeight: 68,
        transition: `background 200ms ${T.ease}`,
      }}
    >
      <div style={{ display: "flex", alignItems: "flex-start", gap: T.s2, flex: 1, minWidth: 0 }}>
        {icon && (
          <span style={{
            fontSize: 20, lineHeight: 1, flexShrink: 0,
            // Small top-nudge so icon aligns with the first line of the
            // title when the title wraps to 2 lines (flex-start layout).
            marginTop: 1,
            filter: disabled ? "grayscale(100%) opacity(0.5)" : "none",
          }}>{icon}</span>
        )}
        <div style={{ display: "flex", flexDirection: "column", gap: 2, minWidth: 0, flex: 1 }}>
          <div style={{
            display: "flex", alignItems: "flex-start", gap: T.s2,
            fontSize: T.fs_md, fontFamily: T.font_sans,
            fontWeight: 600, color: disabled ? T.textMuted : T.text,
            lineHeight: 1.2,
            // Titles allowed to wrap to 2 lines in narrow grid cells
            // (5-col × ~150px). Prior nowrap caused truncation ellipses
            // on longer labels like "Harmonic style".
            wordBreak: "break-word",
          }}>
            {title}
            {showLed && (
              <span
                aria-label={ledGreen ? "section has selection" : "section empty"}
                style={{
                  display: "inline-block",
                  width: 8, height: 8, borderRadius: "50%",
                  background: ledGreen ? "#10b981" : "#ef4444",
                  animation: `${ledGreen ? "cubicleLedPulseGreen" : "cubicleLedPulseRed"} 1.8s ease-in-out infinite`,
                  flexShrink: 0,
                }} />
            )}
          </div>
          {description && (
            <div style={{
              fontSize: T.fs_xs, color: disabled ? T.textMuted : T.textTer,
              fontFamily: T.font_sans, lineHeight: 1.3,
              // Allow 2-line wrap so longer descriptions aren't chopped
              // with a single-line ellipsis in narrow 5-col cells.
              display: "-webkit-box",
              WebkitLineClamp: 2,
              WebkitBoxOrient: "vertical",
              overflow: "hidden",
              wordBreak: "break-word",
            }}>{description}</div>
          )}
          {valuePreview && !isOpen && (
            <div style={{
              fontSize: T.fs_xs, color: filled === true ? V.neonGold : T.textSec,
              fontFamily: T.font_mono, fontWeight: 500, letterSpacing: "0.02em",
              marginTop: 2, lineHeight: 1.2,
              overflow: "hidden", textOverflow: "ellipsis",
              whiteSpace: "nowrap",
            }}>{valuePreview}</div>
          )}
        </div>
      </div>
      {headerClickable && (
        <div style={{
          width: 26, height: 26,
          display: "flex", alignItems: "center", justifyContent: "center",
          borderRadius: "50%",
          background: isOpen ? (filled === true ? `${V.neonGold}22` : `${T.accent}18`) : "transparent",
          color: isOpen ? (filled === true ? V.neonGold : T.accent) : T.textTer,
          fontSize: 16, fontWeight: 700, lineHeight: 1,
          transition: `all 200ms ${T.ease}`,
        }}>
          {isOpen ? "−" : "+"}
        </div>
      )}
    </div>
  );
}


function CubicleGrid({ children, isMobile }) {
  return (
    <div style={{
      display: "grid",
      // Fewer columns = wider cells = readable titles/descriptions without
      // wrap truncation. Desktop goes from 5 to 3 columns (tiles 1.67x
      // wider), mobile from 3 to 2 (tiles 1.5x wider).
      gridTemplateColumns: isMobile ? "repeat(2, minmax(0, 1fr))" : "repeat(3, minmax(0, 1fr))",
      gap: T.s2,
      marginTop: T.s3, marginBottom: T.s3,
    }}>{children}</div>
  );
}

// ErrorBoundary — isolate any failing widget from bringing down the rest
class ErrorBoundary extends Component {
  constructor(p) { super(p); this.state = { err: null }; }
  static getDerivedStateFromError(err) { return { err }; }
  componentDidCatch() {}
  render() {
    if (this.state.err) {
      return (
        <div style={{
          padding: `${T.s3}px ${T.s4}px`, margin: `${T.s3}px 0`,
          background: T.surface, border: `1px solid ${T.border}`, borderRadius: T.r_md,
          color: T.textSec, fontSize: T.fs_sm, fontFamily: T.font_sans,
        }}>Component isolated. <button onClick={() => this.setState({ err: null })} style={{
          background: "none", border: "none", color: T.accent, cursor: "pointer",
          fontFamily: T.font_sans, fontSize: T.fs_sm, textDecoration: "underline",
        }}>Retry</button></div>
      );
    }
    return this.props.children;
  }
}

// ════════════════════════════════════════════════════════════════════════════
// ANIMATED BANNER — nav logo replacement based on Hit Engine Banner design.
// Original design was hero-sized (108-280px); scaled down for nav slot (~28px).
// Dropped from original: canvas starfields (imperceptible at this size), nebula
// drift (too subtle to read). Kept: outlined HIT, animated metal gradient on
// ENGINE, sheen sweep pass, Anton condensed font.
// Loads Anton + JetBrains Mono from Google Fonts once on mount.
// ════════════════════════════════════════════════════════════════════════════

let __animatedBannerFontLoaded = false;
function ensureBannerFonts() {
  if (__animatedBannerFontLoaded || typeof document === "undefined") return;
  const href = "https://fonts.googleapis.com/css2?family=Anton&family=JetBrains+Mono:wght@500&display=swap";
  const exists = Array.from(document.querySelectorAll("link[rel=stylesheet]"))
    .some(l => l.href && l.href.includes("family=Anton"));
  if (!exists) {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = href;
    document.head.appendChild(link);
  }
  __animatedBannerFontLoaded = true;
}

