  // ── HIP-HOP family ─────────────────────────────────────────────
  "Trap": {
    tagline: "Atlanta street sound built on rolling 808s and hi-hat triplets. Went from regional subgenre to the default sound of mainstream rap.",
    traitDetails: [
      { trait: "Rolling 808 bass", detail: "The 808 sub-bass is both kick and bass, sliding between notes; long sustained 808s define 'southern feel'." },
      { trait: "Hi-hat triplets", detail: "Machine-gun triplet patterns (usually 1/16 or 1/32 notes) — Roland TR-808 or modern sample packs." },
      { trait: "Dark pad atmospheres", detail: "Cinematic minor-key pads provide the emotional weight — often one chord progression looped." },
      { trait: "Half-time feel", detail: "Drums feel slow (~70 BPM) despite the 140 BPM hi-hats, creating hypnotic space for vocals." },
    ],
    artistDetails: [
      { name: "T.I.", signature: "Trap Muzik (2003)", why: "Coined the term 'trap' and defined the Atlanta street narrative" },
      { name: "Jeezy", signature: "Let's Get It: Thug Motivation 101 (2005)", why: "Co-founded the genre alongside T.I.; defined trap's hustler-anthem template" },
      { name: "Gucci Mane", signature: "Trap House (2005)", why: "Archetypal trap rapper; Zaytoven's work built the Atlanta sound" },
      { name: "Zaytoven", signature: "Trapholizay (2018)", why: "Producer behind Gucci's era; invented the pluck-piano trap template" },
      { name: "Rick Ross", signature: "Teflon Don (2010)", why: "Luxury-trap bossman aesthetic; MMG era reshaped trap's cinematic scale" },
      { name: "Waka Flocka Flame", signature: "Flockaveli (2010)", why: "Lex Luger's productions on this album defined the 2010s stadium-trap template" },
      { name: "Future", signature: "DS2 (2015)", why: "Pioneered auto-tune melodic trap; the most-streamed rapper of his era" },
      { name: "Young Thug", signature: "Slime Season 3 (2016) / Barter 6 (2015)", why: "Voice-as-instrument approach broke rap vocal conventions" },
      { name: "Migos", signature: "Culture (2017)", why: "Popularized triplet flow globally with 'Bad and Boujee'" },
      { name: "Quavo", signature: "Quavo Huncho (2018)", why: "Migos' hook maestro; solo melodic trap bridge into pop" },
      { name: "Offset", signature: "Father of 4 (2019)", why: "Migos' technical flow anchor; triplet-flow progenitor" },
      { name: "2 Chainz", signature: "Based on a T.R.U. Story (2012)", why: "Punchline-trap cornerstone; late-career reinvention as ATL elder" },
      { name: "Travis Scott", signature: "ASTROWORLD (2018)", why: "Psychedelic stadium trap; three top-25 most-streamed rap albums of all time" },
      { name: "21 Savage", signature: "Savage Mode II (2020, w/ Metro Boomin)", why: "Minimalist menacing trap; defined the late-2010s sound" },
      { name: "Metro Boomin", signature: "Heroes & Villains (2022)", why: "Producer-auteur era; his signature tags opened every major 2020s trap record" },
      { name: "Lil Baby", signature: "My Turn (2020)", why: "Current-era Atlanta trap at its most commercially dominant" },
      { name: "Gunna", signature: "DS4EVER (2022) / A Gift & A Curse (2023)", why: "Melodic-trap poster child; YSL-era signature sound of drip and swagger" },
    ],
  },

