// ────────────────────────────────────────────────────────────────────────────
// GenreDetailCard — context card for the currently-selected genre node.
// Shows era, description, traits, representative artists, and ancestry paths.
// ────────────────────────────────────────────────────────────────────────────
function GenreDetailCard({ genre, onSelectGenre }) {
  const [artistsExpanded, setArtistsExpanded] = useState(false);
  const [traitsExpanded, setTraitsExpanded] = useState(true); // traits open by default
  // Reset expansion state when switching genres
  useEffect(() => {
    setArtistsExpanded(false);
    setTraitsExpanded(true);
  }, [genre]);

  if (!genre) {
    return (
      <div style={{
        background: T.surface, border: `1px solid ${T.border}`,
        borderRadius: T.r_lg, padding: 24,
        display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
        minHeight: 240, textAlign: "center",
      }}>
        <div style={{
          fontSize: 36, marginBottom: 12, opacity: 0.4, lineHeight: 1,
        }}>🎼</div>
        <div style={{
          fontSize: 14, color: T.textSec, fontFamily: T.font_sans, maxWidth: 320,
          lineHeight: 1.5,
        }}>
          Select a genre in the tree to explore its origins, characteristics, and descendants.
        </div>
      </div>
    );
  }

  const node = GENRE_LINEAGE[genre];
  if (!node) return null;
  const children = GENRE_CHILDREN[genre] || [];
  const deep = GENRE_DEEP_INFO[genre]; // may be undefined for genres without research

  // Build merged data: prefer rich from GENRE_DEEP_INFO, fall back to GENRE_LINEAGE
  const traitsList = deep?.traitDetails || node.traits.map(t => ({ trait: t, detail: null }));
  // Artist list: start with rich DEEP_INFO entries (name + signature + why),
  // then append any LINEAGE artists not already present as plain name entries.
  // This way expanded LINEAGE lists (12-20 artists) show up even when a
  // richer DEEP_INFO entry exists for some of them.
  const artistsList = (() => {
    const rich = deep?.artistDetails || [];
    const richNames = new Set(rich.map(a => (a.name || "").toLowerCase()));
    const extras = (node.artists || [])
      .filter(n => n && !richNames.has(n.toLowerCase()))
      .map(n => ({ name: n, signature: null, why: null }));
    return rich.length ? [...rich, ...extras] : extras;
  })();
  const hasRichTraits = !!deep?.traitDetails;
  const hasRichArtists = !!deep?.artistDetails;

  // By default show first 3 artists; expand to show all
  const visibleArtists = artistsExpanded ? artistsList : artistsList.slice(0, 3);

  return (
    <div style={{
      background: T.surface, border: `1px solid ${T.border}`,
      borderRadius: T.r_lg, padding: 20,
      animation: "detailCardIn 280ms cubic-bezier(0.16, 1, 0.3, 1)",
    }}>
      <style>{`
        @keyframes detailCardIn {
          from { opacity: 0; transform: translateY(6px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        @keyframes sectionExpand {
          from { opacity: 0; max-height: 0; }
          to   { opacity: 1; max-height: 2000px; }
        }
      `}</style>

      {/* ── Header: era + genre name ──────────────────────── */}
      <div style={{ marginBottom: 14 }}>
        <div style={{
          fontSize: 10, fontFamily: T.font_mono, color: T.textMuted,
          letterSpacing: "0.2em", marginBottom: 6,
        }}>{node.era.toUpperCase()}</div>
        <div style={{
          fontSize: 26, fontFamily: T.font_sans, fontWeight: 600,
          color: T.text, lineHeight: 1.1, letterSpacing: "-0.015em",
        }}>{genre}</div>
      </div>

      {/* ── Tagline (from deep info) or fallback description ──── */}
      <p style={{
        fontSize: 14, lineHeight: 1.55,
        color: T.textSec, fontFamily: T.font_sans,
        margin: 0, marginBottom: 16,
        fontStyle: deep?.tagline ? "italic" : "normal",
      }}>
        {deep?.tagline || node.description}
      </p>

      {/* ── Popularity curve chart ─────────────────────────────── */}
      {GENRE_HISTORY[genre] && (
        <div style={{ marginBottom: 16 }}>
          <GenrePopularityChart genre={genre} />
        </div>
      )}

      {/* ── Lineage (parents + children) — compact single block ─ */}
      {(node.parents.length > 0 || children.length > 0) && (
        <div style={{
          padding: 12,
          background: T.bg,
          border: `1px solid ${T.border}`,
          borderRadius: 8,
          marginBottom: 16,
        }}>
          {/* Parents */}
          {node.parents.length > 0 && (
            <div style={{ marginBottom: children.length > 0 ? 10 : 0 }}>
              <div style={{
                fontSize: 9, fontFamily: T.font_mono, color: T.textMuted,
                letterSpacing: "0.2em", marginBottom: 6,
              }}>◂ EVOLVED FROM</div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                {node.parents.map(p => (
                  <button key={p} type="button"
                    onClick={() => { playSwitchSound(); onSelectGenre(p); }}
                    style={{
                      padding: "4px 9px",
                      background: "transparent",
                      border: `1px solid ${T.border}`,
                      color: T.textSec,
                      fontSize: 11, fontFamily: T.font_sans, fontWeight: 500,
                      borderRadius: 4, cursor: "pointer",
                      transition: "all 140ms ease-out",
                    }}
                    onMouseEnter={e => { e.currentTarget.style.borderColor = T.accent; e.currentTarget.style.color = T.accent; }}
                    onMouseLeave={e => { e.currentTarget.style.borderColor = T.border; e.currentTarget.style.color = T.textSec; }}>
                    {p}
                  </button>
                ))}
              </div>
            </div>
          )}
          {/* Children */}
          {children.length > 0 && (
            <div>
              <div style={{
                fontSize: 9, fontFamily: T.font_mono, color: T.textMuted,
                letterSpacing: "0.2em", marginBottom: 6,
              }}>▸ SPAWNED</div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                {children.map(c => (
                  <button key={c} type="button"
                    onClick={() => { playSwitchSound(); onSelectGenre(c); }}
                    style={{
                      padding: "4px 9px",
                      background: `${T.accent}11`,
                      border: `1px solid ${T.accentBorder}`,
                      color: T.accentHi,
                      fontSize: 11, fontFamily: T.font_sans, fontWeight: 500,
                      borderRadius: 4, cursor: "pointer",
                      transition: "all 140ms ease-out",
                    }}
                    onMouseEnter={e => { e.currentTarget.style.background = `${T.accent}22`; }}
                    onMouseLeave={e => { e.currentTarget.style.background = `${T.accent}11`; }}>
                    {c}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* ── Key Traits — expandable with detailed explanations ──── */}
      {traitsList.length > 0 && (
        <div style={{
          marginBottom: 16,
          padding: 14,
          background: `${V.neonGold}07`,
          border: `1px solid ${V.neonGold}26`,
          borderRadius: 8,
        }}>
          <button type="button"
            onClick={() => { playSwitchSound(); setTraitsExpanded(!traitsExpanded); }}
            style={{
              width: "100%",
              display: "flex", alignItems: "center", justifyContent: "space-between",
              background: "transparent", border: "none",
              padding: 0, cursor: "pointer",
              marginBottom: traitsExpanded ? 10 : 0,
            }}>
            <div style={{
              fontSize: 10, fontFamily: T.font_mono, fontWeight: 700,
              color: V.neonGold, letterSpacing: "0.18em",
              textShadow: `0 0 4px ${V.neonGold}33`,
            }}>
              KEY TRAITS · {traitsList.length}
            </div>
            <span style={{
              color: V.neonGold, fontSize: 11, fontFamily: T.font_mono,
              transition: "transform 200ms ease-out",
              transform: traitsExpanded ? "rotate(90deg)" : "rotate(0deg)",
            }}>▸</span>
          </button>
          {traitsExpanded && (
            <div style={{
              display: "flex", flexDirection: "column", gap: 10,
              animation: "sectionExpand 220ms ease-out",
            }}>
              {traitsList.map((t, i) => (
                <div key={i} style={{
                  paddingBottom: i < traitsList.length - 1 ? 10 : 0,
                  borderBottom: i < traitsList.length - 1 ? `1px dashed ${V.neonGold}22` : "none",
                }}>
                  <div style={{
                    fontSize: 13, fontWeight: 600, color: T.text,
                    fontFamily: T.font_sans, marginBottom: t.detail ? 4 : 0,
                    lineHeight: 1.3,
                  }}>
                    <span style={{ color: V.neonGold, marginRight: 6 }}>◆</span>
                    {t.trait}
                  </div>
                  {t.detail && (
                    <div style={{
                      fontSize: 12, color: T.textSec,
                      fontFamily: T.font_sans, lineHeight: 1.5,
                      paddingLeft: 14,
                    }}>
                      {t.detail}
                    </div>
                  )}
                </div>
              ))}
              {!hasRichTraits && (
                <div style={{
                  fontSize: 10, color: T.textMuted, fontFamily: T.font_mono,
                  marginTop: 4, fontStyle: "italic",
                  letterSpacing: "0.05em",
                }}>
                  Basic traits only — detailed explanations being researched
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* ── Representative Artists — expandable with signatures ─── */}
      {artistsList.length > 0 && (
        <div style={{
          padding: 14,
          background: T.bg,
          border: `1px solid ${T.border}`,
          borderRadius: 8,
        }}>
          <div style={{
            display: "flex", alignItems: "center", justifyContent: "space-between",
            marginBottom: 10,
          }}>
            <div style={{
              fontSize: 10, fontFamily: T.font_mono, fontWeight: 700,
              color: T.text, letterSpacing: "0.18em",
            }}>
              ARTISTS · {artistsList.length}
            </div>
            {artistsList.length > 3 && (
              <button type="button"
                onClick={() => { playSwitchSound(); setArtistsExpanded(!artistsExpanded); }}
                style={{
                  background: "transparent", border: "none",
                  color: T.accent, fontSize: 11,
                  fontFamily: T.font_mono, fontWeight: 600,
                  letterSpacing: "0.12em", cursor: "pointer",
                  padding: "2px 8px",
                  borderRadius: 4,
                  transition: "all 140ms ease-out",
                }}
                onMouseEnter={e => e.currentTarget.style.background = `${T.accent}15`}
                onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
                {artistsExpanded ? "SHOW LESS ▲" : `SHOW ALL ${artistsList.length} ▾`}
              </button>
            )}
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {visibleArtists.map((a, i) => (
              <div key={i} style={{
                paddingBottom: i < visibleArtists.length - 1 ? 10 : 0,
                borderBottom: i < visibleArtists.length - 1 ? `1px dashed ${T.border}` : "none",
              }}>
                <div style={{
                  fontSize: 14, fontWeight: 600, color: T.text,
                  fontFamily: T.font_sans,
                  marginBottom: a.signature ? 3 : 0,
                  lineHeight: 1.2,
                }}>
                  {a.name}
                </div>
                {a.signature && (
                  <div style={{
                    fontSize: 11, color: T.accent,
                    fontFamily: T.font_mono, letterSpacing: "0.05em",
                    marginBottom: a.why ? 3 : 0,
                  }}>
                    ▸ {a.signature}
                  </div>
                )}
                {a.why && (
                  <div style={{
                    fontSize: 12, color: T.textSec,
                    fontFamily: T.font_sans, lineHeight: 1.5,
                  }}>
                    {a.why}
                  </div>
                )}
              </div>
            ))}
          </div>
          {!hasRichArtists && (
            <div style={{
              marginTop: 8, fontSize: 10, color: T.textMuted, fontFamily: T.font_mono,
              fontStyle: "italic", letterSpacing: "0.05em",
            }}>
              Artist details being researched
            </div>
          )}
        </div>
      )}
    </div>
  );
}




// ── SPARKLINE & CHART COMPONENTS — popularity visualization ───────────
// Both compute from GENRE_HISTORY yearly data points. Sparkline = tiny
// inline version (for sidebar rows). Chart = full-size version (for the
// detail card). Pure line charts: x-axis is years, y-axis is popularity 0-100.

// Get current-year popularity for a genre (used for sorting)
function getCurrentPopularity(genre) {
  const curve = GENRE_HISTORY[genre];
  if (!curve || curve.length === 0) return 0;
  const now = 2026;
  // Use interpolation but without the pre-birth fade-in so sorting is clean
  if (now < curve[0][0]) return 0;
  if (now > curve[curve.length - 1][0]) {
    const delta = now - curve[curve.length - 1][0];
    return Math.max(0, curve[curve.length - 1][1] * (1 - delta / 8));
  }
  for (let i = 0; i < curve.length - 1; i++) {
    const [ta, va] = curve[i];
    const [tb, vb] = curve[i + 1];
    if (now >= ta && now <= tb) {
      const p = (now - ta) / (tb - ta);
      return va + (vb - va) * p;
    }
  }
  return 0;
}

// Build an SVG path (d attribute) from a curve at given dimensions
function buildCurvePath(curve, width, height, minYear, maxYear) {
  if (!curve || curve.length === 0) return "";
  const padY = 4; // leave a little breathing room top/bottom
  const usableH = height - padY * 2;
  const years = maxYear - minYear;
  // Sample every quarter-year for smooth appearance
  const points = [];
  for (let y = minYear; y <= maxYear; y += 0.25) {
    // Linear interp for speed (simpler than smoothstep for chart rendering)
    let val = 0;
    if (y < curve[0][0]) val = 0;
    else if (y > curve[curve.length - 1][0]) {
      const delta = y - curve[curve.length - 1][0];
      val = Math.max(0, curve[curve.length - 1][1] * (1 - delta / 8));
    } else {
      for (let i = 0; i < curve.length - 1; i++) {
        const [ta, va] = curve[i];
        const [tb, vb] = curve[i + 1];
        if (y >= ta && y <= tb) {
          const p = (y - ta) / (tb - ta);
          val = va + (vb - va) * p;
          break;
        }
      }
    }
    const px = ((y - minYear) / years) * width;
    const py = padY + (1 - val / 100) * usableH;
    points.push(`${px.toFixed(1)},${py.toFixed(1)}`);
  }
  if (points.length === 0) return "";
  return `M ${points[0]} L ${points.slice(1).join(" L ")}`;
}

// ── Tiny sidebar sparkline — ~80px wide, 20px tall ─────────────────
function GenreSparkline({ genre, width = 80, height = 20, color }) {
  const curve = GENRE_HISTORY[genre];
  if (!curve || curve.length === 0) return null;
  const minYear = 1960;
  const maxYear = 2026;
  const path = buildCurvePath(curve, width, height, minYear, maxYear);
  const current = getCurrentPopularity(genre);
  // Current-position dot on the right edge
  const dotX = width - 1.5;
  const dotY = 4 + (1 - current / 100) * (height - 8);

  const strokeColor = color || T.textSec;

  return (
    <svg width={width} height={height} style={{ display: "block", flexShrink: 0 }}>
      <path d={path}
        fill="none"
        stroke={strokeColor}
        strokeWidth={1.2}
        strokeLinecap="round"
        strokeLinejoin="round"
        opacity={0.75}
      />
      {/* Current-position dot */}
      <circle cx={dotX} cy={dotY} r={1.8}
        fill={strokeColor}
        opacity={1}
      />
    </svg>
  );
}

// ── Full popularity chart — big line chart for the detail card ─────
function GenrePopularityChart({ genre }) {
  const curve = GENRE_HISTORY[genre];
  if (!curve || curve.length === 0) {
    return (
      <div style={{
        padding: 16, textAlign: "center",
        fontSize: 12, color: T.textMuted, fontFamily: T.font_sans,
        fontStyle: "italic",
      }}>
        No historical data available yet — being researched.
      </div>
    );
  }

  const MIN_YEAR = 1960;
  const MAX_YEAR = 2026;
  const WIDTH = 540;
  const HEIGHT = 160;
  const PAD_L = 32;   // y-axis label room
  const PAD_R = 12;
  const PAD_T = 16;
  const PAD_B = 26;   // x-axis label room
  const CHART_W = WIDTH - PAD_L - PAD_R;
  const CHART_H = HEIGHT - PAD_T - PAD_B;

  const path = buildCurvePath(curve, CHART_W, CHART_H, MIN_YEAR, MAX_YEAR);
  const current = getCurrentPopularity(genre);

  // Decade ticks for the x-axis
  const decadeTicks = [1960, 1970, 1980, 1990, 2000, 2010, 2020];
  // Popularity grid lines
  const yGridLines = [0, 25, 50, 75, 100];

  // Find peak year for annotation
  let peakYear = curve[0][0];
  let peakValue = curve[0][1];
  curve.forEach(([y, v]) => {
    if (v > peakValue) { peakValue = v; peakYear = y; }
  });

  return (
    <div style={{
      padding: "12px 14px",
      background: T.bg,
      border: `1px solid ${T.border}`,
      borderRadius: 8,
    }}>
      {/* Header: current popularity + peak */}
      <div style={{
        display: "flex", alignItems: "baseline", justifyContent: "space-between",
        marginBottom: 6, gap: 10, flexWrap: "wrap",
      }}>
        <div style={{
          fontSize: 10, fontFamily: T.font_mono, fontWeight: 700,
          color: T.textMuted, letterSpacing: "0.18em",
        }}>POPULARITY CURVE</div>
        <div style={{
          fontSize: 11, color: T.textTer, fontFamily: T.font_mono,
          letterSpacing: "0.05em",
          display: "flex", gap: 10,
        }}>
          <span>NOW: <strong style={{ color: T.text }}>{Math.round(current)}</strong></span>
          <span>PEAK: <strong style={{ color: V.neonGold }}>{Math.round(peakValue)}</strong> ({peakYear})</span>
        </div>
      </div>

      <svg
        width="100%"
        viewBox={`0 0 ${WIDTH} ${HEIGHT}`}
        preserveAspectRatio="none"
        style={{ display: "block" }}>
        {/* Y-axis grid lines */}
        {yGridLines.map(v => {
          const y = PAD_T + (1 - v / 100) * CHART_H;
          return (
            <g key={v}>
              <line
                x1={PAD_L} x2={WIDTH - PAD_R}
                y1={y} y2={y}
                stroke={T.border}
                strokeWidth={0.5}
                strokeDasharray={v === 0 || v === 100 ? "0" : "2 3"}
                opacity={0.6}
              />
              <text
                x={PAD_L - 6} y={y + 3}
                textAnchor="end"
                fontSize={8}
                fontFamily={T.font_mono}
                fill={T.textMuted}
                letterSpacing="0.05em">
                {v}
              </text>
            </g>
          );
        })}

        {/* X-axis decade tick marks + labels */}
        {decadeTicks.map(y => {
          const x = PAD_L + ((y - MIN_YEAR) / (MAX_YEAR - MIN_YEAR)) * CHART_W;
          return (
            <g key={y}>
              <line
                x1={x} x2={x}
                y1={PAD_T} y2={PAD_T + CHART_H}
                stroke={T.border}
                strokeWidth={0.5}
                opacity={0.3}
              />
              <text
                x={x} y={HEIGHT - 8}
                textAnchor="middle"
                fontSize={9}
                fontFamily={T.font_mono}
                fill={T.textMuted}
                letterSpacing="0.05em">
                {y}
              </text>
            </g>
          );
        })}

        {/* The actual popularity curve */}
        <g transform={`translate(${PAD_L}, ${PAD_T})`}>
          <path d={path}
            fill="none"
            stroke={T.accent}
            strokeWidth={1.6}
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ filter: `drop-shadow(0 0 2px ${T.accent}88)` }}
          />
          {/* Current-position marker */}
          <circle
            cx={CHART_W}
            cy={(1 - current / 100) * CHART_H}
            r={3}
            fill={T.accentHi}
            stroke={T.bg}
            strokeWidth={1.5}
            style={{ filter: `drop-shadow(0 0 4px ${T.accent})` }}
          />
        </g>

        {/* X-axis label */}
        <text
          x={WIDTH / 2} y={HEIGHT - 1}
          textAnchor="middle"
          fontSize={8}
          fontFamily={T.font_mono}
          fill={T.textMuted}
          letterSpacing="0.15em">
          YEAR · 1960 → 2026
        </text>
      </svg>
    </div>
  );
}


// ════════════════════════════════════════════════════════════════════════════
// GENRE BROWSER — popularity-sorted sidebar + detail pane.
// Genres are sorted by their 2026 popularity (most relevant now at top).
// Each row shows a tiny sparkline so you can see a genre's life-curve at a glance.
// ════════════════════════════════════════════════════════════════════════════
function GenreBrowser({ selectedGenre, onSelectGenre, onNavigate }) {
  const { layout } = useLayout();
  const { tier } = useTier();
  const isMobile = layout === "mobile";
  const [search, setSearch] = useState("");
  const [mobileShowDetail, setMobileShowDetail] = useState(false);

  // Sort mode — "alpha" (A→Z) or "popularity" (current-year hot list).
  // Free/Pro default to alpha and are gated out of popularity sort.
  // VIP/Admin default to popularity (the "what's hot" view is premium).
  const canSortByPopularity = tier === "vip" || tier === "admin";
  const [sortMode, setSortMode] = useState(canSortByPopularity ? "popularity" : "alpha");
  const [salesModalOpen, setSalesModalOpen] = useState(false);

  // Precompute sorted lists for both modes; active mode decides which renders.
  const sortedGenres = useMemo(() => {
    const all = Object.keys(GENRE_LINEAGE).map(g => ({
      name: g,
      current: getCurrentPopularity(g),
    }));
    if (sortMode === "popularity") {
      return all.sort((a, b) => b.current - a.current);
    }
    return all.sort((a, b) => a.name.localeCompare(b.name));
  }, [sortMode]);

  // Search filters across the full list
  const searchLower = search.trim().toLowerCase();
  const isSearching = searchLower.length > 0;
  const visibleGenres = useMemo(() => {
    if (!isSearching) return sortedGenres;
    return sortedGenres.filter(g => g.name.toLowerCase().includes(searchLower));
  }, [sortedGenres, isSearching, searchLower]);

  // On mobile, show detail view when a genre is selected
  useEffect(() => {
    if (isMobile && selectedGenre) setMobileShowDetail(true);
  }, [selectedGenre, isMobile]);

  const handleSelect = (genre) => {
    onSelectGenre(genre);
    if (isMobile) setMobileShowDetail(true);
  };

  // ── Mobile: show either sidebar OR detail, not both ─────────────
  if (isMobile && mobileShowDetail && selectedGenre) {
    return (
      <div style={{
        background: T.bg,
        border: `1px solid ${T.border}`,
        borderRadius: T.r_lg,
        overflow: "hidden",
      }}>
        <button type="button"
          onClick={() => { playSwitchSound(); setMobileShowDetail(false); }}
          style={{
            width: "100%",
            padding: "12px 16px",
            background: T.surface,
            border: "none",
            borderBottom: `1px solid ${T.border}`,
            color: T.text,
            fontSize: 13, fontFamily: T.font_sans, fontWeight: 500,
            cursor: "pointer", textAlign: "left",
            display: "flex", alignItems: "center", gap: 8,
          }}>
          <span style={{ color: T.accent, fontSize: 16 }}>◂</span>
          Back to all genres
        </button>
        <div style={{ padding: T.s3 }}>
          <GenreDetailCard
            genre={selectedGenre}
            onSelectGenre={handleSelect}
          />
        </div>
      </div>
    );
  }

  // ── Sidebar + detail layout ─────────────────────────────────────
  return (
    <div style={{
      display: "grid",
      gridTemplateColumns: isMobile ? "1fr" : "minmax(320px, 380px) 1fr",
      gap: T.s4,
      alignItems: "start",
    }}>
      {/* ════ SIDEBAR ═══════════════════════════════════════════ */}
      <div style={{
        background: T.surface,
        border: `1px solid ${T.border}`,
        borderRadius: T.r_lg,
        overflow: "hidden",
      }}>
        {/* Header with explanatory label + sort toggle */}
        <div style={{
          padding: "12px 14px 10px",
          borderBottom: `1px solid ${T.border}`,
          background: "linear-gradient(180deg, rgba(255,255,255,0.02) 0%, transparent 100%)",
        }}>
          <div style={{
            fontSize: 10, fontFamily: T.font_mono, fontWeight: 700,
            color: T.textMuted, letterSpacing: "0.18em", marginBottom: 6,
          }}>
            {sortMode === "popularity" ? "SORTED BY CURRENT POPULARITY" : "SORTED ALPHABETICALLY"}
          </div>
          <div style={{
            display: "flex", alignItems: "center", justifyContent: "space-between",
            gap: T.s2, flexWrap: "wrap",
          }}>
            <div style={{
              fontSize: 10, color: T.textTer, fontFamily: T.font_sans,
              lineHeight: 1.4,
            }}>
              {visibleGenres.length} genres · {sortMode === "popularity" ? "most relevant today first" : "A to Z"}
            </div>
            {/* Sort toggle — two-pill segmented control */}
            <div style={{
              display: "inline-flex", gap: 2,
              padding: 2,
              background: T.bg,
              border: `1px solid ${T.border}`,
              borderRadius: T.r_sm,
            }}>
              <button type="button"
                onClick={() => { playSwitchSound(); setSortMode("alpha"); }}
                style={{
                  padding: "4px 10px",
                  background: sortMode === "alpha" ? T.accent : "transparent",
                  border: "none",
                  borderRadius: 4,
                  color: sortMode === "alpha" ? "#fff" : T.textMuted,
                  fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
                  letterSpacing: "0.12em",
                  cursor: "pointer",
                  transition: `all ${T.dur_fast} ${T.ease}`,
                }}>A–Z</button>
              <button type="button"
                onClick={() => {
                  if (canSortByPopularity) {
                    setSortMode("popularity");
                  } else {
                    setSalesModalOpen(true);
                  }
                }}
                title={canSortByPopularity ? "Sort by current streaming popularity" : "VIP only — click to learn more"}
                style={{
                  padding: "4px 10px",
                  background: sortMode === "popularity" ? T.accent : "transparent",
                  border: "none",
                  borderRadius: 4,
                  color: sortMode === "popularity"
                    ? "#fff"
                    : (canSortByPopularity ? T.textMuted : "#FFD700"),
                  fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
                  letterSpacing: "0.12em",
                  cursor: "pointer",
                  transition: `all ${T.dur_fast} ${T.ease}`,
                }}>
                {canSortByPopularity ? "POPULAR ⚡" : "🔒 POPULAR"}
              </button>
            </div>
          </div>
        </div>

        {/* Search */}
        <div style={{ padding: 10, borderBottom: `1px solid ${T.border}` }}>
          <input
            type="text"
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="Search genres…"
            style={{
              width: "100%", boxSizing: "border-box",
              padding: isMobile ? "10px 12px" : "8px 12px",
              background: T.bg,
              border: `1px solid ${T.border}`,
              color: T.text,
              fontSize: isMobile ? 16 : 13,
              fontFamily: T.font_sans,
              borderRadius: 6, outline: "none",
              WebkitAppearance: "none",
              transition: "border-color 140ms ease-out",
            }}
            onFocus={e => e.currentTarget.style.borderColor = T.borderFocus}
            onBlur={e => e.currentTarget.style.borderColor = T.border}
          />
        </div>

        {/* Scrollable ranked list */}
        <div style={{
          maxHeight: isMobile ? "none" : "calc(100vh - 260px)",
          overflowY: "auto",
          padding: "4px 0",
        }}>
          {visibleGenres.length === 0 ? (
            <div style={{
              padding: "20px 16px", textAlign: "center",
              fontSize: 13, color: T.textMuted, fontFamily: T.font_sans,
            }}>
              No genres match "{search}"
            </div>
          ) : (
            visibleGenres.map((g, idx) => (
              <GenreRow key={g.name}
                genre={g.name}
                rank={isSearching ? null : idx + 1}
                current={g.current}
                isSelected={selectedGenre === g.name}
                onClick={() => { playSwitchSound(); handleSelect(g.name); }}
              />
            ))
          )}
        </div>
      </div>

      {/* ════ DETAIL PANE ═══════════════════════════════════════ */}
      {!isMobile && (
        <div style={{ position: "sticky", top: 72 }}>
          <GenreDetailCard
            genre={selectedGenre}
            onSelectGenre={handleSelect}
          />
        </div>
      )}
      <SalesModal
        open={salesModalOpen}
        feature="sortByPopularity"
        onClose={() => setSalesModalOpen(false)}
        onUpgrade={() => { onNavigate && onNavigate("shop"); }}
      />
    </div>
  );
}



// Row component — a single clickable genre in the sidebar list.
// Shows: rank number · genre name · hybrid marker · RES badge · sparkline
function GenreRow({ genre, rank, current, isSelected, onClick }) {
  const node = GENRE_LINEAGE[genre];
  if (!node) return null;
  const deep = GENRE_DEEP_INFO[genre];
  const hasRich = !!deep;
  const isHybrid = (node.parents || []).length > 1;

  // Color the sparkline based on current popularity: hot genres get accent,
  // cooler ones fade toward muted gray
  const sparkColor = current >= 60 ? T.accentHi
    : current >= 35 ? T.textSec
    : T.textMuted;

  return (
    <button type="button"
      onClick={onClick}
      style={{
        display: "flex", alignItems: "center", gap: 10, width: "100%",
        padding: "7px 10px 7px 8px",
        background: isSelected ? `linear-gradient(90deg, ${T.accent}22 0%, transparent 80%)` : "transparent",
        border: "none",
        borderLeft: `2px solid ${isSelected ? T.accent : "transparent"}`,
        borderRadius: isSelected ? "0 6px 6px 0" : 6,
        color: isSelected ? T.text : T.textSec,
        fontSize: 13, fontFamily: T.font_sans, fontWeight: isSelected ? 500 : 400,
        cursor: "pointer",
        transition: "all 120ms ease-out",
        textAlign: "left",
      }}
      onMouseEnter={e => { if (!isSelected) e.currentTarget.style.background = T.hover; }}
      onMouseLeave={e => { if (!isSelected) e.currentTarget.style.background = "transparent"; }}>
      {/* Rank number */}
      {rank !== null && rank !== undefined && (
        <span style={{
          flexShrink: 0,
          width: 22, textAlign: "right",
          fontSize: 10, fontFamily: T.font_mono,
          color: rank <= 10 ? T.accentHi : T.textMuted,
          fontWeight: rank <= 10 ? 700 : 400,
          letterSpacing: "0.05em",
        }}>{rank}</span>
      )}
      {/* Genre name */}
      <div style={{
        display: "flex", alignItems: "center", gap: 5,
        flex: 1, minWidth: 0,
      }}>
        <span style={{
          overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
        }}>{genre}</span>
        {isHybrid && (
          <span title={`Hybrid of: ${node.parents.join(", ")}`}
            style={{ fontSize: 9, color: V.cyan, flexShrink: 0 }}>◆</span>
        )}
      </div>
      {/* RES badge + sparkline */}
      <div style={{
        display: "flex", alignItems: "center", gap: 6, flexShrink: 0,
      }}>
        {hasRich && (
          <span style={{
            fontSize: 8, fontFamily: T.font_mono, fontWeight: 700,
            color: T.success, letterSpacing: "0.12em",
            padding: "1px 4px",
            background: `${T.success}14`,
            border: `1px solid ${T.success}44`,
            borderRadius: 3,
          }}>RES</span>
        )}
        <GenreSparkline genre={genre} width={70} height={18} color={sparkColor} />
      </div>
    </button>
  );
}


// ════════════════════════════════════════════════════════════════════════════
// GENRE HISTORY HERO — memorable page opening, cinematic
// ════════════════════════════════════════════════════════════════════════════
// A living intro that frames the whole page thesis. Three-part composition:
//
//   1. Year ticker pane (left) — rotates through curated music-moment cards
//      every 2.5s. Each card shows { year, genre, epitaph }. Uses a crossfade
//      transition so the swap feels like a film cut, not a refresh.
//
//   2. Editorial stack (right) — Instrument Serif giant statement. Italic
//      emphasis word. Short sub-copy. Editorial magazine energy, not
//      generic SaaS marketing copy.
//
//   3. Sonogram pulse (bottom full-width) — animated SVG wave that ticks
//      decade marks from 1960 to 2026, suggesting "sound waves through time."
//      The pulse flows left-to-right continuously via stroke-dashoffset.
//
// Disclaimer pill lives at the top-right as a thin editorial byline so it
// doesn't compete with the statement.
// ════════════════════════════════════════════════════════════════════════════

const GENRE_MOMENTS = [
  { year: "1973", genre: "Disco", epitaph: "a kick, a hat, and a hall full of strangers" },
  { year: "1979", genre: "Post-Punk", epitaph: "four chords and a question about industry" },
  { year: "1987", genre: "Acid House", epitaph: "a 303 squelched and Britain rewired overnight" },
  { year: "1992", genre: "Grunge", epitaph: "a flannel shirt became a generation's uniform" },
  { year: "1996", genre: "Trip-Hop", epitaph: "Bristol made sadness sound expensive" },
  { year: "2001", genre: "Garage", epitaph: "UK clubs chopped the 2-step until it cracked" },
  { year: "2005", genre: "Crunk", epitaph: "Atlanta yelled louder than the bass hit" },
  { year: "2011", genre: "Dubstep", epitaph: "the drop became a cultural instrument" },
  { year: "2016", genre: "Trap", epitaph: "808s rewired what a chorus was supposed to do" },
  { year: "2019", genre: "Hyperpop", epitaph: "every vocal peak, clipped on purpose" },
  { year: "2022", genre: "Amapiano", epitaph: "the log drum walked out of Johannesburg" },
  { year: "2025", genre: "Sierra Jersey", epitaph: "country and club drum machines found each other" },
];

function GenreHistoryHero({ isMobile }) {
  const [idx, setIdx] = useState(0);
  const [phase, setPhase] = useState("in"); // "in" | "out"
  // When the user interacts with the scrubber, pause the auto-rotation for
  // a few seconds so they can actually read what they landed on. Resets
  // itself via a timer so eventually the hero starts breathing again.
  const [scrubbing, setScrubbing] = useState(false);
  const [autoPausedUntil, setAutoPausedUntil] = useState(0);
  // Has the hero finished its mount-time entrance animation? Used to
  // gate the sonogram stroke-draw so it doesn't replay every render.
  const [entered, setEntered] = useState(false);
  // Ref to the scrubber track so we can convert mouse/touch X into index.
  const trackRef = useRef(null);

  // Entrance animation — flip `entered` to true one frame after mount so
  // the CSS transitions / keyframes animate IN from the initial state.
  useEffect(() => {
    const t = setTimeout(() => setEntered(true), 40);
    return () => clearTimeout(t);
  }, []);

  // Rotate the year-moment card on a 2.5s interval UNLESS the user is
  // scrubbing or has recently scrubbed (autoPausedUntil > now). Keeps
  // the hero "alive" when idle but respects user input.
  useEffect(() => {
    const tick = setInterval(() => {
      if (scrubbing) return;
      if (Date.now() < autoPausedUntil) return;
      setPhase("out");
      setTimeout(() => {
        setIdx(i => (i + 1) % GENRE_MOMENTS.length);
        setPhase("in");
      }, 400);
    }, 2500);
    return () => clearInterval(tick);
  }, [scrubbing, autoPausedUntil]);

  const current = GENRE_MOMENTS[idx];

  // Convert a clientX to a GENRE_MOMENTS index based on the track bounds.
  // Pins to [0, length-1]. Used by both mouse + touch handlers.
  const xToIndex = (clientX) => {
    const el = trackRef.current;
    if (!el) return idx;
    const rect = el.getBoundingClientRect();
    const pct = Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
    const maxI = GENRE_MOMENTS.length - 1;
    return Math.round(pct * maxI);
  };

  const commitScrub = (clientX) => {
    const next = xToIndex(clientX);
    if (next !== idx) setIdx(next);
  };

  // Pointer event handlers for the scrubber. Uses Pointer Events API so
  // mouse, touch, and pen all work through the same code path.
  const onPointerDown = (e) => {
    e.currentTarget.setPointerCapture?.(e.pointerId);
    setScrubbing(true);
    setPhase("in"); // kill any in-flight fade so the scrub feels instant
    commitScrub(e.clientX);
  };
  const onPointerMove = (e) => {
    if (!scrubbing) return;
    commitScrub(e.clientX);
  };
  const onPointerUp = (e) => {
    if (!scrubbing) return;
    e.currentTarget.releasePointerCapture?.(e.pointerId);
    setScrubbing(false);
    // Pause auto-rotation for 6 seconds after release, then resume naturally
    setAutoPausedUntil(Date.now() + 6000);
  };

  // Compute current scrubber knob position as a percentage 0-100 for both
  // the knob and the "filled" bar segment behind it.
  const maxI = GENRE_MOMENTS.length - 1;
  const knobPct = (idx / maxI) * 100;

  // Year range derived from the data so we don't have to hardcode — the
  // scrubber always reflects the actual available moments.
  const firstYear = GENRE_MOMENTS[0]?.year || "1960";
  const lastYear  = GENRE_MOMENTS[GENRE_MOMENTS.length - 1]?.year || "2026";

  return (
    <>
      {/* Scoped keyframes for the hero animations */}
      <style>{`
        @keyframes ghhPulseFlow {
          0% { stroke-dashoffset: 0; }
          100% { stroke-dashoffset: -240; }
        }
        @keyframes ghhGradDrift {
          0%, 100% { background-position: 0% 50%; }
          50%      { background-position: 100% 50%; }
        }
        @keyframes ghhVignettePulse {
          0%, 100% { opacity: 0.7; }
          50%      { opacity: 1; }
        }
        @keyframes ghhFadeIn {
          from { opacity: 0; transform: translateY(8px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        /* Mount-time stagger — each element fades up from 10px with
           a delay that cascades down the visual hierarchy. Makes the
           hero feel like it's composing itself on arrival. */
        @keyframes ghhStagger {
          from { opacity: 0; transform: translateY(14px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        /* Sonogram stroke-draw — the path "writes itself" from left
           to right on first reveal. Combined with the flow animation
           underneath to give the illusion of sound waves emerging. */
        @keyframes ghhStrokeDraw {
          from { stroke-dashoffset: 1200; opacity: 0; }
          60%  { opacity: 1; }
          to   { stroke-dashoffset: 0; opacity: 1; }
        }
        /* "You are here" marker — gentle pulse on the 2026 dot so the
           user can always find their place in the timeline. */
        @keyframes ghhYouPulse {
          0%, 100% { transform: scale(1);   opacity: 0.85; }
          50%      { transform: scale(1.4); opacity: 1; }
        }
        /* Ping ring for the "you are here" marker — expands + fades */
        @keyframes ghhYouPing {
          0%   { transform: scale(0.6); opacity: 0.7; }
          100% { transform: scale(2.4); opacity: 0;   }
        }
      `}</style>

      <div style={{
        position: "relative",
        marginBottom: isMobile ? 40 : 64,
        padding: isMobile ? "32px 20px 28px" : "56px 40px 44px",
        borderRadius: 12,
        overflow: "hidden",
        // Drifting gradient field — slow horizontal movement suggests
        // "time flowing". Uses V palette so it reads as branded.
        background: `linear-gradient(135deg, #0A0D14 0%, #131728 35%, #1A1533 70%, #0D1020 100%)`,
        backgroundSize: "200% 200%",
        animation: "ghhGradDrift 18s ease-in-out infinite",
        border: `1px solid ${T.border}`,
      }}>
        {/* Corner vignette — soft gold bleed in top-right, subtle */}
        <div aria-hidden="true" style={{
          position: "absolute", top: "-30%", right: "-20%",
          width: "60%", height: "120%", pointerEvents: "none",
          background: `radial-gradient(ellipse, ${V.neonGold}18 0%, transparent 60%)`,
          animation: "ghhVignettePulse 6s ease-in-out infinite",
        }} />
        {/* Corner vignette — opposite, faint indigo */}
        <div aria-hidden="true" style={{
          position: "absolute", bottom: "-30%", left: "-15%",
          width: "50%", height: "100%", pointerEvents: "none",
          background: `radial-gradient(ellipse, ${T.accent}15 0%, transparent 60%)`,
        }} />

        {/* Editorial byline / disclaimer pill — top right, thin */}
        <div style={{
          position: "absolute", top: 16, right: isMobile ? 16 : 24,
          display: "inline-flex", alignItems: "center", gap: 6,
          padding: "4px 10px",
          background: "rgba(255, 215, 0, 0.04)",
          border: `1px solid ${V.neonGold}22`,
          borderRadius: 3,
          fontSize: 9, fontFamily: T.font_mono, fontWeight: 700,
          letterSpacing: "0.18em",
          color: `${V.neonGold}cc`,
          zIndex: 2,
          opacity: entered ? 1 : 0,
          transform: entered ? "translateY(0)" : "translateY(-6px)",
          transition: "opacity 600ms ease 40ms, transform 600ms ease 40ms",
        }}>
          <span style={{ width: 5, height: 5, borderRadius: 999, background: V.neonGold, boxShadow: `0 0 6px ${V.neonGold}` }} />
          EDITORIAL · APR 2026
        </div>

        <div style={{
          position: "relative", zIndex: 1,
          display: "grid",
          gridTemplateColumns: isMobile ? "1fr" : "minmax(0, 0.85fr) minmax(0, 1.15fr)",
          gap: isMobile ? 28 : 48,
          alignItems: "center",
        }}>
          {/* ═══ LEFT: ROTATING YEAR-MOMENT CARD ═══ */}
          <div style={{
            position: "relative",
            padding: isMobile ? "20px 18px" : "28px 24px",
            background: "rgba(255, 255, 255, 0.02)",
            border: `1px solid rgba(255, 255, 255, 0.06)`,
            borderRadius: 8,
            backdropFilter: "blur(4px)",
            minHeight: isMobile ? 180 : 230,
            display: "flex", flexDirection: "column", justifyContent: "center",
            overflow: "hidden",
            // Stagger entrance: card appears after kicker (460ms delay)
            opacity: entered ? 1 : 0,
            transform: entered ? "translateY(0)" : "translateY(18px)",
            transition: "opacity 700ms ease 460ms, transform 700ms ease 460ms",
          }}>
            {/* Micro header */}
            <div style={{
              fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
              letterSpacing: "0.28em", color: T.textTer,
              marginBottom: 14,
              display: "flex", alignItems: "center", gap: 8,
            }}>
              <span style={{ width: 6, height: 6, borderRadius: 999, background: V.neonGold,
                boxShadow: `0 0 8px ${V.neonGold}` }} />
              <span>MOMENTS · {String(idx + 1).padStart(2, "0")}/{GENRE_MOMENTS.length}</span>
              {scrubbing && (
                <span style={{
                  marginLeft: "auto",
                  fontSize: 8, letterSpacing: "0.2em",
                  padding: "2px 6px",
                  color: V.neonGold,
                  border: `1px dashed ${V.neonGold}55`,
                  borderRadius: 2,
                }}>SCRUBBING</span>
              )}
            </div>

            {/* Crossfading content */}
            <div style={{
              opacity: phase === "in" ? 1 : 0,
              transform: phase === "in" ? "translateY(0)" : "translateY(6px)",
              transition: "opacity 320ms ease, transform 320ms ease",
            }}>
              {/* The year — big, serif, editorial */}
              <div style={{
                fontFamily: T.font_display,
                fontSize: isMobile ? 48 : 72,
                fontWeight: 400, lineHeight: 0.95,
                letterSpacing: "-0.02em",
                color: T.text,
                marginBottom: 10,
                fontStyle: "italic",
              }}>
                {current.year}
              </div>
              {/* Genre tag */}
              <div style={{
                display: "inline-block",
                padding: "3px 10px",
                marginBottom: 12,
                background: `${V.neonGold}12`,
                border: `1px solid ${V.neonGold}55`,
                borderRadius: 3,
                fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
                letterSpacing: "0.15em", color: V.neonGold,
                textShadow: `0 0 6px ${V.neonGold}66`,
              }}>
                {current.genre.toUpperCase()}
              </div>
              {/* The epitaph — lowercase, italic, literary */}
              <div style={{
                fontFamily: T.font_display,
                fontSize: isMobile ? 15 : 17,
                lineHeight: 1.45, fontStyle: "italic",
                color: T.textSec,
                maxWidth: 340,
              }}>
                {current.epitaph}.
              </div>
            </div>

            {/* Progress dots at the bottom of the card */}
            <div style={{
              position: "absolute", left: isMobile ? 18 : 24, bottom: isMobile ? 14 : 18,
              display: "flex", gap: 3,
            }}>
              {GENRE_MOMENTS.map((_, i) => (
                <span key={i} style={{
                  width: i === idx ? 14 : 4, height: 2,
                  background: i === idx ? V.neonGold : "rgba(255,255,255,0.15)",
                  borderRadius: 1,
                  transition: "width 320ms ease, background 320ms ease",
                  boxShadow: i === idx ? `0 0 4px ${V.neonGold}` : "none",
                }} />
              ))}
            </div>
          </div>

          {/* ═══ RIGHT: EDITORIAL STATEMENT STACK ═══ */}
          <div style={{
            display: "flex", flexDirection: "column",
            gap: isMobile ? 16 : 20,
          }}>
            {/* Kicker — first element in the entrance stagger */}
            <div style={{
              fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
              letterSpacing: "0.32em", color: V.neonGold,
              display: "flex", alignItems: "center", gap: 10,
              opacity: entered ? 1 : 0,
              transform: entered ? "translateY(0)" : "translateY(10px)",
              transition: "opacity 500ms ease 100ms, transform 500ms ease 100ms",
            }}>
              <span style={{ width: 18, height: 1, background: V.neonGold, opacity: 0.6 }} />
              GENRE HISTORY · SIXTY YEARS OF SOUND
              <span style={{ flex: 1, maxWidth: 60, height: 1, background: V.neonGold, opacity: 0.25 }} />
            </div>

            {/* The statement — Instrument Serif, huge, editorial */}
            <h1 style={{
              margin: 0,
              fontFamily: T.font_display,
              fontSize: isMobile ? "clamp(36px, 9vw, 52px)" : "clamp(44px, 5.5vw, 76px)",
              fontWeight: 400, lineHeight: 0.98,
              letterSpacing: "-0.025em",
              color: T.text,
              opacity: entered ? 1 : 0,
              transform: entered ? "translateY(0)" : "translateY(16px)",
              transition: "opacity 800ms ease 240ms, transform 800ms ease 240ms",
            }}>
              Every sound had<br />
              <span style={{
                fontStyle: "italic",
                background: `linear-gradient(90deg, ${V.neonGold} 0%, #FFB800 100%)`,
                WebkitBackgroundClip: "text",
                WebkitTextFillColor: "transparent",
                backgroundClip: "text",
              }}>a moment</span>.
              <span style={{ color: T.textTer }}> Then another.</span>
            </h1>

            {/* Subcopy */}
            <p style={{
              margin: 0,
              fontFamily: T.font_sans,
              fontSize: isMobile ? 15 : 17,
              lineHeight: 1.6, color: T.textSec,
              maxWidth: 520,
              opacity: entered ? 1 : 0,
              transform: entered ? "translateY(0)" : "translateY(10px)",
              transition: "opacity 700ms ease 400ms, transform 700ms ease 400ms",
            }}>
              Sixty years of genre births, peaks, and slow fades — mapped from {firstYear} through today. Drag the timeline below to jump through the moments, or let it breathe on its own.
            </p>
          </div>
        </div>

        {/* ═══ BOTTOM: INTERACTIVE TIMELINE SCRUBBER + SONOGRAM ═══
            This is the "unique and memorable" layer. A scrubbable
            timeline track that gives the user direct control over
            the featured moment above. Click or drag anywhere along
            the track to jump the year card to the nearest moment.
            The sonogram pulse underneath is visually anchored to
            the timeline so hovering one affects the other's focus.
            The 2026 end-marker pulses softly as "you are here".
        */}
        <div style={{
          marginTop: isMobile ? 28 : 40,
          paddingTop: 20,
          borderTop: `1px solid rgba(255, 255, 255, 0.06)`,
          position: "relative",
          opacity: entered ? 1 : 0,
          transform: entered ? "translateY(0)" : "translateY(8px)",
          transition: "opacity 700ms ease 620ms, transform 700ms ease 620ms",
        }}>
          {/* Micro label row — HOW TO USE + YOU-ARE-HERE pill */}
          <div style={{
            display: "flex", alignItems: "center", gap: 10,
            marginBottom: 14,
            fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
            letterSpacing: "0.2em",
          }}>
            <span style={{ color: T.textTer }}>
              ◂ DRAG OR TAP TIMELINE ▸
            </span>
            <span style={{ flex: 1 }} />
            <span style={{
              display: "inline-flex", alignItems: "center", gap: 6,
              padding: "3px 9px",
              background: `${V.neonGold}14`,
              border: `1px solid ${V.neonGold}55`,
              borderRadius: 2,
              color: V.neonGold,
              letterSpacing: "0.22em",
            }}>
              <span style={{
                position: "relative",
                width: 6, height: 6, borderRadius: 999,
                background: V.neonGold,
                boxShadow: `0 0 8px ${V.neonGold}`,
                animation: "ghhYouPulse 1.8s ease-in-out infinite",
              }} />
              YOU ARE HERE · 2026
            </span>
          </div>

          {/* The scrubber track itself. 56px tall hit region (mobile-safe)
              containing: the year-tick labels on top, the interactive bar
              in the middle, the sonogram pulse below. All pointer events
              land on the track wrapper and translate to a moment index. */}
          <div
            ref={trackRef}
            onPointerDown={onPointerDown}
            onPointerMove={onPointerMove}
            onPointerUp={onPointerUp}
            onPointerCancel={onPointerUp}
            style={{
              position: "relative",
              height: 80,
              cursor: scrubbing ? "grabbing" : "grab",
              touchAction: "none",
              userSelect: "none",
            }}
          >
            {/* Decade tick labels — positioned along the top of the track */}
            <div style={{
              position: "absolute", left: 0, right: 0, top: 0,
              display: "flex", justifyContent: "space-between",
              fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
              letterSpacing: "0.14em", color: T.textTer,
              pointerEvents: "none",
            }}>
              {["1960", "1970", "1980", "1990", "2000", "2010", "2020", "2026"].map((yr, i, arr) => (
                <span key={yr} style={{
                  color: i === arr.length - 1 ? V.neonGold : T.textTer,
                  textShadow: i === arr.length - 1 ? `0 0 4px ${V.neonGold}` : "none",
                }}>{yr}</span>
              ))}
            </div>

            {/* Scrubber rail + filled segment + knob */}
            <div style={{
              position: "absolute", left: 0, right: 0, top: 22,
              height: 4,
              background: "rgba(255, 255, 255, 0.06)",
              borderRadius: 2,
              pointerEvents: "none",
            }}>
              {/* Filled portion up to the current knob */}
              <div style={{
                position: "absolute", left: 0, top: 0, bottom: 0,
                width: `${knobPct}%`,
                background: `linear-gradient(90deg, ${T.accent}60 0%, ${V.neonGold} 100%)`,
                borderRadius: 2,
                transition: scrubbing ? "none" : "width 320ms ease",
              }} />
              {/* Moment tick marks along the rail */}
              {GENRE_MOMENTS.map((_, i) => {
                const pct = (i / maxI) * 100;
                const active = i === idx;
                return (
                  <span key={i} style={{
                    position: "absolute",
                    left: `${pct}%`, top: -3,
                    width: active ? 2 : 1, height: 10,
                    marginLeft: active ? -1 : -0.5,
                    background: active ? V.neonGold : "rgba(255,255,255,0.2)",
                    borderRadius: 1,
                    boxShadow: active ? `0 0 6px ${V.neonGold}` : "none",
                    transition: "background 260ms ease",
                  }} />
                );
              })}
              {/* Knob */}
              <div style={{
                position: "absolute",
                left: `${knobPct}%`, top: -6,
                width: 16, height: 16,
                marginLeft: -8,
                borderRadius: 999,
                background: V.neonGold,
                border: `2px solid #0A0D14`,
                boxShadow: `0 0 0 2px ${V.neonGold}33, 0 0 14px ${V.neonGold}66`,
                transition: scrubbing ? "none" : "left 320ms ease",
              }} />
            </div>

            {/* "You are here" 2026 marker — positioned flush right, over
                the end of the rail. Pulses independently of the knob. */}
            <div aria-hidden="true" style={{
              position: "absolute", right: 0, top: 18,
              width: 12, height: 12,
              marginRight: -2,
              pointerEvents: "none",
            }}>
              <span style={{
                position: "absolute", inset: 0,
                borderRadius: 999,
                border: `2px solid ${V.neonGold}`,
                animation: "ghhYouPing 1.8s ease-out infinite",
              }} />
              <span style={{
                position: "absolute", inset: 3,
                borderRadius: 999,
                background: V.neonGold,
                boxShadow: `0 0 8px ${V.neonGold}`,
              }} />
            </div>

            {/* Sonogram pulse line — positioned below the rail, visually
                anchored so the track and the sonogram read as one object.
                Stroke-draws on entrance for the cinematic reveal. */}
            <svg viewBox="0 0 1200 40" preserveAspectRatio="none"
              style={{
                position: "absolute", left: 0, right: 0, bottom: 0,
                width: "100%", height: 40, display: "block",
                pointerEvents: "none",
              }}>
              <defs>
                <linearGradient id="ghhPulseGrad" x1="0%" y1="0%" x2="100%" y2="0%">
                  <stop offset="0%"   stopColor={T.accent} stopOpacity="0.15" />
                  <stop offset="50%"  stopColor={V.neonGold} stopOpacity="0.85" />
                  <stop offset="100%" stopColor={V.neonGold} stopOpacity="1" />
                </linearGradient>
              </defs>
              {/* Baseline */}
              <line x1="0" y1="20" x2="1200" y2="20"
                stroke="rgba(255,255,255,0.08)" strokeWidth="1" />
              {/* Primary pulse — stroke-draws on mount, then flows */}
              <path
                d="M 0 20 L 40 20 L 50 10 L 60 30 L 70 20 L 130 20 L 140 6 L 150 34 L 160 20 L 210 20 L 220 12 L 230 28 L 240 20 L 300 20 L 310 8 L 320 32 L 330 20 L 380 20 L 390 14 L 400 26 L 410 20 L 470 20 L 480 4 L 490 36 L 500 20 L 560 20 L 570 10 L 580 30 L 590 20 L 650 20 L 660 14 L 670 26 L 680 20 L 740 20 L 750 8 L 760 32 L 770 20 L 830 20 L 840 12 L 850 28 L 860 20 L 920 20 L 930 4 L 940 36 L 950 20 L 1020 20 L 1030 12 L 1040 28 L 1050 20 L 1110 20 L 1120 2 L 1130 38 L 1140 20 L 1200 20"
                fill="none"
                stroke="url(#ghhPulseGrad)"
                strokeWidth="1.5"
                strokeDasharray={entered ? "4 3" : "1200"}
                strokeDashoffset={entered ? 0 : 1200}
                strokeLinecap="round"
                style={{
                  transition: "stroke-dashoffset 1600ms ease-out 520ms, stroke-dasharray 50ms linear 2100ms",
                  animation: entered ? "ghhPulseFlow 6s linear 2200ms infinite" : "none",
                }}
              />
              {/* Echo pass — slower, lower opacity */}
              <path
                d="M 0 20 L 50 20 L 60 14 L 70 26 L 80 20 L 150 20 L 160 10 L 170 30 L 180 20 L 260 20 L 270 6 L 280 34 L 290 20 L 360 20 L 370 14 L 380 26 L 390 20 L 470 20 L 480 8 L 490 32 L 500 20 L 580 20 L 590 12 L 600 28 L 610 20 L 700 20 L 710 6 L 720 34 L 730 20 L 820 20 L 830 14 L 840 26 L 850 20 L 940 20 L 950 10 L 960 30 L 970 20 L 1060 20 L 1070 4 L 1080 36 L 1090 20 L 1200 20"
                fill="none"
                stroke={T.accent}
                strokeOpacity={entered ? 0.25 : 0}
                strokeWidth="1"
                strokeDasharray="2 4"
                strokeLinecap="round"
                style={{
                  transition: "stroke-opacity 900ms ease 1400ms",
                  animation: entered ? "ghhPulseFlow 11s linear 2200ms infinite reverse" : "none",
                }}
              />
            </svg>
          </div>
        </div>
      </div>
    </>
  );
}

function HistoryPage({ onNavigate }) {
  const { layout } = useLayout();
  const { features } = useTier();
  const isMobile = layout === "mobile";
  const historyMainOnly = features.historyAccess === "main-yearly";
  const allowMonthly    = features.historyAccess === "full-monthly";

  // Main genre families — kept minimal for the free tier
  const MAIN_GENRES = ["Hip-Hop","R&B / Soul","Pop","Electronic","Rock","Metal","Latin","K-Pop","Country","Jazz","Afrobeats","Amapiano","Blues","Folk","Gospel"];
  const AVAILABLE = historyMainOnly
    ? Object.keys(GENRE_HISTORY).filter(g => MAIN_GENRES.includes(g))
    : Object.keys(GENRE_HISTORY);

  const ALL_GENRES = AVAILABLE;
  const defaultSelected = historyMainOnly
    ? AVAILABLE.slice(0, Math.min(3, AVAILABLE.length))
    : ["Hip-Hop","Pop","Electronic","Latin","K-Pop","Afrobeats","Amapiano","Tech-House"].filter(g => AVAILABLE.includes(g));

  const [selected, setSelected] = useState(defaultSelected);
  const [search, setSearch] = useState("");
  const [viewMode, setViewMode] = useState("grid");
  const [resolution, setResolution] = useState("yearly"); // yearly|monthly|weekly
  const [pageMode, setPageMode] = useState("browse"); // browse | charts
  const [selectedLineage, setSelectedLineage] = useState("Hip-Hop"); // currently selected tree node
  const MAX_SELECTED = features.historyMaxSelect || 3;

  // Enforce cap if tier changes and user had too many selected
  useEffect(() => {
    setSelected(prev => prev.filter(g => AVAILABLE.includes(g)).slice(0, MAX_SELECTED));
    if (!allowMonthly && resolution !== "yearly") setResolution("yearly");
  }, [features.historyAccess]);

  // Trend-index pre-computed for all genres
  const trendIndex = useMemo(() => {
    const map = {};
    ALL_GENRES.forEach(g => { map[g] = calcTrendIndex(GENRE_HISTORY[g]); });
    return map;
  }, []);

  const toggleGenre = (g) => {
    setSelected(prev =>
      prev.includes(g)
        ? prev.filter(x => x !== g)
        : prev.length < MAX_SELECTED ? [...prev, g] : prev
    );
  };

  const selectAllVisible = () => {
    setSelected(filteredGenres.slice(0, MAX_SELECTED));
  };
  const clearAll = () => setSelected([]);

  const searchLower = search.trim().toLowerCase();
  const filteredGenres = useMemo(() => {
    let list = ALL_GENRES;
    if (searchLower) list = list.filter(g => g.toLowerCase().includes(searchLower));
    // Single sort: alphabetical
    list = [...list].sort((a, b) => a.localeCompare(b));
    return list;
  }, [searchLower]);

  // Accent-family palette for lines
  const LINE_COLORS = [T.accentHi, T.accent, T.text, T.warning, T.success, "#8B5CF6", "#06B6D4", T.danger, T.textSec, "#FF6B00", "#00E5FF", "#FF2D9C", "#FFD700", "#00FF88", "#E94FEF", "#F5A524", "#4ADE80", "#7C8BFF", "#5E6AD2", "#6B6E76", "#EF4444", "#8B5CF6", "#06B6D4", "#10B981", "#F59E0B"];

  return (
    <div style={{
      maxWidth: 1440, margin: "0 auto",
      padding: isMobile
        ? `${T.s5}px ${T.s4}px ${T.s8}px`
        : `${T.s8}px ${T.s7}px ${T.s10}px`,
    }}>
      {/* ── CINEMATIC HERO — memorable opening ────────────────────────
          Not a plain headline + paragraph. A living intro that evokes
          the whole thesis of the page: music history is a living
          timeline, genres rise and fall, every sound has a moment.

          Composition:
            1. Background: slow-drifting gradient field with faint
               decade tick marks (1960 → 2026) as subliminal context
            2. Foreground LEFT: rotating year-moment ledger that
               cycles through curated {year, genre, epitaph} moments
               every 2.5s — the "living timeline" feel
            3. Foreground RIGHT: editorial headline stack — small
               category kicker, giant serif statement, sub-copy
            4. Bottom: sonogram pulse line (animated SVG) that
               suggests "sound waves through time" — ties the
               abstract "history" to the concrete "audio"
            5. Disclaimer pill remains at the bottom of the hero

          Aesthetic: consumer-facing (V + T palette), Instrument
          Serif for the statement, Geist Mono for the ticker, high
          contrast for long-session readability. No hacker green —
          that belongs to BubbleTools. */}
      <GenreHistoryHero isMobile={isMobile} />

      {/* ── PAGE MODE SWITCHER — simplified to 2 tabs ─────────────────── */}
      <div style={{
        display: "inline-flex",
        background: T.surface, border: `1px solid ${T.border}`,
        borderRadius: 8, padding: 4, marginBottom: T.s6,
      }}>
        {[
          { id: "browse", label: "Browse", hint: "Explore genres grouped by era" },
          { id: "charts", label: "Popularity charts", hint: "Popularity over time" },
        ].map(m => (
          <button key={m.id} type="button"
            onClick={() => { playSwitchSound(); setPageMode(m.id); }}
            title={m.hint}
            style={{
              padding: "8px 16px",
              background: pageMode === m.id ? T.elevated : "transparent",
              border: "none",
              color: pageMode === m.id ? T.text : T.textSec,
              fontSize: 13, fontFamily: T.font_sans, fontWeight: 500,
              borderRadius: 6, cursor: "pointer",
              transition: "all 160ms ease-out",
            }}>{m.label}</button>
        ))}
      </div>

      {/* ── BROWSE MODE — new era-grouped encyclopedia ───────────────── */}
      {pageMode === "browse" && (
        <div style={{ marginBottom: T.s7 }}>
          <GenreBrowser
            selectedGenre={selectedLineage}
            onSelectGenre={setSelectedLineage}
            onNavigate={onNavigate}
          />
        </div>
      )}

      {/* ── TREND CHARTS MODE — existing functionality ───────────────── */}
      {pageMode === "charts" && (<>


      {/* ── CONTROLS — search, sort, view mode, selection counter ───── */}
      <div style={{
        display: "flex", flexWrap: "wrap", gap: T.s3,
        alignItems: "center", marginBottom: T.s4,
      }}>
        <input type="text" value={search} onChange={e => setSearch(e.target.value)}
          placeholder="Search genres…"
          style={{
            flex: "1 1 240px", minWidth: 200,
            background: T.surface, border: `1px solid ${T.border}`,
            color: T.text,
            padding: isMobile ? "10px 12px" : `${T.s2}px ${T.s3}px`,
            fontSize: isMobile ? 16 : T.fs_md,
            fontFamily: T.font_sans,
            borderRadius: T.r_md, outline: "none",
            boxSizing: "border-box",
            height: isMobile ? 40 : "auto",
            WebkitAppearance: "none",
            transition: `border-color ${T.dur_fast} ${T.ease}`,
          }}
          onFocus={e => e.currentTarget.style.borderColor = T.borderFocus}
          onBlur={e => e.currentTarget.style.borderColor = T.border}
        />

        {/* View mode */}
        <div style={{
          display: "flex", background: T.surface,
          border: `1px solid ${T.border}`, borderRadius: T.r_md, padding: 2,
        }}>
          {[
            { id: "grid",    label: "Grid" },
            { id: "overlay", label: "Overlay" },
          ].map(o => (
            <button key={o.id} type="button" onClick={() => { playSwitchSound(); setViewMode(o.id); }} style={{
              background: viewMode === o.id ? T.elevated : "transparent",
              border: "none",
              color: viewMode === o.id ? T.text : T.textTer,
              padding: `${T.s2}px ${T.s3}px`, cursor: "pointer",
              fontSize: T.fs_sm, fontFamily: T.font_sans, fontWeight: 500,
              borderRadius: T.r_sm,
              transition: `all ${T.dur_fast} ${T.ease}`,
            }}>{o.label}</button>
          ))}
        </div>

        <span style={{
          fontSize: T.fs_sm, color: T.textSec, fontFamily: T.font_mono,
          marginLeft: "auto",
        }}>
          {selected.length} / {MAX_SELECTED} selected
        </span>

        <Button variant="ghost" size="sm" onClick={() => { playSwitchSound(); selectAllVisible(); }}>
          Select top {Math.min(MAX_SELECTED, filteredGenres.length)}
        </Button>
        <Button variant="ghost" size="sm" onClick={() => { playSwitchSound(); clearAll(); }}>Clear</Button>
      </div>

      {/* ── CHART AREA ─────────────────────────────────────────────── */}
      {selected.length === 0 ? (
        <div style={{
          padding: `${T.s7}px ${T.s5}px`,
          background: T.surface, border: `1px dashed ${T.border}`,
          borderRadius: T.r_lg, textAlign: "center",
          color: T.textTer, fontFamily: T.font_sans,
          marginBottom: T.s6,
        }}>
          Select up to {MAX_SELECTED} genres below to see their popularity curves.
        </div>
      ) : viewMode === "overlay" ? (
        <OverlayChart selected={selected} colors={LINE_COLORS} />
      ) : (
        <MiniChartGrid selected={selected} colors={LINE_COLORS} trendIndex={trendIndex} />
      )}

      {/* ── GENRE PICKER LIST ──────────────────────────────────────── */}
      <Label color={T.textSec} style={{ display: "block", marginBottom: T.s3 }}>
        All genres ({filteredGenres.length})
      </Label>
      <div style={{
        display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))",
        gap: T.s2, marginBottom: T.s7,
      }}>
        {filteredGenres.map(g => {
          const isOn = selected.includes(g);
          const score = trendIndex[g];
          const idx = selected.indexOf(g);
          const color = idx >= 0 ? LINE_COLORS[idx % LINE_COLORS.length] : T.textTer;
          const disabled = !isOn && selected.length >= MAX_SELECTED;
          return (
            <button key={g} type="button"
              onClick={() => { if (!disabled) { playSwitchSound(); toggleGenre(g); } }}
              disabled={disabled}
              style={{
                display: "flex", alignItems: "center", justifyContent: "space-between",
                gap: T.s2, padding: `${T.s2}px ${T.s3}px`,
                background: isOn ? T.elevated : T.surface,
                border: `1px solid ${isOn ? T.borderHi : T.border}`,
                borderRadius: T.r_md,
                color: isOn ? T.text : T.textSec,
                fontFamily: T.font_sans, fontSize: T.fs_sm, fontWeight: 500,
                cursor: disabled ? "not-allowed" : "pointer",
                opacity: disabled ? 0.35 : 1,
                transition: `all ${T.dur_fast} ${T.ease}`,
                textAlign: "left",
              }}>
              <span style={{ display: "inline-flex", alignItems: "center", gap: T.s2, flex: 1, minWidth: 0 }}>
                <span style={{
                  width: 8, height: 8, borderRadius: "50%",
                  background: isOn ? color : T.border,
                  flexShrink: 0,
                }} />
                <span style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{g}</span>
              </span>
              <span style={{
                fontSize: T.fs_xs, color: T.textTer,
                fontFamily: T.font_mono, flexShrink: 0,
              }}>{score}</span>
            </button>
          );
        })}
      </div>

      {/* ── CONTEXT CARDS ─────────────────────────────────────────── */}
      {selected.filter(g => GENRE_CONTEXT[g]).length > 0 && (
        <div>
          <Label color={T.textSec} style={{ display: "block", marginBottom: T.s3 }}>
            Context
          </Label>
          <div style={{
            display: "grid", gap: T.s3,
            gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))",
          }}>
            {selected.filter(g => GENRE_CONTEXT[g]).map(g => (
              <div key={g} style={{
                padding: T.s4,
                background: T.surface, border: `1px solid ${T.border}`,
                borderRadius: T.r_md,
              }}>
                <div style={{
                  display: "flex", justifyContent: "space-between", alignItems: "baseline",
                  marginBottom: T.s2,
                }}>
                  <span style={{
                    fontSize: T.fs_base, color: T.text, fontWeight: 600,
                    fontFamily: T.font_sans,
                  }}>{g}</span>
                  <span style={{
                    fontSize: T.fs_sm, color: T.accentHi,
                    fontFamily: T.font_mono, fontWeight: 600,
                  }}>{trendIndex[g]}</span>
                </div>
                <div style={{
                  fontSize: T.fs_md, color: T.textSec, lineHeight: 1.55,
                  fontFamily: T.font_sans,
                }}>{GENRE_CONTEXT[g]}</div>
              </div>
            ))}
          </div>
        </div>
      )}
      </>)}
    </div>
  );
}

// ── Overlay chart: single large SVG with all selected genres overlaid ──
function OverlayChart({ selected, colors }) {
  const width = 1000, height = 480;
  const padL = 56, padR = 28, padT = 32, padB = 40;
  const plotW = width - padL - padR, plotH = height - padT - padB;
  const years = [1960, 1970, 1980, 1990, 2000, 2010, 2020, 2026];
  const xFor = (yr) => padL + ((yr - 1960) / (2026 - 1960)) * plotW;
  const yFor = (v) => padT + (1 - v / 100) * plotH;

  const pathFor = (data) => {
    const sorted = [...data].sort((a, b) => a[0] - b[0]);
    return sorted.map((pt, i) =>
      `${i === 0 ? "M" : "L"} ${xFor(pt[0]).toFixed(1)} ${yFor(pt[1]).toFixed(1)}`
    ).join(" ");
  };

  return (
    <div style={{
      background: T.surface, border: `1px solid ${T.border}`,
      borderRadius: T.r_lg, padding: T.s5, marginBottom: T.s6,
    }}>
      <svg viewBox={`0 0 ${width} ${height}`} style={{ width: "100%", height: "auto", display: "block" }}>
        {[0, 25, 50, 75, 100].map(v => (
          <g key={v}>
            <line x1={padL} x2={width - padR} y1={yFor(v)} y2={yFor(v)}
              stroke={T.border} strokeWidth={1} strokeDasharray="2 4" />
            <text x={padL - 10} y={yFor(v) + 4} textAnchor="end"
              fill={T.textTer} fontSize={T.fs_xs} fontFamily={T.font_mono}>{v}</text>
          </g>
        ))}
        {years.map(yr => (
          <text key={yr} x={xFor(yr)} y={height - padB + 20} textAnchor="middle"
            fill={T.textTer} fontSize={T.fs_xs} fontFamily={T.font_mono}>{yr}</text>
        ))}
        <line x1={padL} x2={width - padR} y1={height - padB} y2={height - padB} stroke={T.borderHi} strokeWidth={1} />
        <line x1={padL} x2={padL} y1={padT} y2={height - padB} stroke={T.borderHi} strokeWidth={1} />

        {selected.map((g, i) => {
          const data = GENRE_HISTORY[g] || [];
          const color = colors[i % colors.length];
          return (
            <g key={g}>
              <path d={pathFor(data)} fill="none" stroke={color} strokeWidth={1.5}
                strokeLinejoin="round" strokeLinecap="round" opacity={0.9} />
            </g>
          );
        })}
      </svg>
    </div>
  );
}

// ── Mini chart grid: small multiples, one chart per genre ──
function MiniChartGrid({ selected, colors, trendIndex }) {
  return (
    <div style={{
      display: "grid",
      gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))",
      gap: T.s3, marginBottom: T.s6,
    }}>
      {selected.map((g, i) => (
        <MiniChart key={g} genre={g} data={GENRE_HISTORY[g] || []}
          color={colors[i % colors.length]} score={trendIndex[g]} />
      ))}
    </div>
  );
}

function MiniChart({ genre, data, color, score }) {
  const width = 220, height = 120;
  const padL = 8, padR = 8, padT = 28, padB = 20;
  const plotW = width - padL - padR, plotH = height - padT - padB;
  const xFor = (yr) => padL + ((yr - 1960) / (2026 - 1960)) * plotW;
  const yFor = (v) => padT + (1 - v / 100) * plotH;

  const sorted = [...data].sort((a, b) => a[0] - b[0]);
  const path = sorted.map((pt, i) =>
    `${i === 0 ? "M" : "L"} ${xFor(pt[0]).toFixed(1)} ${yFor(pt[1]).toFixed(1)}`
  ).join(" ");
  // Area fill
  const areaPath = sorted.length > 0
    ? `${path} L ${xFor(sorted[sorted.length - 1][0])} ${yFor(0)} L ${xFor(sorted[0][0])} ${yFor(0)} Z`
    : "";

  const barColor = score >= 85 ? T.success : score >= 70 ? T.warning : T.accent;

  return (
    <div style={{
      padding: T.s3,
      background: T.surface, border: `1px solid ${T.border}`,
      borderRadius: T.r_md,
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 6 }}>
        <span style={{
          fontSize: T.fs_sm, color: T.text, fontWeight: 600,
          fontFamily: T.font_sans,
          overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
          minWidth: 0, flex: 1,
        }}>{genre}</span>
        <span style={{
          fontSize: T.fs_sm, color: barColor, fontFamily: T.font_mono,
          fontWeight: 700, marginLeft: T.s2, flexShrink: 0,
        }}>{score}</span>
      </div>
      <svg viewBox={`0 0 ${width} ${height}`} style={{ width: "100%", height: "auto", display: "block" }}>
        <path d={areaPath} fill={color} opacity={0.15} />
        <path d={path} fill="none" stroke={color} strokeWidth={1.3}
          strokeLinejoin="round" strokeLinecap="round" />
        <line x1={padL} x2={width - padR} y1={height - padB} y2={height - padB}
          stroke={T.border} strokeWidth={1} />
        <text x={padL} y={height - 4} fill={T.textTer} fontSize={9} fontFamily={T.font_mono}>1960</text>
        <text x={width - padR} y={height - 4} textAnchor="end"
          fill={T.textTer} fontSize={9} fontFamily={T.font_mono}>2026</text>
      </svg>
    </div>
  );
}





