// Static style objects for trend cards — hoisted out of map() to avoid
// re-creating per-item on every render.
const TREND_CARD_NUM_STYLE = {
  fontSize: 9, fontFamily: T.font_mono, fontWeight: 700,
  color: "#FFD700", letterSpacing: "0.22em", marginBottom: 6,
};
const TREND_CARD_ARTIST_STYLE = {
  fontSize: T.fs_lg, fontFamily: T.font_sans, fontWeight: 600,
  color: T.text, marginBottom: 4, letterSpacing: "-0.01em",
};
const TREND_CARD_TRACK_STYLE = {
  fontSize: T.fs_sm, fontFamily: T.font_display, fontStyle: "italic",
  color: T.textSec, marginBottom: T.s2, lineHeight: 1.3,
};
const TREND_CARD_GENRE_STYLE = {
  fontSize: 10, fontFamily: T.font_mono, color: T.textMuted,
  letterSpacing: "0.08em", textTransform: "uppercase",
};

function TrendSetterPage() {
  const { layout } = useLayout();
  const { fuels, consumeFuel, setActiveFuel } = useFuel();
  const isMobile = layout === "mobile";
  const [region, setRegion] = useState("us");
  const [selectedItem, setSelectedItem] = useState(null);
  const [copyState, setCopyState] = useState("idle");

  // On unmount (user leaves Trend Setter), snap fuel back to free.
  // Per product decision: always snap to free regardless of prior state.
  useEffect(() => {
    return () => {
      setActiveFuel("free");
    };
  }, [setActiveFuel]);

  const regionData = TREND_DATA[region];
  const trendFuelLeft = fuels.trend;

  const generatePrompt = (item) => {
    // IMPORTANT: prompts must NEVER name real artists or real tracks — doing
    // so creates legal/IP exposure and degrades output quality (AI models
    // trained on copyrighted material will refuse or mangle named-artist
    // requests). Instead we describe the SONIC FINGERPRINT using the
    // item's genre + style-descriptor metadata, which captures the viral
    // quality without referencing any protected work.
    //
    // Trend Setter implies user wants vocals (most viral tracks have vocals),
    // so we sanitize Suno's vocal-killer words from the output.
    const raw = `${item.genre}, ${item.style}, modern mix, radio-ready production, 2026 viral energy, contemporary chart-topping sound`;
    return sunoSanitize(raw, true);
  };

  const doCopy = async (text) => {
    const ok = await copyToClipboard(text);
    setCopyState(ok ? "copied" : "error");
    setTimeout(() => setCopyState("idle"), 2000);
  };

  return (
    <div style={{
      maxWidth: 1100, margin: "0 auto",
      padding: isMobile ? `${T.s6}px ${T.s4}px ${T.s10}px` : `${T.s8}px ${T.s7}px ${T.s10}px`,
    }}>
      {/* Masthead */}
      <div style={{ marginBottom: T.s8, paddingBottom: T.s6, borderBottom: `1px solid ${T.border}` }}>
        <div style={{
          display: "flex", alignItems: "center", gap: T.s3, marginBottom: T.s4,
          fontSize: 10, fontFamily: T.font_mono, letterSpacing: "0.22em",
        }}>
          <span style={{ color: "#FFD700", fontWeight: 700, textShadow: "0 0 6px #FFD70066" }}>⭐ TREND SETTER · VIP</span>
          <div style={{ flex: 1, height: 1, background: `linear-gradient(90deg, #FFD70066 0%, transparent 100%)` }} />
          <span style={{ color: T.textMuted }}>
            FUEL: {Number.isFinite(trendFuelLeft) ? trendFuelLeft : "∞"} / 50
          </span>
        </div>
        <h1 style={{
          fontSize: isMobile ? "clamp(48px, 13vw, 80px)" : "clamp(80px, 9vw, 140px)",
          lineHeight: 0.92, letterSpacing: "-0.03em",
          margin: 0, marginBottom: T.s4,
          fontFamily: T.font_display, fontWeight: 400, fontStyle: "italic",
          color: T.text,
        }}>
          Trend Setter
        </h1>
        <p style={{
          fontSize: isMobile ? T.fs_lg : T.fs_xl, lineHeight: 1.4, color: T.textSec,
          fontFamily: T.font_display, fontStyle: "italic", margin: 0, maxWidth: 640,
        }}>
          Ride the currents. Generate prompts biased toward what's peaking right now in your chosen region.
        </p>
      </div>

      {/* Region tabs */}
      <div style={{
        display: "flex", gap: T.s2, marginBottom: T.s6, flexWrap: "wrap",
      }}>
        {Object.entries(TREND_DATA).map(([id, data]) => {
          const active = region === id;
          return (
            <button key={id} type="button"
              onClick={() => { playSwitchSound(); setRegion(id); setSelectedItem(null); }}
              style={{
                display: "inline-flex", alignItems: "center", gap: T.s2,
                padding: `${T.s3}px ${T.s4}px`,
                background: active ? `linear-gradient(135deg, #FFD70022 0%, transparent 100%)` : T.surface,
                border: `1px solid ${active ? "#FFD70088" : T.border}`,
                borderRadius: T.r_md, cursor: "pointer",
                fontSize: T.fs_md, fontFamily: T.font_sans,
                fontWeight: active ? 600 : 500,
                color: active ? T.text : T.textSec,
                transition: `all ${T.dur_fast} ${T.ease}`,
              }}>
              <span style={{ fontSize: 20 }}>{data.flag}</span>
              {data.label}
              <span style={{ fontSize: 10, fontFamily: T.font_mono, color: T.textMuted, marginLeft: 4 }}>
                {data.items.length}
              </span>
            </button>
          );
        })}
      </div>

      {/* Trend grid */}
      <div style={{
        display: "grid",
        gridTemplateColumns: isMobile ? "1fr" : "repeat(auto-fill, minmax(280px, 1fr))",
        gap: T.s3, marginBottom: T.s7,
      }}>
        {regionData.items.map((item, i) => {
          const isSelected = selectedItem === item;
          return (
            <button key={i} type="button"
              onClick={() => { playSwitchSound(); setSelectedItem(item); }}
              style={{
                textAlign: "left", padding: T.s4,
                background: isSelected
                  ? `linear-gradient(135deg, #FFD70014 0%, transparent 100%)`
                  : T.surface,
                border: `1px solid ${isSelected ? "#FFD70088" : T.border}`,
                borderRadius: T.r_lg, cursor: "pointer",
                transition: `all ${T.dur_fast} ${T.ease}`,
              }}>
              <div style={TREND_CARD_NUM_STYLE}>
                #{String(i + 1).padStart(2, "0")} · {regionData.flag}
              </div>
              <div style={TREND_CARD_ARTIST_STYLE}>{item.artist}</div>
              <div style={TREND_CARD_TRACK_STYLE}>{item.track}</div>
              <div style={TREND_CARD_GENRE_STYLE}>{item.genre}</div>
            </button>
          );
        })}
      </div>

      {/* Selected item detail */}
      {selectedItem && (
        <div style={{
          padding: T.s5,
          background: `linear-gradient(135deg, #FFD70008 0%, transparent 100%)`,
          border: `1px solid #FFD70044`, borderRadius: T.r_lg, marginBottom: T.s7,
        }}>
          <div style={{
            fontSize: 10, fontFamily: T.font_mono, fontWeight: 700,
            color: "#FFD700", letterSpacing: "0.22em", marginBottom: T.s3,
          }}>
            ▸ GENERATED TREND PROMPT
          </div>
          <div style={{
            padding: T.s4, background: T.bg,
            border: `1px solid ${T.border}`, borderRadius: T.r_md,
            fontFamily: T.font_mono, fontSize: T.fs_md, lineHeight: 1.6,
            color: T.text, marginBottom: T.s3,
          }}>
            {generatePrompt(selectedItem)}
          </div>
          <button type="button"
            onClick={() => { playSwitchSound(); doCopy(generatePrompt(selectedItem)); }}
            style={{
              padding: `${T.s3}px ${T.s5}px`,
              background: copyState === "copied" ? T.success : "#FFD700",
              border: "none", borderRadius: T.r_md,
              color: "#000", fontWeight: 700, fontSize: T.fs_md,
              fontFamily: T.font_sans, cursor: "pointer",
              letterSpacing: "0.05em",
              transition: "all 160ms ease-out",
            }}>
            {copyState === "copied" ? "✓ Copied" : "Copy prompt"}
          </button>
        </div>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// JOYSTICK — retro single-stick fuel selector (Atari-2600 style).
// Shows 2-3 positions depending on tier. Moving to trend snaps to TrendSetterPage
// with a tire-smoke animation and synthesized car-takeoff sound via Web Audio.
// ════════════════════════════════════════════════════════════════════════════

// Synthesize car-takeoff sound via Web Audio. ~3 seconds, decays naturally.
// Uses oscillator with rising frequency + noise for tire screech texture.
// Switch/toggle sound helper — pool of 3 Audio elements cycled so rapid
// toggles don't cut off each other. Loaded lazily on first call and cached.
let _switchAudioPool = null;
let _switchAudioIdx = 0;
function playSwitchSound() {
  try {
    if (typeof window === "undefined" || typeof Audio === "undefined") return;
    if (!_switchAudioPool) {
      // Cache-bust query param forces a fresh fetch when the asset is
      // replaced. Bump the version number when swapping the sound file.
      _switchAudioPool = [new Audio("/switch-sound.mp3?v=2"), new Audio("/switch-sound.mp3?v=2"), new Audio("/switch-sound.mp3?v=2")];
      _switchAudioPool.forEach(a => { a.volume = 0.5; a.preload = "auto"; });
    }
    const a = _switchAudioPool[_switchAudioIdx];
    _switchAudioIdx = (_switchAudioIdx + 1) % _switchAudioPool.length;
    a.currentTime = 0;
    const p = a.play();
    if (p && typeof p.catch === "function") p.catch(() => {}); // ignore autoplay rejections
  } catch {}
}

// Button sound helper — fires on first touch of the joystick (pointer-down)
// Same pool pattern as switch sound so rapid touches don't cut off.
let _buttonAudioPool = null;
let _buttonAudioIdx = 0;
function playButtonSound() {
  try {
    if (typeof window === "undefined" || typeof Audio === "undefined") return;
    if (!_buttonAudioPool) {
      _buttonAudioPool = [new Audio("/BUTTON-SOUND.mp3"), new Audio("/BUTTON-SOUND.mp3"), new Audio("/BUTTON-SOUND.mp3")];
      _buttonAudioPool.forEach(a => { a.volume = 0.5; a.preload = "auto"; });
    }
    const a = _buttonAudioPool[_buttonAudioIdx];
    _buttonAudioIdx = (_buttonAudioIdx + 1) % _buttonAudioPool.length;
    a.currentTime = 0;
    const p = a.play();
    if (p && typeof p.catch === "function") p.catch(() => {});
  } catch {}
}

// Hit-button sound — fires once when the user presses HIT and fuel is
// available to start a roll. Uses the same pool pattern as the other
// sound helpers so rapid successive HITs don't cut off.
//
// Asset path: /hit-button-sound.mp3 (the file in public/ is named
// "hit-button-sound.mp3" with hyphens). Confirmed via dir listing on
// 2026-04-19. If the file is ever renamed in public/, update this URL
// to match exactly or the asset will 404.
//
// Version query (?v=2): cache-bust when the sound file is replaced.
// Browsers aggressively cache audio assets so bumping this number
// forces a fresh fetch after a sound swap. Increment when the file
// changes. Matches the same pattern used on switch-sound (?v=2).
//
// DIAGNOSTICS: set window.__HE_DEBUG_AUDIO = true in DevTools console
// to see verbose logs explaining exactly why the sound might not fire.
// Covers: path 404, autoplay policy block, load errors, pool exhaustion.
const HIT_SOUND_URL = "/hit-button-sound.mp3?v=3";
let _hitAudioPool = null;
let _hitAudioIdx = 0;
let _hitAudioLoadError = null;
function playHitSound() {
  const debug = typeof window !== "undefined" && window.__HE_DEBUG_AUDIO;
  try {
    if (typeof window === "undefined" || typeof Audio === "undefined") {
      if (debug) console.warn("[HIT sound] Audio API unavailable");
      return;
    }
    if (!_hitAudioPool) {
      // Initialize pool. Each Audio is a separate HTMLAudioElement so
      // rapid-fire HITs can overlap without cutting each other off.
      _hitAudioPool = [];
      for (let i = 0; i < 3; i++) {
        const a = new Audio(HIT_SOUND_URL);
        a.volume = 0.6;
        a.preload = "auto";
        // Capture any load error so future playHitSound calls can log it
        a.addEventListener("error", (e) => {
          _hitAudioLoadError = a.error ? a.error.code : "unknown";
          if (debug) {
            console.error("[HIT sound] load error code:", _hitAudioLoadError,
              `— expected asset at ${HIT_SOUND_URL} in public/`);
          }
        });
        if (debug) {
          a.addEventListener("canplaythrough", () => {
            console.log("[HIT sound] loaded OK, pool slot", i);
          }, { once: true });
        }
        _hitAudioPool.push(a);
      }
      if (debug) console.log("[HIT sound] pool initialized, 3 slots");
    }
    const a = _hitAudioPool[_hitAudioIdx];
    _hitAudioIdx = (_hitAudioIdx + 1) % _hitAudioPool.length;
    // Reset playhead — important for pool re-use
    try { a.currentTime = 0; } catch (e) {
      if (debug) console.warn("[HIT sound] currentTime reset failed:", e);
    }
    const p = a.play();
    if (p && typeof p.then === "function") {
      p.then(() => {
        if (debug) console.log("[HIT sound] play() resolved");
      }).catch(err => {
        if (debug) {
          console.error("[HIT sound] play() rejected:", err.name, err.message);
          if (err.name === "NotAllowedError") {
            console.warn("[HIT sound] Autoplay blocked — browser requires a user gesture first. Click anywhere, then try HIT again.");
          } else if (err.name === "NotSupportedError") {
            console.warn(`[HIT sound] Source format not supported or file missing. Check Network tab for 404 on ${HIT_SOUND_URL}`);
          }
        }
      });
    }
  } catch (e) {
    if (debug) console.error("[HIT sound] unexpected error:", e);
  }
}

// Fuel-button sound — short, punchy click used on fuel tank tiles in the
// FUEL SELECT gearshift. Distinct from BUTTON-SOUND and SWITCH-SOUND so
// fuel changes have their own sonic identity.
let _fuelBtnAudioPool = null;
let _fuelBtnAudioIdx = 0;
function playFuelButtonSound() {
  try {
    if (typeof window === "undefined" || typeof Audio === "undefined") return;
    if (!_fuelBtnAudioPool) {
      _fuelBtnAudioPool = [new Audio("/BUTTON-SOUND.mp3"), new Audio("/BUTTON-SOUND.mp3"), new Audio("/BUTTON-SOUND.mp3")];
      _fuelBtnAudioPool.forEach(a => { a.volume = 0.55; a.preload = "auto"; });
    }
    const a = _fuelBtnAudioPool[_fuelBtnAudioIdx];
    _fuelBtnAudioIdx = (_fuelBtnAudioIdx + 1) % _fuelBtnAudioPool.length;
    a.currentTime = 0;
    const p = a.play();
    if (p && typeof p.catch === "function") p.catch(() => {});
  } catch {}
}

function playCarTakeoffSound() {
  try {
    const AudioCtx = window.AudioContext || window.webkitAudioContext;
    if (!AudioCtx) return;
    const ctx = new AudioCtx();
    const now = ctx.currentTime;

    // Engine low-rumble: rising sawtooth from 80Hz to 200Hz
    const engine = ctx.createOscillator();
    engine.type = "sawtooth";
    engine.frequency.setValueAtTime(80, now);
    engine.frequency.exponentialRampToValueAtTime(200, now + 2.5);
    const engineGain = ctx.createGain();
    engineGain.gain.setValueAtTime(0.25, now);
    engineGain.gain.exponentialRampToValueAtTime(0.001, now + 3);
    engine.connect(engineGain).connect(ctx.destination);
    engine.start(now);
    engine.stop(now + 3);

    // High-pitched screech (tire slip)
    const screech = ctx.createOscillator();
    screech.type = "square";
    screech.frequency.setValueAtTime(1800, now);
    screech.frequency.exponentialRampToValueAtTime(400, now + 0.6);
    const screechGain = ctx.createGain();
    screechGain.gain.setValueAtTime(0.08, now);
    screechGain.gain.exponentialRampToValueAtTime(0.001, now + 0.8);
    screech.connect(screechGain).connect(ctx.destination);
    screech.start(now);
    screech.stop(now + 0.8);

    // Noise burst (tire smoke / road)
    const bufferSize = ctx.sampleRate * 3;
    const noiseBuffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const noiseData = noiseBuffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) noiseData[i] = (Math.random() * 2 - 1) * (1 - i / bufferSize);
    const noise = ctx.createBufferSource();
    noise.buffer = noiseBuffer;
    const noiseFilter = ctx.createBiquadFilter();
    noiseFilter.type = "lowpass";
    noiseFilter.frequency.value = 2000;
    const noiseGain = ctx.createGain();
    noiseGain.gain.setValueAtTime(0.12, now);
    noiseGain.gain.exponentialRampToValueAtTime(0.001, now + 2.5);
    noise.connect(noiseFilter).connect(noiseGain).connect(ctx.destination);
    noise.start(now);
    noise.stop(now + 3);
  } catch (err) {
    // Silent fail — audio isn't critical
    console.log("Audio unavailable:", err);
  }
}

// Static style for smoke puff particles — hoisted to avoid re-creating
// 12 identical objects per transition render cycle.
const SMOKE_PUFF_STATIC_STYLE = {
  position: "absolute",
  borderRadius: "50%",
  background: "radial-gradient(circle, rgba(220,220,220,0.4) 0%, transparent 70%)",
  pointerEvents: "none",
};

function Joystick({ onNavigate, onLockedClick }) {
  const { tier, features } = useTier();
  const { fuels, activeFuel, setActiveFuel } = useFuel();
  const { layout } = useLayout();
  const isMobile = layout === "mobile";
  const [transitioning, setTransitioning] = useState(false);
  const [hoverPos, setHoverPos] = useState(null);
  // Drag state — when non-null, overrides the discrete tiltAngle with a
  // continuous value so the handle tracks the pointer 1:1.
  const [dragAngle, setDragAngle] = useState(null);
  const svgRef = useRef(null);
  // Track pointer-down position so we can distinguish a tap (click) from a
  // drag on pointer-up. Small movement → toggle free/pro; larger → snap-drag.
  const pointerStartRef = useRef(null);

  // Joystick is always rendered with all 3 positions so free/pro users can
  // see the full VIP experience (and be tempted to upgrade). Trend slot is
  // visually locked for tiers without trend fuel allocation.
  const hasTrend = features.dailyFuel.trend > 0;
  const positions = ["free", "pro", "trend"];
  const isLocked = (pos) => pos === "trend" && !hasTrend;

  const currentIdx = Math.max(0, positions.indexOf(activeFuel));

  // Compute the discrete tilt angle for a given position index.
  // Always 3 positions now: -22°, 0°, +22°.
  const angleForIdx = (idx) => (idx - 1) * 22;

  // Joystick tilt angle: -1 = left, 0 = center, +1 = right
  const discreteTilt = angleForIdx(currentIdx);
  // During drag, use live pointer-tracked angle; otherwise use discrete.
  const tiltAngle = dragAngle != null ? dragAngle : discreteTilt;

  const handleSelect = (pos) => {
    if (pos === activeFuel) return;
    // Locked positions open the sales modal instead of switching fuel.
    if (isLocked(pos)) {
      onLockedClick && onLockedClick();
      return;
    }
    setActiveFuel(pos);
    if (pos === "trend") {
      setTransitioning(true);
      playCarTakeoffSound();
      setTimeout(() => {
        onNavigate("trendsetter");
        setTransitioning(false);
      }, 3200);
    }
  };

  // ─── DRAG HANDLERS ────────────────────────────────────────────────
  // Convert a pointer event's clientX into the joystick's angular tilt.
  // The SVG is uniformly scaled, so we map pointer position into SVG
  // coordinates using the bounding rect, then compute angle from the
  // pivot point (JOYSTICK_CX, JOYSTICK_BASE_Y - 8).
  const pointerToAngle = (e) => {
    const svg = svgRef.current;
    if (!svg) return 0;
    const rect = svg.getBoundingClientRect();
    // Normalize pointer X into SVG viewBox coords
    const svgX = ((e.clientX - rect.left) / rect.width) * VB_W;
    const dx = svgX - JOYSTICK_CX;
    // Max horizontal reach at ball height is ~80px (shaft ~85 long).
    // Convert horizontal offset to tilt angle via arcsin approximation.
    const maxReach = 85;
    const normalized = Math.max(-1, Math.min(1, dx / maxReach));
    // Angular range clamp — same as the discrete positions allow
    const maxAngle = positions.length === 3 ? 22 : positions.length === 2 ? 18 : 0;
    return normalized * maxAngle;
  };

  // Snap a live angle to the nearest valid position index.
  const angleToNearestIdx = (angle) => {
    let bestIdx = 0, bestDelta = Infinity;
    for (let i = 0; i < positions.length; i++) {
      const delta = Math.abs(angle - angleForIdx(i));
      if (delta < bestDelta) { bestDelta = delta; bestIdx = i; }
    }
    return bestIdx;
  };

  const handlePointerDown = (e) => {
    if (positions.length < 2) return; // nothing to drag to
    e.preventDefault();
    e.currentTarget.setPointerCapture(e.pointerId);
    pointerStartRef.current = { x: e.clientX, y: e.clientY, t: Date.now() };
    setDragAngle(pointerToAngle(e));
  };

  const handlePointerMove = (e) => {
    if (dragAngle == null) return;
    setDragAngle(pointerToAngle(e));
  };

  const handlePointerUp = (e) => {
    if (dragAngle == null) return;
    // Determine whether this was a tap (click) vs a drag.
    // Tap = small pointer movement + short duration.
    const start = pointerStartRef.current;
    const dx = start ? Math.abs(e.clientX - start.x) : 999;
    const dy = start ? Math.abs(e.clientY - start.y) : 999;
    const dt = start ? Date.now() - start.t : 9999;
    const isTap = dx < 6 && dy < 6 && dt < 400;
    pointerStartRef.current = null;
    setDragAngle(null); // release drag — CSS transition re-engages toward discrete
    try { e.currentTarget.releasePointerCapture(e.pointerId); } catch {}

    if (isTap) {
      // TAP BEHAVIOR: toggle between free and pro, ignoring trend.
      // If currently on trend/something else, snap to free first.
      const next = activeFuel === "free" ? "pro" : "free";
      if (next !== activeFuel) handleSelect(next);
      return;
    }

    // DRAG BEHAVIOR: snap to the nearest position based on drag angle.
    const targetIdx = angleToNearestIdx(dragAngle);
    const targetPos = positions[targetIdx];
    // Locked position: fire modal, don't switch fuel (snap-back is automatic
    // since we cleared dragAngle — tilt reverts to current activeFuel's idx).
    if (isLocked(targetPos)) {
      onLockedClick && onLockedClick();
      return;
    }
    if (targetPos !== activeFuel) handleSelect(targetPos);
  };

  // Layout constants for the SVG
  // Viewport: 480×220 (desktop), scales down on mobile
  // Joystick occupies left 140px, LCD panel right 320px
  const VB_W = 480;
  const VB_H = 220;
  const JOYSTICK_CX = 80;
  const JOYSTICK_BASE_Y = 160;
  const SCREEN_AREA_X = 160;
  const SCREEN_AREA_W = 300;
  const SCREEN_COUNT = positions.length;
  const SCREEN_GAP = 12;
  const SCREEN_W = (SCREEN_AREA_W - SCREEN_GAP * (SCREEN_COUNT - 1)) / SCREEN_COUNT;
  const SCREEN_H = 120;
  const SCREEN_Y = 50;

  // Responsive sizing: cap at 480 on desktop, fill width on mobile
  const displayWidth = isMobile ? Math.min(360, typeof window !== "undefined" ? window.innerWidth - 40 : 320) : 480;

  return (
    <>
      <style>{`
        @keyframes lcdFlicker {
          0%, 100% { opacity: 1; }
          48%      { opacity: 0.94; }
          49%      { opacity: 1; }
        }
        @keyframes lcdScan {
          from { transform: translateY(-100%); }
          to   { transform: translateY(200%); }
        }
      `}</style>
      {/* ── GOING TREND TRANSITION — deep cosmic VFX ──────────────────
          Replaces the previous tire-smoke effect. Full interstellar VFX
          composition (gravitational well, wormhole pulses, shockwave,
          speed lines, chromatic aberration, warp-speed streaks, nebulas,
          scan bar) plays for the full 1.8s transition duration. ───── */}
      {transitioning && (
        <div style={{
          position: "fixed", inset: 0, zIndex: 10000, pointerEvents: "none",
          background: "#02010A",
          animation: "trendCosmicFade 3.2s ease-out forwards",
          overflow: "hidden",
        }}>
          <style>{`
            @keyframes trendCosmicFade {
              0%   { opacity: 0; }
              10%  { opacity: 1; }
              85%  { opacity: 1; }
              100% { opacity: 0; }
            }
            @keyframes trendTitleZoom {
              0%   { transform: translate(-50%, -50%) scale(0.3); opacity: 0; filter: blur(20px); }
              25%  { opacity: 1; filter: blur(0); }
              75%  { opacity: 1; filter: blur(0); }
              100% { transform: translate(-50%, -50%) scale(1.18); opacity: 0; filter: blur(10px); }
            }
          `}</style>
          {/* Deep cosmic scene fills the fixed-position container */}
          <CosmicVFX intensity="deep" active={transitioning} wipeOriginX="50%" wipeOriginY="50%" />
          {/* Title on top of the VFX */}
          <div style={{
            position: "absolute", top: "50%", left: "50%",
            transform: "translate(-50%, -50%)",
            fontSize: "clamp(40px, 7vw, 88px)",
            fontFamily: T.font_display, fontStyle: "italic",
            color: "#FFD700",
            textShadow: `
              0 0 20px #FFD70099,
              0 0 48px #FFD70055,
              0 0 96px #FF6B9988,
              0 4px 20px rgba(0,0,0,0.95)
            `,
            letterSpacing: "-0.02em",
            fontWeight: 900,
            zIndex: 2,
            animation: "trendTitleZoom 3.2s cubic-bezier(0.25, 0.1, 0.25, 1) forwards",
            whiteSpace: "nowrap",
          }}>
            ⭐ Going Trend
          </div>
        </div>
      )}

      {/* Joystick + LCD panel */}
      <div style={{
        display: "flex", flexDirection: "column", alignItems: "center", gap: T.s2,
        padding: `${T.s3}px 0`,
      }}>
        <svg
          ref={svgRef}
         
          viewBox={`0 0 ${VB_W} ${VB_H}`}
          width={displayWidth}
          style={{ display: "block", maxWidth: "100%", touchAction: "none" }}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
          onPointerCancel={handlePointerUp}
        >
          <defs>
            {/* Base plate gradient — metallic grey */}
            <linearGradient id="joyBase" x1="0%" y1="0%" x2="0%" y2="100%">
              <stop offset="0%" stopColor="#3a3a42" />
              <stop offset="40%" stopColor="#28282e" />
              <stop offset="100%" stopColor="#18181c" />
            </linearGradient>
            {/* Ball top — glossy red */}
            <radialGradient id="joyBall" cx="35%" cy="30%">
              <stop offset="0%" stopColor="#ff6b6b" />
              <stop offset="30%" stopColor="#e63333" />
              <stop offset="75%" stopColor="#a01717" />
              <stop offset="100%" stopColor="#550a0a" />
            </radialGradient>
            {/* Shaft — chromed metal */}
            <linearGradient id="joyShaft" x1="0%" y1="0%" x2="100%" y2="0%">
              <stop offset="0%" stopColor="#1a1a1e" />
              <stop offset="30%" stopColor="#5c5c64" />
              <stop offset="55%" stopColor="#a8a8b0" />
              <stop offset="75%" stopColor="#5c5c64" />
              <stop offset="100%" stopColor="#1a1a1e" />
            </linearGradient>
            {/* Rubber collar/boot at base of shaft */}
            <radialGradient id="joyBoot" cx="50%" cy="40%">
              <stop offset="0%" stopColor="#2a2a30" />
              <stop offset="100%" stopColor="#0a0a0c" />
            </radialGradient>
            {/* LCD screen bezel — dark plastic with subtle highlight */}
            <linearGradient id="lcdBezel" x1="0%" y1="0%" x2="0%" y2="100%">
              <stop offset="0%" stopColor="#2a2a2e" />
              <stop offset="50%" stopColor="#151518" />
              <stop offset="100%" stopColor="#08080a" />
            </linearGradient>
            {/* LCD inner screen — dark green phosphor default */}
            <linearGradient id="lcdScreenIdle" x1="0%" y1="0%" x2="0%" y2="100%">
              <stop offset="0%" stopColor="#0a1a0e" />
              <stop offset="100%" stopColor="#050d08" />
            </linearGradient>
            {/* Drop shadow for components */}
            <filter id="joyShadow" x="-20%" y="-20%" width="140%" height="140%">
              <feGaussianBlur in="SourceAlpha" stdDeviation="3" />
              <feOffset dx="0" dy="4" result="offsetblur" />
              <feComponentTransfer><feFuncA type="linear" slope="0.5" /></feComponentTransfer>
              <feMerge><feMergeNode /><feMergeNode in="SourceGraphic" /></feMerge>
            </filter>
            {/* Subtle inner shadow for LCD recessed look */}
            <filter id="lcdRecess" x="0%" y="0%" width="100%" height="100%">
              <feGaussianBlur in="SourceAlpha" stdDeviation="2" result="blur" />
              <feOffset in="blur" dx="0" dy="2" result="offsetBlur" />
              <feFlood floodColor="#000" floodOpacity="0.6" result="flood" />
              <feComposite in="flood" in2="offsetBlur" operator="in" result="shadow" />
              <feComposite in="shadow" in2="SourceGraphic" operator="over" />
            </filter>
          </defs>

          {/* ============ UNIFIED CONTROLLER BODY — one big base plate tying everything together ============ */}
          <rect x="10" y="30" width={VB_W - 20} height={VB_H - 50}
            rx="14" fill="url(#joyBase)" stroke="#000" strokeWidth="1"
            filter="url(#joyShadow)" />

          {/* Body highlight line along the top for depth */}
          <rect x="14" y="34" width={VB_W - 28} height="1.5"
            fill="rgba(255,255,255,0.08)" rx="1" />

          {/* Mounting screws on corners */}
          {[[24, 42], [VB_W - 24, 42], [24, VB_H - 32], [VB_W - 24, VB_H - 32]].map(([x, y], i) => (
            <g key={`screw-${i}`}>
              <circle cx={x} cy={y} r={4} fill="#555" stroke="#1a1a1e" strokeWidth="0.5" />
              <circle cx={x} cy={y} r={3} fill="url(#joyBase)" />
              <line x1={x - 2} y1={y} x2={x + 2} y2={y} stroke="#0a0a0c" strokeWidth="0.8" />
            </g>
          ))}

          {/* ============ LCD SCREENS (right side) ============ */}
          {positions.map((pos, i) => {
            const x = SCREEN_AREA_X + i * (SCREEN_W + SCREEN_GAP);
            const isActive = pos === activeFuel;
            const isHovered = hoverPos === pos;
            const locked = isLocked(pos);
            const color = FUEL_TYPES[pos].color;
            const label = pos.toUpperCase();
            const fuelCount = fuels[pos];
            const fuelText = Number.isFinite(fuelCount) ? String(fuelCount) : "∞";

            return (
              <g key={pos}
                style={{ cursor: "pointer", opacity: locked ? 0.55 : 1 }}
                onClick={() => {
                  // Play button sound only when the LCD tile is clicked
                  // (screen click), not during drag/tap on the joystick
                  // handle itself. Skip if clicking the active tile or
                  // a locked one (no state change anyway).
                  if (pos !== activeFuel && !isLocked(pos)) {
                    playFuelButtonSound();
                  }
                  handleSelect(pos);
                }}
                onMouseEnter={() => setHoverPos(pos)}
                onMouseLeave={() => setHoverPos(null)}
              >
                {/* Bezel/frame */}
                <rect x={x} y={SCREEN_Y} width={SCREEN_W} height={SCREEN_H}
                  rx="6" fill="url(#lcdBezel)" stroke="#000" strokeWidth="1.5" />

                {/* Recessed inner area — the actual "screen" */}
                <rect x={x + 6} y={SCREEN_Y + 6} width={SCREEN_W - 12} height={SCREEN_H - 12}
                  rx="3"
                  fill={isActive
                    ? `url(#lcdScreenActive-${pos})`
                    : "url(#lcdScreenIdle)"}
                  style={{
                    filter: "drop-shadow(inset 0 2px 4px rgba(0,0,0,0.8))",
                    animation: isActive ? "lcdFlicker 3s infinite" : "none",
                  }}
                />

                {/* Active-state screen gradient overlay */}
                <defs>
                  <linearGradient id={`lcdScreenActive-${pos}`} x1="0%" y1="0%" x2="0%" y2="100%">
                    <stop offset="0%" stopColor={color} stopOpacity="0.18" />
                    <stop offset="60%" stopColor={color} stopOpacity="0.05" />
                    <stop offset="100%" stopColor="#000" stopOpacity="0.4" />
                  </linearGradient>
                </defs>

                {/* Scanline overlay (subtle horizontal lines) */}
                <g clipPath={`url(#lcdClip-${pos})`}>
                  <clipPath id={`lcdClip-${pos}`}>
                    <rect x={x + 6} y={SCREEN_Y + 6} width={SCREEN_W - 12} height={SCREEN_H - 12} rx="3" />
                  </clipPath>
                  {Array.from({ length: Math.floor((SCREEN_H - 12) / 3) }).map((_, idx) => (
                    <line key={idx}
                      x1={x + 6} x2={x + SCREEN_W - 6}
                      y1={SCREEN_Y + 6 + idx * 3} y2={SCREEN_Y + 6 + idx * 3}
                      stroke="rgba(0,0,0,0.25)" strokeWidth="1"
                    />
                  ))}
                </g>

                {/* Status dot indicator (top-left of screen) */}
                <circle cx={x + 14} cy={SCREEN_Y + 16} r="3"
                  fill={isActive ? color : "#1a3a20"}
                  style={{
                    filter: isActive ? `drop-shadow(0 0 4px ${color})` : "none",
                  }} />
                <text x={x + 22} y={SCREEN_Y + 20}
                  fontSize="8" fontFamily="monospace" fontWeight="700"
                  fill={isActive ? color : "#2a5a35"}
                  letterSpacing="0.15em">
                  {isActive ? "ON" : "STBY"}
                </text>

                {/* BIG label — the fuel type name */}
                <text x={x + SCREEN_W / 2} y={SCREEN_Y + SCREEN_H / 2 + 4}
                  textAnchor="middle"
                  fontSize="22" fontFamily="monospace" fontWeight="900"
                  fill={isActive ? color : "#2a5a35"}
                  letterSpacing="0.12em"
                  style={{
                    filter: isActive ? `drop-shadow(0 0 6px ${color}aa)` : "none",
                  }}>
                  {label}
                </text>

                {/* Credit count — small retro readout at bottom */}
                <text x={x + SCREEN_W / 2} y={SCREEN_Y + SCREEN_H - 18}
                  textAnchor="middle"
                  fontSize="10" fontFamily="monospace" fontWeight="700"
                  fill={isActive ? color : "#1a3a20"}
                  letterSpacing="0.1em"
                  opacity={isActive ? 0.95 : 0.5}>
                  ▸ {fuelText}
                </text>

                {/* Lock overlay — small padlock centered when VIP-only */}
                {locked && (
                  <g>
                    {/* Semi-transparent backdrop so the label stays readable behind */}
                    <rect x={x + 6} y={SCREEN_Y + 6} width={SCREEN_W - 12} height={SCREEN_H - 12}
                      rx="3" fill="rgba(0,0,0,0.38)" />
                    {/* Padlock SVG — simple, purple VIP accent */}
                    <g transform={`translate(${x + SCREEN_W / 2 - 9}, ${SCREEN_Y + SCREEN_H / 2 - 11})`}>
                      {/* Shackle (arc above body) */}
                      <path d="M 4 9 L 4 5.5 A 5 5 0 0 1 14 5.5 L 14 9"
                        fill="none" stroke="#FFD700" strokeWidth="2" strokeLinecap="round" />
                      {/* Body */}
                      <rect x="1" y="9" width="16" height="13" rx="2"
                        fill="#FFD700" stroke="#9B7ED8" strokeWidth="0.6" />
                      {/* Keyhole */}
                      <circle cx="9" cy="14.5" r="1.5" fill="#1a1025" />
                      <rect x="8.4" y="14.5" width="1.2" height="3.5" fill="#1a1025" />
                    </g>
                  </g>
                )}

                {/* Hover/active border highlight */}
                <rect x={x + 1} y={SCREEN_Y + 1} width={SCREEN_W - 2} height={SCREEN_H - 2}
                  rx="5" fill="none"
                  stroke={isActive ? color : (isHovered ? "#666" : "transparent")}
                  strokeWidth={isActive ? "1.5" : "1"}
                  style={{
                    filter: isActive ? `drop-shadow(0 0 6px ${color}aa)` : "none",
                    transition: "stroke 160ms ease-out",
                  }} />
              </g>
            );
          })}

          {/* ============ JOYSTICK (left side) ============ */}
          {/* Rubber boot/collar at shaft base */}
          <ellipse cx={JOYSTICK_CX} cy={JOYSTICK_BASE_Y - 8}
            rx="22" ry="9" fill="url(#joyBoot)" stroke="#000" strokeWidth="0.5" />

          {/* Tilting shaft group */}
          <g transform={`rotate(${tiltAngle}, ${JOYSTICK_CX}, ${JOYSTICK_BASE_Y - 8})`}
            onPointerDown={handlePointerDown}
            style={{
              transition: dragAngle != null ? "none" : "transform 320ms cubic-bezier(0.34, 1.56, 0.64, 1)",
              cursor: positions.length < 2 ? "default" : (dragAngle != null ? "grabbing" : "grab"),
            }}>
            {/* Shaft */}
            <rect
              x={JOYSTICK_CX - 5} y={JOYSTICK_BASE_Y - 85}
              width="10" height="78" rx="2.5"
              fill="url(#joyShaft)"
              stroke="#000" strokeWidth="0.5"
            />
            {/* Shaft ridges for grip */}
            {[0, 1, 2].map(i => (
              <rect key={i}
                x={JOYSTICK_CX - 5} y={JOYSTICK_BASE_Y - 55 + i * 8}
                width="10" height="1.5"
                fill="rgba(0,0,0,0.35)" />
            ))}
            {/* Ball top with shadow */}
            <circle cx={JOYSTICK_CX} cy={JOYSTICK_BASE_Y - 92}
              r="22" fill="url(#joyBall)"
              stroke="#2a0808" strokeWidth="0.8"
              filter="url(#joyShadow)" />
            {/* Ball highlight */}
            <ellipse cx={JOYSTICK_CX - 7} cy={JOYSTICK_BASE_Y - 100}
              rx="7" ry="4" fill="rgba(255,255,255,0.4)" />
            {/* Secondary smaller highlight */}
            <ellipse cx={JOYSTICK_CX - 10} cy={JOYSTICK_BASE_Y - 103}
              rx="2.5" ry="1.5" fill="rgba(255,255,255,0.7)" />
          </g>

          {/* Position reference marks around the base */}
          {positions.map((pos, i) => {
            const angle = positions.length === 3
              ? (i - 1) * 22
              : positions.length === 2
                ? (i * 2 - 1) * 18
                : 0;
            const rad = (angle - 90) * Math.PI / 180;
            const markR = 30;
            const mx = JOYSTICK_CX + Math.cos(rad) * markR;
            const my = JOYSTICK_BASE_Y - 8 + Math.sin(rad) * markR;
            const isActive = pos === activeFuel;
            const color = FUEL_TYPES[pos].color;
            return (
              <circle key={`mark-${pos}`}
                cx={mx} cy={my} r={isActive ? 2.5 : 1.5}
                fill={isActive ? color : "#444"}
                style={{
                  filter: isActive ? `drop-shadow(0 0 3px ${color})` : "none",
                  transition: "all 220ms ease-out",
                }} />
            );
          })}

          {/* Brand plate under joystick */}
          <text x={JOYSTICK_CX} y={VB_H - 36}
            textAnchor="middle"
            fontSize="9" fontFamily="monospace" fontWeight="700"
            fill="#555" letterSpacing="0.25em">
            HIT-CTRL
          </text>
          <text x={JOYSTICK_CX} y={VB_H - 25}
            textAnchor="middle"
            fontSize="6" fontFamily="monospace"
            fill="#333" letterSpacing="0.2em">
            MODEL-88
          </text>
        </svg>

        {/* Active fuel label under the controller */}
        <div style={{
          fontSize: 11, fontFamily: T.font_mono,
          color: FUEL_TYPES[activeFuel].color,
          textShadow: `0 0 6px ${FUEL_TYPES[activeFuel].color}66`,
          letterSpacing: "0.2em", fontWeight: 700,
        }}>
          ▸ {FUEL_TYPES[activeFuel].label.toUpperCase()}
        </div>
      </div>
    </>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// SHOP PAGE — demo shop for purchasing tier upgrades with fake credits
// ════════════════════════════════════════════════════════════════════════════

// ════════════════════════════════════════════════════════════════════════════
// GENRE SLOT PICKER — CRT VARIANT
// ════════════════════════════════════════════════════════════════════════════
// CRT/hacker-terminal variant of GenreSlotPicker, purpose-built for the
// SunoMasterConsole inside BubbleTools. Same data model as the consumer
// picker (GENRE_TREE navigation → {genre, sub, micro} slot output), but
// styled entirely in the green-terminal palette so it composes with the
// surrounding hacker console without visual dissonance.
//
// Design choices that differ from the consumer picker:
//   - No tier-locking UI (admin-only by definition of where it renders)
//   - No empty-state upsell CTA (admin always has all slots)
//   - Terminal-style path label at the top of the drawer
//     ("~/genres/hip-hop/trap") reflecting the current navigation depth
//   - Monospace everywhere, letter-spaced uppercase for headers
//   - Instant-commit on selection (same as consumer)
//   - Per-slot lock toggle retained for Turn-3 integration (lock buttons
//     render but their handler is a no-op in Turn 1 — plumbing is ready
//     when we want to wire it up for re-roll protection)
//
// Props:
//   slots           — array of {genre, sub, micro} or null, length=3
//   onChange        — (newSlots) => void
//   slotLocks       — optional boolean[] per slot (reserved, Turn 3)
//   onToggleSlotLock— optional (idx) => void (reserved, Turn 3)
// ════════════════════════════════════════════════════════════════════════════

function GenreSlotPickerCRT({ slots, onChange, slotLocks, onToggleSlotLock }) {
  const { layout } = useLayout();
  const isMobile = layout === "mobile";
  const [activeSlot, setActiveSlot] = useState(null);
  const [activeCat, setActiveCat] = useState(null);
  const [activeGenre, setActiveGenre] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");

  // Local palette tokens — match SunoMasterConsole so the picker feels
  // native to the console frame. Defined once, reused everywhere below.
  const GREEN = "#00FF41";
  const GREEN_HI = "#66FF88";
  const GREEN_DIM = "rgba(0, 255, 65, 0.55)";
  const GREEN_MUTE = "rgba(0, 255, 65, 0.32)";
  const GREEN_FAINT = "rgba(0, 255, 65, 0.15)";
  const GREEN_BG = "rgba(0, 255, 65, 0.04)";
  const BLACK = "#050805";
  const BLACK_RAISED = "#0A1008";
  const MAX_SLOTS = 3;

  const q = searchQuery.trim().toLowerCase();
  const matches = (s) => !q || s.toLowerCase().includes(q);

  const openSlot = (idx) => {
    setActiveSlot(idx);
    const ex = slots[idx];
    if (ex) {
      // Resolve existing {genre, sub, micro} selection back into category
      // + genre so opening a filled slot lands the drawer in the right place.
      const cat = Object.keys(GENRE_TREE).find(c => Object.keys(GENRE_TREE[c]).includes(ex.genre));
      setActiveCat(cat || null);
      setActiveGenre(ex.genre);
    } else {
      setActiveCat(null);
      setActiveGenre(null);
    }
    setSearchQuery("");
  };
  const closeSlot = () => {
    setActiveSlot(null);
    setActiveCat(null);
    setActiveGenre(null);
    setSearchQuery("");
  };

  // Instant commit — any picker action immediately mutates the slot
  // structure upstream via onChange. No "apply" button. Keeps the UX tight.
  const commitSlot = (mainCat, subGenre, micro) => {
    const next = [...slots];
    if (subGenre) {
      next[activeSlot] = { genre: subGenre, sub: micro || null, micro: null };
    } else if (mainCat) {
      next[activeSlot] = { genre: mainCat, sub: null, micro: null };
    } else {
      next[activeSlot] = null;
    }
    onChange(next);
  };

  const clearSlot = (idx) => {
    const next = [...slots];
    next[idx] = null;
    onChange(next);
  };

  // Render a single slot card. Extracted so the three-card row stays
  // legible in the main JSX. Uses active/filled/empty states to pick
  // the right visual treatment.
  const renderSlotCard = (i) => {
    const slot = slots[i];
    const isActive = activeSlot === i;
    const isLocked = slotLocks?.[i];
    const hasContent = !!slot;

    // Stacked display: slot number → genre (top) → sub (mid) → micro (bottom).
    // Empty slot shows a dimmed "+ EMPTY" prompt so the card is tappable.
    return (
      <div key={i} style={{
        position: "relative",
        padding: "10px 12px",
        minHeight: 82,
        background: hasContent ? "rgba(0, 255, 65, 0.05)" : "rgba(0, 255, 65, 0.015)",
        border: `1px solid ${isLocked ? "#FFD700" : isActive ? GREEN : hasContent ? GREEN_DIM : GREEN_FAINT}`,
        borderRadius: 3,
        cursor: "pointer",
        transition: `all 150ms ease`,
        boxShadow: isLocked
          ? `0 0 0 1px #FFD70055, 0 0 10px #FFD70033`
          : isActive
          ? `0 0 0 1px ${GREEN}33, 0 0 10px ${GREEN_DIM}`
          : "none",
      }}
      onClick={() => { playSwitchSound(); isActive ? closeSlot() : openSlot(i); }}
      onMouseEnter={e => {
        if (!isActive && !isLocked) e.currentTarget.style.borderColor = GREEN_DIM;
      }}
      onMouseLeave={e => {
        if (!isActive && !isLocked) {
          e.currentTarget.style.borderColor = hasContent ? GREEN_DIM : GREEN_FAINT;
        }
      }}
      >
        {/* Header row: slot number + action buttons (lock / clear) */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          marginBottom: 6,
        }}>
          <span style={{
            fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
            letterSpacing: "0.22em",
            color: isLocked ? "#FFD700" : hasContent ? GREEN : GREEN_MUTE,
          }}>
            ▸ SLOT_{i + 1}{isLocked ? " · LOCKED" : ""}
          </span>
          <div style={{ display: "flex", gap: 4 }}>
            {/* Clear button — visible only when slot has content */}
            {hasContent && (
              <button type="button"
                onClick={e => { e.stopPropagation(); playSwitchSound(); clearSlot(i); }}
                title="Clear this slot"
                style={{
                  padding: "1px 6px",
                  background: "transparent",
                  border: `1px solid ${GREEN_FAINT}`,
                  borderRadius: 2,
                  color: GREEN_MUTE,
                  fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
                  letterSpacing: "0.1em",
                  cursor: "pointer",
                  lineHeight: 1.2,
                }}
              >✕</button>
            )}
            {/* Lock toggle — wired to upstream handler if provided,
                otherwise a visual no-op placeholder for Turn 3. */}
            <button type="button"
              onClick={e => { e.stopPropagation(); playSwitchSound(); onToggleSlotLock?.(i); }}
              title={isLocked ? "Unlock slot" : "Lock slot against re-roll"}
              style={{
                padding: "1px 6px",
                background: isLocked ? "rgba(255, 215, 0, 0.12)" : "transparent",
                border: `1px solid ${isLocked ? "#FFD700" : GREEN_FAINT}`,
                borderRadius: 2,
                color: isLocked ? "#FFD700" : GREEN_MUTE,
                fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
                letterSpacing: "0.1em",
                cursor: "pointer",
                lineHeight: 1.2,
              }}
            >{isLocked ? "🔒" : "🔓"}</button>
          </div>
        </div>

        {/* Slot content body */}
        {hasContent ? (
          <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
            <span style={{
              fontFamily: T.font_mono, fontSize: 12, fontWeight: 700,
              color: GREEN_HI, lineHeight: 1.3,
              textShadow: `0 0 6px ${GREEN_MUTE}`,
            }}>{slot.genre}</span>
            {slot.sub && (
              <span style={{
                fontFamily: T.font_mono, fontSize: 10, fontWeight: 500,
                color: GREEN_DIM, lineHeight: 1.3,
              }}>› {slot.sub}</span>
            )}
            {slot.micro && (
              <span style={{
                fontFamily: T.font_mono, fontSize: 9, fontWeight: 400,
                color: GREEN_MUTE, lineHeight: 1.3, fontStyle: "italic",
              }}>  · {slot.micro}</span>
            )}
          </div>
        ) : (
          <div style={{
            fontFamily: T.font_mono, fontSize: 10, fontWeight: 500,
            color: GREEN_MUTE, letterSpacing: "0.08em",
          }}>
            + CLICK_TO_ASSIGN
          </div>
        )}
      </div>
    );
  };

  // ── DRAWER CONTENT — helper renderers for each depth ──

  // Category grid (top-level of GENRE_TREE). Shows all main categories
  // when no category is active. Each one a tappable terminal chip.
  const renderCategoryGrid = () => (
    <div style={{
      display: "grid",
      gridTemplateColumns: `repeat(${isMobile ? 2 : 4}, 1fr)`,
      gap: 6,
      // Scroll cap — if more categories get added later they won't
      // balloon the drawer past the viewport. Generous cap since
      // categories are the top of the tree. Matches the consumer
      // Engine picker's behavior so mental model is the same.
      maxHeight: isMobile ? "32vh" : "30vh",
      overflowY: "auto",
      paddingRight: 4,
    }}>
      {Object.keys(GENRE_TREE).filter(matches).map(cat => (
        <button key={cat} type="button"
          onClick={() => { playSwitchSound(); setActiveCat(cat); setSearchQuery(""); }}
          style={{
            padding: "9px 11px",
            background: "transparent",
            border: `1px solid ${GREEN_FAINT}`,
            borderRadius: 3,
            color: GREEN,
            fontFamily: T.font_mono, fontSize: 11, fontWeight: 600,
            letterSpacing: "0.03em",
            cursor: "pointer",
            textAlign: "left",
            transition: "all 150ms ease",
          }}
          onMouseEnter={e => {
            e.currentTarget.style.borderColor = GREEN;
            e.currentTarget.style.background = "rgba(0, 255, 65, 0.06)";
          }}
          onMouseLeave={e => {
            e.currentTarget.style.borderColor = GREEN_FAINT;
            e.currentTarget.style.background = "transparent";
          }}
        >{cat}</button>
      ))}
    </div>
  );

  // Subgenre grid — rendered once a category is active. Include a
  // "commit just the category" button at top so users can pick a broad
  // genre without drilling deeper. Each subgenre is also tappable to
  // commit, OR to drill into its microstyles.
  const renderSubgenreGrid = () => {
    if (!activeCat) return null;
    const subs = Object.keys(GENRE_TREE[activeCat]).filter(matches);
    return (
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {/* Category-level commit button */}
        <button type="button"
          onClick={() => { playSwitchSound(); commitSlot(activeCat, null, null); closeSlot(); }}
          style={{
            padding: "8px 11px",
            background: "rgba(0, 255, 65, 0.10)",
            border: `1px dashed ${GREEN}`,
            borderRadius: 3,
            color: GREEN_HI,
            fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
            letterSpacing: "0.15em",
            cursor: "pointer",
            textAlign: "left",
            textShadow: `0 0 6px ${GREEN_MUTE}`,
          }}
        >◂ COMMIT AS ‹{activeCat.toUpperCase()}› (NO SUBGENRE)</button>

        {/* Subgenre grid */}
        <div style={{
          display: "grid",
          gridTemplateColumns: `repeat(${isMobile ? 2 : 3}, 1fr)`,
          gap: 6,
          // Scroll cap — Hebrew / Electronic / World categories have
          // 40+ subgenres and would balloon the drawer past the
          // viewport, cutting off bottom chips. Caps at ~44vh with
          // internal scroll so all chips are reachable.
          maxHeight: isMobile ? "38vh" : "44vh",
          overflowY: "auto",
          paddingRight: 4,
        }}>
          {subs.map(sub => (
            <button key={sub} type="button"
              onClick={() => { playSwitchSound(); setActiveGenre(sub); setSearchQuery(""); }}
              style={{
                padding: "8px 10px",
                background: activeGenre === sub ? "rgba(0, 255, 65, 0.08)" : "transparent",
                border: `1px solid ${activeGenre === sub ? GREEN : GREEN_FAINT}`,
                borderRadius: 3,
                color: activeGenre === sub ? GREEN_HI : GREEN,
                fontFamily: T.font_mono, fontSize: 10, fontWeight: 600,
                letterSpacing: "0.02em",
                cursor: "pointer",
                textAlign: "left",
                transition: "all 150ms ease",
              }}
              onMouseEnter={e => {
                if (activeGenre !== sub) e.currentTarget.style.borderColor = GREEN_DIM;
              }}
              onMouseLeave={e => {
                if (activeGenre !== sub) e.currentTarget.style.borderColor = GREEN_FAINT;
              }}
            >{sub}</button>
          ))}
        </div>
      </div>
    );
  };

  // Microstyle grid — rendered once both category + subgenre are active.
  // Show a "commit without microstyle" button at top for cleaner commits.
  const renderMicroGrid = () => {
    if (!activeCat || !activeGenre) return null;
    const micros = (GENRE_TREE[activeCat][activeGenre] || []).filter(matches);
    return (
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {/* Subgenre-level commit button */}
        <button type="button"
          onClick={() => { playSwitchSound(); commitSlot(activeCat, activeGenre, null); closeSlot(); }}
          style={{
            padding: "8px 11px",
            background: "rgba(0, 255, 65, 0.10)",
            border: `1px dashed ${GREEN}`,
            borderRadius: 3,
            color: GREEN_HI,
            fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
            letterSpacing: "0.15em",
            cursor: "pointer",
            textAlign: "left",
            textShadow: `0 0 6px ${GREEN_MUTE}`,
          }}
        >◂ COMMIT AS ‹{activeGenre.toUpperCase()}› (NO MICROSTYLE)</button>

        {/* Microstyle grid */}
        <div style={{
          display: "grid",
          gridTemplateColumns: `repeat(${isMobile ? 2 : 3}, 1fr)`,
          gap: 6,
          // Same scroll cap pattern as subgenre grid. Some subgenres
          // (Trap, House, Hebrew Mizrahi) have 20+ microstyles.
          maxHeight: isMobile ? "32vh" : "36vh",
          overflowY: "auto",
          paddingRight: 4,
        }}>
          {micros.map(micro => (
            <button key={micro} type="button"
              onClick={() => { playSwitchSound(); commitSlot(activeCat, activeGenre, micro); closeSlot(); }}
              style={{
                padding: "8px 10px",
                background: "transparent",
                border: `1px solid ${GREEN_FAINT}`,
                borderRadius: 3,
                color: GREEN_DIM,
                fontFamily: T.font_mono, fontSize: 10, fontWeight: 500,
                letterSpacing: "0.02em",
                cursor: "pointer",
                textAlign: "left",
                fontStyle: "italic",
                transition: "all 150ms ease",
              }}
              onMouseEnter={e => {
                e.currentTarget.style.borderColor = GREEN;
                e.currentTarget.style.background = "rgba(0, 255, 65, 0.06)";
                e.currentTarget.style.color = GREEN_HI;
              }}
              onMouseLeave={e => {
                e.currentTarget.style.borderColor = GREEN_FAINT;
                e.currentTarget.style.background = "transparent";
                e.currentTarget.style.color = GREEN_DIM;
              }}
            >· {micro}</button>
          ))}
        </div>
      </div>
    );
  };

  // Search results — when the user types, flatten GENRE_TREE to subgenre
  // and microstyle hits, sort alphabetically, and surface them as
  // one-click commit chips. Short-circuits the category navigation.
  const renderSearchResults = () => {
    const subHits = [];
    const microHits = [];
    Object.keys(GENRE_TREE).forEach(cat => {
      const subs = GENRE_TREE[cat];
      Object.keys(subs).forEach(sub => {
        if (matches(sub)) subHits.push({ cat, sub });
        (subs[sub] || []).forEach(micro => {
          if (matches(micro)) microHits.push({ cat, sub, micro });
        });
      });
    });
    subHits.sort((a, b) => a.sub.localeCompare(b.sub));
    microHits.sort((a, b) => a.micro.localeCompare(b.micro));
    const MAX_SUB = 20;
    const MAX_MICRO = 14;
    const subVisible = subHits.slice(0, MAX_SUB);
    const microVisible = microHits.slice(0, MAX_MICRO);
    const total = subHits.length + microHits.length;

    if (total === 0) {
      return (
        <div style={{
          padding: "16px 12px", textAlign: "center",
          color: GREEN_DIM, fontFamily: T.font_mono, fontSize: 11,
          border: `1px dashed ${GREEN_FAINT}`,
          borderRadius: 3,
          letterSpacing: "0.05em",
        }}>
          &gt; no matches for "{searchQuery}"
        </div>
      );
    }
    return (
      <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
        {subVisible.length > 0 && (
          <div>
            <div style={{
              fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
              letterSpacing: "0.22em", color: GREEN_DIM,
              marginBottom: 6,
            }}>
              ▸ SUBGENRES ({subHits.length})
            </div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
              {subVisible.map(({ cat, sub }) => (
                <button key={`s-${cat}-${sub}`} type="button"
                  onClick={() => { playSwitchSound(); commitSlot(cat, sub, null); closeSlot(); }}
                  style={{
                    padding: "5px 10px",
                    background: "transparent",
                    border: `1px solid ${GREEN_FAINT}`,
                    borderRadius: 3,
                    color: GREEN,
                    fontFamily: T.font_mono, fontSize: 10, fontWeight: 600,
                    cursor: "pointer",
                    letterSpacing: "0.02em",
                  }}
                  onMouseEnter={e => { e.currentTarget.style.borderColor = GREEN; e.currentTarget.style.background = "rgba(0, 255, 65, 0.06)"; }}
                  onMouseLeave={e => { e.currentTarget.style.borderColor = GREEN_FAINT; e.currentTarget.style.background = "transparent"; }}
                >{sub}<span style={{ color: GREEN_MUTE, marginLeft: 5, fontSize: 8 }}>/{cat}</span></button>
              ))}
              {subHits.length > MAX_SUB && (
                <span style={{ color: GREEN_MUTE, fontFamily: T.font_mono, fontSize: 9, padding: "5px 6px" }}>
                  +{subHits.length - MAX_SUB} more
                </span>
              )}
            </div>
          </div>
        )}
        {microVisible.length > 0 && (
          <div>
            <div style={{
              fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
              letterSpacing: "0.22em", color: GREEN_DIM,
              marginBottom: 6,
            }}>
              ▸ MICROSTYLES ({microHits.length})
            </div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
              {microVisible.map(({ cat, sub, micro }) => (
                <button key={`m-${cat}-${sub}-${micro}`} type="button"
                  onClick={() => { playSwitchSound(); commitSlot(cat, sub, micro); closeSlot(); }}
                  style={{
                    padding: "5px 10px",
                    background: "transparent",
                    border: `1px dashed ${GREEN_FAINT}`,
                    borderRadius: 3,
                    color: GREEN_DIM,
                    fontFamily: T.font_mono, fontSize: 10, fontWeight: 500,
                    cursor: "pointer",
                    fontStyle: "italic",
                  }}
                  onMouseEnter={e => { e.currentTarget.style.borderColor = GREEN; e.currentTarget.style.color = GREEN_HI; }}
                  onMouseLeave={e => { e.currentTarget.style.borderColor = GREEN_FAINT; e.currentTarget.style.color = GREEN_DIM; }}
                >· {micro}<span style={{ color: GREEN_MUTE, marginLeft: 5, fontSize: 8 }}>/{sub}</span></button>
              ))}
              {microHits.length > MAX_MICRO && (
                <span style={{ color: GREEN_MUTE, fontFamily: T.font_mono, fontSize: 9, padding: "5px 6px" }}>
                  +{microHits.length - MAX_MICRO} more
                </span>
              )}
            </div>
          </div>
        )}
      </div>
    );
  };

  // Breadcrumb path — terminal-style string showing where the user is
  // in the tree. Refreshes the spatial sense of "what level am I at".
  const renderPath = () => {
    const parts = [`~`, `genres`];
    if (activeCat) parts.push(activeCat.toLowerCase().replace(/\s+/g, "-").replace("/", "-"));
    if (activeGenre) parts.push(activeGenre.toLowerCase().replace(/\s+/g, "-"));
    return parts.join("/");
  };

  return (
    <div>
      {/* ═══ SLOT CARDS ROW ═══ */}
      <div style={{
        display: "grid",
        gridTemplateColumns: isMobile ? "1fr" : `repeat(${MAX_SLOTS}, 1fr)`,
        gap: 8,
      }}>
        {Array.from({ length: MAX_SLOTS }).map((_, i) => renderSlotCard(i))}
      </div>

      {/* ═══ DRAWER — open when activeSlot is non-null ═══ */}
      {activeSlot !== null && (
        <div style={{
          marginTop: 10,
          padding: 14,
          // Cap drawer width on desktop — the CRT console renders
          // at full pane width (~580px inside SMC), and 580 for
          // chip navigation was too wide to scan. 520 tightens the
          // horizontal scan without hiding any chip text. Mobile
          // stays 100%.
          maxWidth: isMobile ? "100%" : 520,
          background: BLACK_RAISED,
          border: `1px solid ${GREEN_DIM}`,
          borderRadius: 4,
          boxShadow: `0 0 0 1px ${GREEN_FAINT}, 0 0 20px ${GREEN_FAINT}`,
        }}>
          {/* Drawer title bar: path + close button */}
          <div style={{
            display: "flex", alignItems: "center", gap: 8,
            marginBottom: 10,
            paddingBottom: 10,
            borderBottom: `1px dashed ${GREEN_FAINT}`,
          }}>
            <span style={{
              fontFamily: T.font_mono, fontSize: 10, color: GREEN,
              letterSpacing: "0.08em",
              textShadow: `0 0 4px ${GREEN_MUTE}`,
              flex: 1,
              overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
            }}>
              <span style={{ color: GREEN_MUTE }}>$</span> cd <span style={{ color: GREEN_HI }}>{renderPath()}</span>
              <span style={{
                display: "inline-block", width: 6, height: 11,
                background: GREEN, marginLeft: 3, verticalAlign: "-2px",
                animation: "smcCaretBlink 1s steps(1) infinite",
              }} />
            </span>
            {/* Back button — only show if user has drilled deeper than root */}
            {(activeCat || activeGenre) && (
              <button type="button"
                onClick={() => {
                  playSwitchSound();
                  if (activeGenre) setActiveGenre(null);
                  else if (activeCat) setActiveCat(null);
                }}
                style={{
                  padding: "3px 8px",
                  background: "transparent",
                  border: `1px solid ${GREEN_FAINT}`,
                  borderRadius: 2,
                  color: GREEN_DIM,
                  fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
                  letterSpacing: "0.1em",
                  cursor: "pointer",
                }}
              >◂ BACK</button>
            )}
            <button type="button"
              onClick={() => { playSwitchSound(); closeSlot(); }}
              style={{
                padding: "3px 8px",
                background: "transparent",
                border: `1px solid ${GREEN_FAINT}`,
                borderRadius: 2,
                color: GREEN_DIM,
                fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
                letterSpacing: "0.1em",
                cursor: "pointer",
              }}
            >CLOSE ✕</button>
          </div>

          {/* Search field */}
          <div style={{ marginBottom: 12, position: "relative" }}>
            <input type="text" value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              placeholder="// search genres + microstyles..."
              style={{
                width: "100%", boxSizing: "border-box",
                padding: isMobile ? "9px 36px 9px 12px" : "7px 36px 7px 12px",
                background: BLACK,
                border: `1px solid ${GREEN_FAINT}`,
                borderRadius: 3,
                color: GREEN,
                fontFamily: T.font_mono,
                fontSize: isMobile ? 16 : 12,
                fontWeight: 500,
                letterSpacing: "0.02em",
                outline: "none",
              }}
              onFocus={e => { e.currentTarget.style.borderColor = GREEN; }}
              onBlur={e => { e.currentTarget.style.borderColor = GREEN_FAINT; }}
            />
            {searchQuery && (
              <button type="button"
                onClick={() => { playSwitchSound(); setSearchQuery(""); }}
                style={{
                  position: "absolute", right: 8, top: "50%", transform: "translateY(-50%)",
                  width: 22, height: 22, display: "grid", placeItems: "center",
                  background: "transparent", border: "none", color: GREEN_DIM,
                  cursor: "pointer", fontSize: 12, lineHeight: 1,
                  borderRadius: 2,
                }}
              >✕</button>
            )}
          </div>

          {/* Body — depends on current navigation state */}
          {q
            ? renderSearchResults()
            : !activeCat
              ? renderCategoryGrid()
              : !activeGenre
                ? renderSubgenreGrid()
                : renderMicroGrid()}
        </div>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// SUNO MASTER CONSOLE — purpose-built producer workstation for Israeli scene
// ════════════════════════════════════════════════════════════════════════════
// Lives inside BubbleToolsPage only (admin-gated upstream). This is NOT a
// clone of EngineWorkspace — it's a different workflow built specifically
// for producers who take Suno AI output and finish it for Israeli artists:
//
//   1. Pick an Israeli artist from the roster (12 available)
//   2. Optionally expand a DNA panel that shows the artist's sonic
//      signature + producers + era notes pulled from ARTIST_VOCABULARY
//      when available, or fallback to pack-level descriptors
//   3. Configure a Suno prompt via terminal-skinned structured slots
//      — genre, mood, groove, BPM, key, texture, mix
//   4. Live-build a prompt preview on the right that updates as slots
//      commit. Copy → paste into Suno → done.
//
// Aesthetic: full CRT terminal. Scan lines, green glow, monospace
// everywhere, typing-cursor animations on drawers, ASCII dividers.
// High contrast readable because producers work long sessions.
//
// Data sources (already in the codebase, no new data):
//   - MIMIC_PACKS filtered to region === "israeli"
//   - ARTIST_VOCABULARY (getArtistVocabulary helper)
//   - MOODS, ENERGIES, GROOVES, HARMONIC_STYLES, SOUND_TEXTURES, MIX_CHARS
//   - GENRE_TREE for genre pickers (simplified single-slot)
// ════════════════════════════════════════════════════════════════════════════

function SunoMasterConsole() {
  const { layout } = useLayout();
  const isMobile = layout === "mobile";

  // Terminal palette — locally scoped so the component is self-contained
  const GREEN = "#00FF41";
  const GREEN_HI = "#66FF88";            // brighter accent for text focus
  const GREEN_DIM = "rgba(0, 255, 65, 0.55)";
  const GREEN_MUTE = "rgba(0, 255, 65, 0.32)";
  const GREEN_FAINT = "rgba(0, 255, 65, 0.15)";
  const GREEN_BG = "rgba(0, 255, 65, 0.04)";
  const BLACK = "#050805";
  const BLACK_RAISED = "#0A1008";

  // ── Artists: Israeli roster only ──
  const israeliArtists = useMemo(
    () => MIMIC_PACKS.filter(a => a.region === "israeli"),
    []
  );

  // ── State ──
  const [artistId, setArtistId] = useState(israeliArtists[0]?.artistId || null);
  const [dnaOpen, setDnaOpen] = useState(false);
  // Slot structure — mirrors consumer Engine: 3 slots, each either null
  // or { genre, sub, micro } from GENRE_TREE navigation. First slot is
  // the "primary" genre, subsequent slots layer/blend additional styles
  // into the Suno prompt. Seeded from active artist's first pack on
  // mount and whenever the artist changes.
  const [slots, setSlots] = useState([null, null, null]);
  // Per-slot locks — Turn 3 will wire these to a re-roll action. For
  // now they toggle independently and do nothing destructive. Exposed
  // via the picker's lock button; enables the gold-border treatment.
  const [slotLocks, setSlotLocks] = useState([false, false, false]);
  const [mood, setMood] = useState("Defiant");
  const [energy, setEnergy] = useState("Steady groove throughout");
  const [groove, setGroove] = useState("straight");
  const [texture, setTexture] = useState("Warm & analog");
  const [mix, setMix] = useState("Modern polished radio");
  const [harmonic, setHarmonic] = useState("Minor-key introspection");
  const [bpm, setBpm] = useState(96);
  // Turn 1 of the full-parity rebuild: consumer-Engine fields that were
  // missing from the original minimal console. All optional — "Any"
  // leaves them out of the generated prompt so Suno doesn't get over-
  // constrained. Each maps cleanly to a single catalog constant above.
  const [vocalist, setVocalist] = useState("Any");
  const [language, setLanguage] = useState("en");
  const [lyricalVibe, setLyricalVibe] = useState("Any");
  // Instrumental / Song switch — mirrors the consumer Engine's
  // LyricalSwitch. When true, Suno prompt includes a "with vocals"
  // framing; when false, an "instrumental, no vocals" explicit flag.
  const [lyricsOn, setLyricsOn] = useState(true);
  const [copied, setCopied] = useState(false);

  const activeArtist = israeliArtists.find(a => a.artistId === artistId) || israeliArtists[0];
  const vocab = activeArtist ? getArtistVocabulary(activeArtist.artistId) : null;

  // Reset DNA drawer when changing artist (otherwise data flashes stale)
  useEffect(() => { setDnaOpen(false); }, [artistId]);

  // Auto-suggest defaults when artist changes: pull the first pack's
  // state as a soft seed so new artists don't open empty. Now seeds
  // the full 3-slot genre tree selection plus all other controls.
  useEffect(() => {
    if (!activeArtist) return;
    const firstPack = activeArtist.packs[0];
    if (!firstPack || !firstPack.state) return;
    const s = firstPack.state;
    if (s.mood) setMood(s.mood);
    if (s.energy) setEnergy(s.energy);
    if (s.groove) setGroove(s.groove);
    if (s.texture) setTexture(s.texture);
    if (s.mix) setMix(s.mix);
    if (s.harmonic) setHarmonic(s.harmonic);
    if (typeof s.bpm === "number") setBpm(s.bpm);
    // Turn 1 full-parity seeds — vocalist / language / lyrical vibe
    // from the first-pack state. If the pack doesn't specify one we
    // leave the user's current selection untouched rather than
    // forcing "Any" (respect manual overrides across artist switches).
    if (s.vocalist) setVocalist(s.vocalist);
    if (s.language) setLanguage(s.language);
    if (s.lyricalVibe) setLyricalVibe(s.lyricalVibe);
    // Seed the full slot structure. Pack slots are already in
    // {genre, sub, micro} format — just copy the reference (pad/truncate
    // to exactly 3 entries so picker state shape is stable).
    if (Array.isArray(s.slots)) {
      const padded = [...s.slots];
      while (padded.length < 3) padded.push(null);
      setSlots(padded.slice(0, 3));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [artistId]);

  // ── Prompt preview build — structured format Suno accepts well ──
  // Genre line is now assembled from the slot structure: primary genre
  // from slot[0], blended secondaries from subsequent non-null slots.
  // Format examples:
  //   "Mediterranean pop (bouzouki pluck microstyle)"
  //   "Trap + Afrobeats blend"
  //   "Hip-Hop" (category-only commit)
  const genrePhrase = useMemo(() => {
    const filled = slots.filter(Boolean);
    if (filled.length === 0) return "genre unset";
    const rendered = filled.map(s => {
      if (s.sub) return s.micro ? `${s.sub} (${s.micro})` : s.sub;
      return s.genre;
    });
    if (rendered.length === 1) return rendered[0];
    return rendered.join(" + ");
  }, [slots]);

  const prompt = useMemo(() => {
    const parts = [];
    // Line 1: genre stack + mood + energy
    parts.push(`${genrePhrase}, ${mood} mood, ${energy}`);
    // Line 2: rhythmic feel + BPM
    parts.push(`${groove} groove at ${bpm} BPM`);
    // Line 3: harmonic + texture + mix
    parts.push(`${harmonic}, ${texture} texture, ${mix}`);
    // Line 4: vocal character + language + lyrical framing
    //   - skip the voice block entirely if instrumental
    //   - omit any field set to "Any" so the prompt isn't over-
    //     specified (Suno handles absence better than vague spec)
    if (!lyricsOn) {
      parts.push(`instrumental, no vocals`);
    } else {
      const voiceBits = [];
      if (vocalist && vocalist !== "Any") voiceBits.push(`${vocalist.toLowerCase()} vocal`);
      const langLabel = (LANGUAGES.find(l => l.code === language) || {}).label;
      if (langLabel && language !== "en") voiceBits.push(`${langLabel} lyrics`);
      if (lyricalVibe && lyricalVibe !== "Any") voiceBits.push(`${lyricalVibe.toLowerCase()} lyrical mode`);
      if (voiceBits.length) parts.push(voiceBits.join(", "));
    }
    // Line 5: DNA block — pulled from ARTIST_VOCABULARY when available
    if (vocab) {
      const vParts = [];
      if (Array.isArray(vocab.vocal) && vocab.vocal.length) vParts.push(vocab.vocal[0]);
      if (Array.isArray(vocab.production) && vocab.production.length) vParts.push(vocab.production[0]);
      if (Array.isArray(vocab.signature) && vocab.signature.length) vParts.push(vocab.signature[0]);
      if (vParts.length) parts.push(`[sonic DNA: ${vParts.join("; ")}]`);
    } else if (activeArtist) {
      parts.push(`[in the style of: ${activeArtist.artistName} pack palette]`);
    }
    return parts.join(". ");
  }, [genrePhrase, mood, energy, groove, bpm, harmonic, texture, mix, vocalist, language, lyricalVibe, lyricsOn, vocab, activeArtist]);

  const doCopy = async () => {
    try {
      await navigator.clipboard.writeText(prompt);
      setCopied(true);
      setTimeout(() => setCopied(false), 1600);
    } catch {}
  };

  // Catalog options pulled from the existing engine data so we stay
  // aligned with what the main prompt engine considers valid.
  const MOODS_OPTIONS = useMemo(() => (typeof MOODS !== "undefined" ? MOODS : [mood]), [mood]);
  const ENERGIES_OPTIONS = useMemo(() => (typeof ENERGIES !== "undefined" ? ENERGIES : [energy]), [energy]);
  const GROOVES_OPTIONS = useMemo(() => (typeof GROOVES !== "undefined" ? GROOVES.map(g => g.id) : [groove]), [groove]);
  const HARMONIC_OPTIONS = useMemo(() => (typeof HARMONIC_STYLES !== "undefined" ? HARMONIC_STYLES : [harmonic]), [harmonic]);
  const TEXTURE_OPTIONS = useMemo(() => (typeof SOUND_TEXTURES !== "undefined" ? SOUND_TEXTURES : [texture]), [texture]);
  const MIX_OPTIONS = useMemo(() => (typeof MIX_CHARS !== "undefined" ? MIX_CHARS : [mix]), [mix]);
  // Turn 1 parity additions. "Any" is injected as the first option so
  // the producer can explicitly leave a field unspecified. The prompt
  // builder respects "Any" by omitting the related line entirely rather
  // than writing "Any vocalist" into the prompt.
  const VOCALISTS_OPTIONS = useMemo(
    () => ["Any", ...(typeof VOCALISTS !== "undefined" ? VOCALISTS : [])],
    []
  );
  const LYRICAL_VIBES_OPTIONS = useMemo(
    () => ["Any", ...(typeof LYRICAL_VIBES !== "undefined" ? LYRICAL_VIBES : [])],
    []
  );
  // Languages are objects {code, label} — we render the label but
  // store the code so prompt logic / seeding stays stable across
  // translations.
  const LANGUAGES_OPTIONS = useMemo(
    () => (typeof LANGUAGES !== "undefined" ? LANGUAGES : [{ code: "en", label: "English" }]),
    []
  );

  // Genre list — pull top subgenre names from GENRE_TREE. Flat list of
  // subgenres across all Tier-A genres so the dropdown is useful without
  // overwhelming. Fallback if GENRE_TREE shape doesn't match expectation.
  const GENRE_OPTIONS = useMemo(() => {
    const out = new Set(["Mediterranean pop"]);
    try {
      if (typeof GENRE_TREE !== "undefined" && GENRE_TREE && typeof GENRE_TREE === "object") {
        Object.values(GENRE_TREE).forEach(cat => {
          if (cat && typeof cat === "object") {
            Object.keys(cat).forEach(sub => out.add(sub));
          }
        });
      }
    } catch {}
    return Array.from(out);
  }, []);

  // Reusable terminal slot — label + native select.
  const slot = (label, value, setter, options, note) => (
    <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
      <div style={{ display: "flex", alignItems: "baseline", gap: 6 }}>
        <span style={{
          fontSize: 9, fontWeight: 700, letterSpacing: "0.22em",
          color: GREEN_DIM, fontFamily: T.font_mono,
        }}>
          ▸ {label}
        </span>
        {note && (
          <span style={{
            fontSize: 9, color: GREEN_MUTE, fontFamily: T.font_mono,
            letterSpacing: "0.05em",
          }}>// {note}</span>
        )}
      </div>
      <select
        value={value}
        onChange={e => { playSwitchSound(); setter(e.target.value); }}
        style={{
          padding: isMobile ? "9px 12px" : "7px 10px",
          background: BLACK,
          border: `1px solid ${GREEN_FAINT}`,
          borderRadius: 3,
          color: GREEN,
          fontFamily: T.font_mono,
          fontSize: isMobile ? 16 : 12,
          fontWeight: 600,
          letterSpacing: "0.02em",
          outline: "none",
          cursor: "pointer",
          appearance: "none",
          WebkitAppearance: "none",
          backgroundImage: `linear-gradient(45deg, transparent 50%, ${GREEN_DIM} 50%), linear-gradient(135deg, ${GREEN_DIM} 50%, transparent 50%)`,
          backgroundPosition: `calc(100% - 14px) calc(50% - 2px), calc(100% - 9px) calc(50% - 2px)`,
          backgroundSize: "5px 5px, 5px 5px",
          backgroundRepeat: "no-repeat",
          paddingRight: 28,
        }}
        onFocus={e => { e.currentTarget.style.borderColor = GREEN; }}
        onBlur={e => { e.currentTarget.style.borderColor = GREEN_FAINT; }}
      >
        {options.map(o => (
          <option key={o} value={o} style={{ background: BLACK, color: GREEN }}>{o}</option>
        ))}
      </select>
    </div>
  );

  return (
    <>
      {/* ── SCOPED KEYFRAMES FOR CRT/TERMINAL FLAIR ─────────────── */}
      <style>{`
        @keyframes smcCaretBlink {
          0%, 49% { opacity: 1; }
          50%, 100% { opacity: 0; }
        }
        @keyframes smcScanDrift {
          0%   { background-position: 0 0; }
          100% { background-position: 0 4px; }
        }
        @keyframes smcBootGlow {
          0%   { opacity: 0; filter: blur(8px) brightness(1.6); }
          40%  { opacity: 1; filter: blur(0)   brightness(1.2); }
          100% { opacity: 1; filter: blur(0)   brightness(1); }
        }
        @keyframes smcTypeIn {
          from { clip-path: inset(0 100% 0 0); }
          to   { clip-path: inset(0 0 0 0); }
        }
        @keyframes smcFlicker {
          0%,100% { opacity: 1; }
          18%, 22% { opacity: 0.82; }
          35%, 36% { opacity: 0.96; }
          72%, 73% { opacity: 0.9; }
        }
      `}</style>

      {/* Section header */}
      <div style={{
        display: "flex", alignItems: "center", gap: 8,
        marginBottom: 12,
      }}>
        <span style={{
          fontSize: 10, fontWeight: 700, letterSpacing: "0.3em",
          color: GREEN,
          padding: "4px 8px",
          background: GREEN_BG,
          border: `1px solid ${GREEN_FAINT}`,
          borderRadius: 3,
          fontFamily: T.font_mono,
        }}>
          § SUNO_MASTER_CONSOLE
        </span>
        <span style={{ flex: 1, height: 1, background: GREEN_FAINT }} />
        <span style={{
          color: GREEN_DIM, fontSize: 10,
          padding: "2px 6px",
          background: GREEN_BG,
          border: `1px dashed ${GREEN_FAINT}`,
          borderRadius: 3,
          letterSpacing: "0.1em",
          fontFamily: T.font_mono,
        }}>
          ISRAELI SCENE · {israeliArtists.length} ARTISTS
        </span>
      </div>

      {/* ── CONSOLE FRAME ── */}
      <div style={{
        marginBottom: 32,
        position: "relative",
        border: `1px solid ${GREEN_FAINT}`,
        borderRadius: 6,
        background: BLACK,
        overflow: "hidden",
        animation: "smcBootGlow 420ms ease-out",
      }}>
        {/* CRT scan-line overlay — scoped to this frame */}
        <div aria-hidden="true" style={{
          position: "absolute", inset: 0, zIndex: 2,
          pointerEvents: "none",
          background: "repeating-linear-gradient(0deg, rgba(0,255,65,0.035) 0px, rgba(0,255,65,0.035) 1px, transparent 1px, transparent 4px)",
          animation: "smcScanDrift 8s linear infinite",
        }} />
        {/* Soft vignette from the bottom-right like a CRT corner-glow */}
        <div aria-hidden="true" style={{
          position: "absolute", right: "-20%", bottom: "-30%",
          width: "80%", height: "80%", zIndex: 1,
          pointerEvents: "none",
          background: "radial-gradient(ellipse, rgba(0,255,65,0.06) 0%, transparent 60%)",
        }} />

        {/* Terminal title bar */}
        <div style={{
          position: "relative", zIndex: 3,
          display: "flex", alignItems: "center", gap: 10,
          padding: "8px 12px",
          background: "rgba(0, 255, 65, 0.03)",
          borderBottom: `1px solid ${GREEN_FAINT}`,
          fontFamily: T.font_mono,
        }}>
          <span style={{ color: GREEN_MUTE, fontSize: 11, letterSpacing: "0.08em" }}>
            ~/suno-master/<span style={{ color: GREEN }}>{activeArtist?.artistName.toLowerCase().replace(/\s+/g, "-") || "console"}</span>
          </span>
          <span style={{ flex: 1 }} />
          <span style={{
            fontSize: 9, color: GREEN_MUTE, letterSpacing: "0.15em",
            padding: "2px 6px",
            border: `1px dashed ${GREEN_FAINT}`, borderRadius: 2,
          }}>SESSION · ACTIVE</span>
        </div>

        <div style={{
          position: "relative", zIndex: 3,
          padding: isMobile ? 16 : 20,
          display: "grid",
          gridTemplateColumns: isMobile ? "1fr" : "minmax(0, 1fr) minmax(0, 0.85fr)",
          gap: isMobile ? 20 : 24,
          animation: "smcFlicker 9s ease-in-out infinite",
        }}>
          {/* ═══════════ LEFT PANE — ARTIST + SLOTS ═══════════ */}
          <div style={{ display: "flex", flexDirection: "column", gap: 16, minWidth: 0 }}>
            {/* Boot prompt line */}
            <div style={{
              fontFamily: T.font_mono, fontSize: 11,
              color: GREEN_MUTE, letterSpacing: "0.1em",
              display: "flex", alignItems: "center", gap: 6,
            }}>
              <span style={{ color: GREEN }}>$</span>
              <span>suno-master init</span>
              <span>--artist=<span style={{
                color: GREEN_HI,
                animation: "smcTypeIn 380ms ease-out",
                display: "inline-block",
              }}>{activeArtist?.artistName.toLowerCase().replace(/\s+/g, "_") || "null"}</span></span>
              <span style={{
                display: "inline-block", width: 8, height: 13,
                background: GREEN, marginLeft: 2,
                animation: "smcCaretBlink 1s steps(1) infinite",
              }} />
            </div>

            {/* Artist picker */}
            <div>
              <div style={{
                fontSize: 9, fontWeight: 700, letterSpacing: "0.22em",
                color: GREEN_DIM, fontFamily: T.font_mono,
                marginBottom: 8,
              }}>
                ▸ SELECT_ARTIST
              </div>
              <div style={{
                display: "flex", flexWrap: "wrap", gap: 5,
              }}>
                {israeliArtists.map(a => {
                  const isActive = a.artistId === artistId;
                  const hasDNA = !!getArtistVocabulary(a.artistId);
                  return (
                    <button key={a.artistId} type="button"
                      onClick={() => { playSwitchSound(); setArtistId(a.artistId); }}
                      style={{
                        position: "relative",
                        padding: "6px 11px",
                        background: isActive ? "rgba(0, 255, 65, 0.12)" : "transparent",
                        border: `1px solid ${isActive ? GREEN : GREEN_FAINT}`,
                        borderRadius: 3,
                        color: isActive ? GREEN_HI : GREEN_DIM,
                        fontFamily: T.font_mono,
                        fontSize: 11, fontWeight: 700,
                        letterSpacing: "0.04em",
                        cursor: "pointer",
                        textShadow: isActive ? `0 0 6px ${GREEN_DIM}` : "none",
                        transition: `all ${T.dur_fast} ${T.ease}`,
                      }}
                      onMouseEnter={e => { if (!isActive) e.currentTarget.style.borderColor = GREEN_DIM; }}
                      onMouseLeave={e => { if (!isActive) e.currentTarget.style.borderColor = GREEN_FAINT; }}
                    >
                      {a.artistName}
                      {hasDNA && (
                        <span style={{
                          marginLeft: 6,
                          fontSize: 7, letterSpacing: "0.2em",
                          padding: "1px 4px",
                          color: GREEN,
                          background: "rgba(0, 255, 65, 0.08)",
                          borderRadius: 2,
                        }}>DNA</span>
                      )}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* DNA expandable drawer */}
            <div>
              <button type="button"
                onClick={() => { playSwitchSound(); setDnaOpen(v => !v); }}
                style={{
                  width: "100%",
                  display: "flex", alignItems: "center", gap: 8,
                  padding: "7px 11px",
                  background: dnaOpen ? "rgba(0, 255, 65, 0.06)" : "transparent",
                  border: `1px dashed ${GREEN_MUTE}`,
                  borderRadius: 3,
                  color: GREEN,
                  fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
                  letterSpacing: "0.15em",
                  cursor: "pointer",
                  textAlign: "left",
                  transition: `all ${T.dur_fast} ${T.ease}`,
                }}
              >
                <span style={{ color: GREEN_HI }}>{dnaOpen ? "▾" : "▸"}</span>
                <span>SONIC_DNA</span>
                <span style={{ flex: 1 }} />
                <span style={{ color: GREEN_MUTE, fontSize: 9 }}>
                  {vocab ? "full profile available" : "pack-level only"}
                </span>
              </button>
              {dnaOpen && (
                <div style={{
                  marginTop: 6,
                  padding: "12px 14px",
                  background: BLACK_RAISED,
                  border: `1px solid ${GREEN_FAINT}`,
                  borderRadius: 3,
                  fontFamily: T.font_mono, fontSize: 11,
                  color: GREEN_HI,
                  lineHeight: 1.65,
                }}>
                  {vocab ? (
                    <>
                      {Array.isArray(vocab.vocal) && vocab.vocal.length > 0 && (
                        <DnaBlock label="VOCAL" items={vocab.vocal} color={GREEN} dim={GREEN_MUTE} />
                      )}
                      {Array.isArray(vocab.production) && vocab.production.length > 0 && (
                        <DnaBlock label="PRODUCTION" items={vocab.production} color={GREEN} dim={GREEN_MUTE} />
                      )}
                      {Array.isArray(vocab.signature) && vocab.signature.length > 0 && (
                        <DnaBlock label="SIGNATURE" items={vocab.signature} color={GREEN} dim={GREEN_MUTE} />
                      )}
                      {vocab.era && (
                        <div style={{ marginTop: 8 }}>
                          <span style={{ color: GREEN_MUTE, fontSize: 9, letterSpacing: "0.2em" }}>// ERA</span>
                          <div style={{ marginTop: 3 }}>{vocab.era}</div>
                        </div>
                      )}
                    </>
                  ) : (
                    <div style={{ color: GREEN_DIM }}>
                      &gt; no DNA profile in database for this artist yet
                      <br />
                      &gt; falling back to first-pack descriptors as seed
                      {activeArtist?.packs?.[0]?.state && (
                        <div style={{ marginTop: 10, paddingTop: 10, borderTop: `1px dashed ${GREEN_FAINT}`, color: GREEN_HI }}>
                          mood: {activeArtist.packs[0].state.mood || "—"}<br />
                          groove: {activeArtist.packs[0].state.groove || "—"}<br />
                          texture: {activeArtist.packs[0].state.texture || "—"}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* Divider */}
            <div style={{
              fontFamily: T.font_mono, fontSize: 10, color: GREEN_MUTE,
              letterSpacing: "0.1em",
              padding: "6px 0",
              borderTop: `1px dashed ${GREEN_FAINT}`,
              borderBottom: `1px dashed ${GREEN_FAINT}`,
            }}>
              ─── CONFIG ───────────────────────────
            </div>

            {/* Structured slots */}
            {/* ═══════ GENRE SLOTS — 3-slot tree picker ═══════
                Full genre / subgenre / microgenre tree navigation
                lives in its own block above the other config sliders
                because it's structurally bigger + more important
                (it's the primary anchor of any prompt). The other
                sliders stay in the 2-col grid below. */}
            <div>
              <div style={{
                display: "flex", alignItems: "baseline", gap: 6,
                marginBottom: 8,
              }}>
                <span style={{
                  fontSize: 9, fontWeight: 700, letterSpacing: "0.22em",
                  color: GREEN_DIM, fontFamily: T.font_mono,
                }}>
                  ▸ GENRE_STACK
                </span>
                <span style={{
                  fontSize: 9, color: GREEN_MUTE, fontFamily: T.font_mono,
                  letterSpacing: "0.05em",
                }}>
                  // primary + blend slots · tree: genre › subgenre › microstyle
                </span>
              </div>
              <GenreSlotPickerCRT
                slots={slots}
                onChange={setSlots}
                slotLocks={slotLocks}
                onToggleSlotLock={(i) => {
                  setSlotLocks(prev => {
                    const next = [...prev];
                    next[i] = !next[i];
                    return next;
                  });
                }}
              />
            </div>

            {/* ═══════ INSTRUMENTAL / SONG SWITCH ═══════
                Before the genre stack — first decision a producer
                makes. Gates whether the vocal block renders below
                (instrumental hides VOCALIST / LANGUAGE / LYRICAL_VIBE
                since those are meaningless without vocals). Styled
                as a CRT dual-tab rail to match the terminal aesthetic. */}
            <div>
              <div style={{
                display: "flex", alignItems: "baseline", gap: 6,
                marginBottom: 8,
              }}>
                <span style={{
                  fontSize: 9, fontWeight: 700, letterSpacing: "0.22em",
                  color: GREEN_DIM, fontFamily: T.font_mono,
                }}>▸ TYPE</span>
                <span style={{
                  fontSize: 9, color: GREEN_MUTE, fontFamily: T.font_mono,
                  letterSpacing: "0.05em",
                }}>// instrumental vs vocal song — gates voice block below</span>
              </div>
              <div style={{
                display: "inline-flex",
                border: `1px solid ${GREEN_FAINT}`,
                borderRadius: 3,
                overflow: "hidden",
                background: BLACK,
              }}>
                {[
                  { id: true,  label: "▶ SONG", note: "with vocals" },
                  { id: false, label: "▬ INSTRUMENTAL", note: "no vocals" },
                ].map(opt => {
                  const active = lyricsOn === opt.id;
                  return (
                    <button key={String(opt.id)} type="button"
                      onClick={() => { playSwitchSound(); setLyricsOn(opt.id); }}
                      style={{
                        padding: isMobile ? "9px 14px" : "8px 16px",
                        background: active ? "rgba(0, 255, 65, 0.12)" : "transparent",
                        border: "none",
                        color: active ? GREEN_HI : GREEN_MUTE,
                        fontFamily: T.font_mono,
                        fontSize: isMobile ? 13 : 11, fontWeight: 700,
                        letterSpacing: "0.15em",
                        cursor: "pointer",
                        textShadow: active ? `0 0 6px ${GREEN_DIM}` : "none",
                        transition: `all ${T.dur_fast} ${T.ease}`,
                      }}
                    >
                      {opt.label}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* ═══════ REMAINING CONFIG GRID ═══════
                Mood / energy / groove / harmonic / texture / mix / BPM
                as terminal-skinned dropdowns + slider. Laid out in a
                2-column grid (single column on mobile). */}
            <div style={{
              display: "grid",
              gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr",
              gap: 14,
            }}>
              {slot("MOOD",      mood,      setMood,      MOODS_OPTIONS, "emotional tone")}
              {slot("ENERGY",    energy,    setEnergy,    ENERGIES_OPTIONS, "dynamic arc")}
              {slot("GROOVE",    groove,    setGroove,    GROOVES_OPTIONS, "rhythmic feel")}
              {slot("HARMONIC",  harmonic,  setHarmonic,  HARMONIC_OPTIONS, "key character")}
              {slot("TEXTURE",   texture,   setTexture,   TEXTURE_OPTIONS, "sonic feel")}
              {slot("MIX",       mix,       setMix,       MIX_OPTIONS, "polish character")}
              {/* BPM — slider rather than dropdown */}
              <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                <div style={{ display: "flex", alignItems: "baseline", gap: 6 }}>
                  <span style={{
                    fontSize: 9, fontWeight: 700, letterSpacing: "0.22em",
                    color: GREEN_DIM, fontFamily: T.font_mono,
                  }}>▸ BPM</span>
                  <span style={{
                    fontSize: 11, color: GREEN, fontFamily: T.font_mono,
                    fontWeight: 700,
                  }}>{bpm}</span>
                </div>
                <input type="range" min="60" max="180" value={bpm}
                  onChange={e => setBpm(parseInt(e.target.value, 10))}
                  style={{
                    width: "100%",
                    accentColor: GREEN,
                  }}
                />
              </div>
            </div>

            {/* ═══════ VOCAL MODE ═══════
                Only renders in SONG mode (lyricsOn=true). In
                INSTRUMENTAL mode the whole block collapses — vocalist /
                language / lyrical vibe are meaningless without vocals.
                Gated render keeps the console tight and honest about
                what's actually driving the prompt. */}
            {lyricsOn && (
              <div>
                <div style={{
                  display: "flex", alignItems: "baseline", gap: 6,
                  marginBottom: 8,
                }}>
                  <span style={{
                    fontSize: 9, fontWeight: 700, letterSpacing: "0.22em",
                    color: GREEN_DIM, fontFamily: T.font_mono,
                  }}>▸ VOCAL_MODE</span>
                  <span style={{
                    fontSize: 9, color: GREEN_MUTE, fontFamily: T.font_mono,
                    letterSpacing: "0.05em",
                  }}>// vocal character · language · lyrical framing</span>
                </div>
                <div style={{
                  display: "grid",
                  gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr 1fr",
                  gap: 14,
                }}>
                  {slot("VOCALIST", vocalist, setVocalist, VOCALISTS_OPTIONS, "vocal character")}
                  {/* LANGUAGE — uses code as value, label as display */}
                  <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                    <div style={{ display: "flex", alignItems: "baseline", gap: 6 }}>
                      <span style={{
                        fontSize: 9, fontWeight: 700, letterSpacing: "0.22em",
                        color: GREEN_DIM, fontFamily: T.font_mono,
                      }}>▸ LANGUAGE</span>
                      <span style={{
                        fontSize: 9, color: GREEN_MUTE, fontFamily: T.font_mono,
                        letterSpacing: "0.05em",
                      }}>// lyric language</span>
                    </div>
                    <select
                      value={language}
                      onChange={e => { playSwitchSound(); setLanguage(e.target.value); }}
                      style={{
                        padding: isMobile ? "9px 12px" : "7px 10px",
                        background: BLACK,
                        border: `1px solid ${GREEN_FAINT}`,
                        borderRadius: 3,
                        color: GREEN,
                        fontFamily: T.font_mono,
                        fontSize: isMobile ? 16 : 12,
                        fontWeight: 600,
                        letterSpacing: "0.02em",
                        outline: "none",
                        cursor: "pointer",
                        appearance: "none",
                        WebkitAppearance: "none",
                        backgroundImage: `linear-gradient(45deg, transparent 50%, ${GREEN_DIM} 50%), linear-gradient(135deg, ${GREEN_DIM} 50%, transparent 50%)`,
                        backgroundPosition: `calc(100% - 14px) calc(50% - 2px), calc(100% - 9px) calc(50% - 2px)`,
                        backgroundSize: "5px 5px, 5px 5px",
                        backgroundRepeat: "no-repeat",
                        paddingRight: 28,
                      }}
                      onFocus={e => { e.currentTarget.style.borderColor = GREEN; }}
                      onBlur={e => { e.currentTarget.style.borderColor = GREEN_FAINT; }}
                    >
                      {LANGUAGES_OPTIONS.map(l => (
                        <option key={l.code} value={l.code} style={{ background: BLACK, color: GREEN }}>
                          {l.label}
                        </option>
                      ))}
                    </select>
                  </div>
                  {slot("LYRICAL_VIBE", lyricalVibe, setLyricalVibe, LYRICAL_VIBES_OPTIONS, "lyric framing")}
                </div>
              </div>
            )}
          </div>

          {/* ═══════════ RIGHT PANE — LIVE PROMPT ═══════════ */}
          <div style={{
            display: "flex", flexDirection: "column", gap: 14,
            minWidth: 0,
          }}>
            <div style={{
              fontFamily: T.font_mono, fontSize: 11,
              color: GREEN_MUTE, letterSpacing: "0.1em",
            }}>
              <span style={{ color: GREEN }}>$</span> cat prompt.txt
            </div>
            <div style={{
              position: "relative",
              flex: 1,
              minHeight: 180,
              padding: "14px 16px",
              background: BLACK_RAISED,
              border: `1px solid ${GREEN_FAINT}`,
              borderRadius: 3,
              fontFamily: T.font_mono,
              fontSize: 12.5,
              lineHeight: 1.7,
              color: GREEN_HI,
              letterSpacing: "0.01em",
              whiteSpace: "pre-wrap",
              wordBreak: "break-word",
              overflow: "auto",
              textShadow: `0 0 4px ${GREEN_MUTE}`,
            }}>
              {prompt}
              <span style={{
                display: "inline-block", width: 7, height: 13,
                background: GREEN, marginLeft: 4, verticalAlign: "middle",
                animation: "smcCaretBlink 1s steps(1) infinite",
              }} />
            </div>
            {/* Action rail */}
            <div style={{
              display: "flex", gap: 8, flexWrap: "wrap",
              alignItems: "center",
            }}>
              <button type="button"
                onClick={doCopy}
                style={{
                  padding: "8px 14px",
                  background: copied ? "rgba(0, 255, 65, 0.18)" : "rgba(0, 255, 65, 0.08)",
                  border: `1px solid ${copied ? GREEN_HI : GREEN}`,
                  borderRadius: 3,
                  color: copied ? GREEN_HI : GREEN,
                  fontFamily: T.font_mono, fontSize: 11, fontWeight: 700,
                  letterSpacing: "0.15em",
                  cursor: "pointer",
                  textShadow: `0 0 6px ${GREEN_MUTE}`,
                  transition: `all ${T.dur_fast} ${T.ease}`,
                }}
              >
                {copied ? "✓ COPIED_TO_CLIPBOARD" : "⎘ COPY_PROMPT"}
              </button>
              <span style={{
                fontFamily: T.font_mono, fontSize: 10,
                color: GREEN_MUTE, letterSpacing: "0.08em",
              }}>
                // paste into suno.com and generate
              </span>
            </div>
            {/* Footer stat ledger */}
            <div style={{
              marginTop: "auto",
              paddingTop: 10,
              borderTop: `1px dashed ${GREEN_FAINT}`,
              fontFamily: T.font_mono, fontSize: 10,
              color: GREEN_MUTE,
              letterSpacing: "0.08em",
              lineHeight: 1.7,
            }}>
              <div>length: {prompt.length} chars</div>
              <div>genre_slots: {slots.filter(Boolean).length}/3 · locked: {slotLocks.filter(Boolean).length}</div>
              <div>mode: {lyricsOn ? "song" : "instrumental"}{lyricsOn && language !== "en" ? ` · ${language}` : ""}</div>
              <div>dna_source: {vocab ? "ARTIST_VOCABULARY" : "pack_palette_fallback"}</div>
            </div>
          </div>
        </div>

        {/* ── BOTTOM STATUS STRIP ── */}
        <div style={{
          position: "relative", zIndex: 3,
          padding: "6px 12px",
          borderTop: `1px solid ${GREEN_FAINT}`,
          background: "rgba(0, 255, 65, 0.02)",
          display: "flex", gap: 16, flexWrap: "wrap",
          fontFamily: T.font_mono, fontSize: 9,
          color: GREEN_MUTE, letterSpacing: "0.1em",
        }}>
          <span>sys: suno-master-console</span>
          <span>v: 1.0.0</span>
          <span style={{ flex: 1 }} />
          <span>bpm: {bpm}</span>
          <span>•</span>
          <span>{activeArtist?.artistName || "—"}</span>
        </div>
      </div>
    </>
  );
}

// Helper: one DNA block inside the expandable drawer. Separated so the
// drawer body stays readable in the main component.
function DnaBlock({ label, items, color, dim }) {
  return (
    <div style={{ marginBottom: 10 }}>
      <div style={{ color: dim, fontSize: 9, letterSpacing: "0.2em", marginBottom: 3 }}>
        // {label}
      </div>
      {items.map((item, i) => (
        <div key={i} style={{ paddingLeft: 10 }}>
          <span style={{ color: dim }}>›</span> {item}
        </div>
      ))}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// BUBBLE TOOLS PAGE — admin-only dedicated surface for internal tools
// ════════════════════════════════════════════════════════════════════════════
// Hacker-backdoor aesthetic: black background, electric-green accents,
// terminal mono type, subtle scan-line overlay. This is Bubble's dev
// vault — all admin-only internal tools live here instead of cluttering
// the Engine page. Accessed via the ◢ BUBBLE TOOLS nav link that only
// renders when tier === "admin".
//
// V1 content: Artist Mimic Pack browser (moved from Engine page).
// Future sections will be added: Era Picker, Future Prompts generator,
// Artist DNA editor, Credit-grant tool, Debug console.
//
// Pack application flow: clicking a pack writes the selection to
// sessionStorage and navigates to /engine, which has a mount-effect
// that reads the pending pack and calls applyMimicPack. This preserves
// all existing apply logic without needing to lift engine state.
// ════════════════════════════════════════════════════════════════════════════

function BubbleToolsPage({ onNavigate }) {
  const { tier } = useTier();
  const { layout } = useLayout();
  const isMobile = layout === "mobile";

  // Mimic pack state — local to this page. Mirrors what used to live
  // inside EnginePage. Applying a pack navigates to Engine.
  const [mimicArtistId, setMimicArtistId] = useState(MIMIC_PACKS[0].artistId);
  const [mimicRegionFilter, setMimicRegionFilter] = useState("all");
  const [mimicSearch, setMimicSearch] = useState("");
  const [mimicVibeFilter, setMimicVibeFilter] = useState("all");
  const [mimicViewMode, setMimicViewMode] = useState("artist");
  const [crossVibeActive, setCrossVibeActive] = useState("anthemic");
  const [vibeUsageCounts, setVibeUsageCounts] = useState({});
  const [mimicBlendVibe, setMimicBlendVibe] = useState(null);

  const filteredMimicArtists = MIMIC_PACKS.filter(a => {
    if (mimicRegionFilter !== "all" && a.region !== mimicRegionFilter) return false;
    if (mimicSearch.trim()) {
      const q = mimicSearch.trim().toLowerCase();
      if (!a.artistName.toLowerCase().includes(q)) return false;
    }
    return true;
  });
  const activeMimicArtist = MIMIC_PACKS.find(a => a.artistId === mimicArtistId) || MIMIC_PACKS[0];
  useEffect(() => { setMimicVibeFilter("all"); }, [mimicArtistId]);
  const filteredPacks = activeMimicArtist.packs.filter(p => {
    if (mimicVibeFilter === "all") return true;
    return p.vibe === mimicVibeFilter;
  });

  const allPacksFlat = useMemo(() => {
    const out = [];
    MIMIC_PACKS.forEach(artist => { artist.packs.forEach(pack => { out.push({ artist, pack }); }); });
    return out;
  }, []);
  const packsByVibe = useMemo(() => {
    const map = {};
    VIBE_META.forEach(v => { map[v.id] = []; });
    allPacksFlat.forEach(({ artist, pack }) => {
      const v = pack.vibe || "moody";
      if (!map[v]) map[v] = [];
      map[v].push({ artist, pack });
    });
    return map;
  }, [allPacksFlat]);
  const mostUsedVibe = useMemo(() => {
    const entries = Object.entries(vibeUsageCounts);
    if (entries.length === 0) return null;
    entries.sort((a, b) => b[1] - a[1]);
    return entries[0][0];
  }, [vibeUsageCounts]);
  const trackVibeUse = (vibeId) => {
    if (!vibeId) return;
    setVibeUsageCounts(prev => ({ ...prev, [vibeId]: (prev[vibeId] || 0) + 1 }));
  };

  // Pack application handler — writes {artistId, packId, blendVibe}
  // to sessionStorage and navigates to Engine. Engine reads the pending
  // entry on mount and fires applyMimicPack with the matching pack.
  // Using sessionStorage (not a context or URL param) keeps the
  // BubbleTools page self-contained and avoids touching engine state
  // plumbing that's already working cleanly.
  const applyAndGo = (artist, pack) => {
    playSwitchSound();
    try {
      sessionStorage.setItem("he-pending-mimic", JSON.stringify({
        artistId: artist.artistId,
        packId: pack.id,
        blendVibe: mimicBlendVibe,
        ts: Date.now(),
      }));
      // Dispatch a custom event so the EngineWorkspace embedded on
      // THIS page (Turn 2 refactor) can pick up the pack immediately
      // without a page navigation. The workspace listens for this
      // event and re-reads sessionStorage. Pure /engine page visits
      // still work via the mount-time useEffect handler.
      window.dispatchEvent(new CustomEvent("he-pending-change", {
        detail: { kind: "mimic" },
      }));
    } catch {}
    trackVibeUse(pack.vibe);
    // No page navigation — the Engine is embedded right here on
    // BubbleTools. Let the embedded workspace react via event.
    // If admin scrolled past the embedded Engine, they can scroll
    // back up to see the applied result.
  };

  const shuffleVibe = () => {
    const weightedVibes = [];
    VIBE_META.forEach(v => {
      const count = (packsByVibe[v.id] || []).length;
      for (let i = 0; i < count; i++) weightedVibes.push(v.id);
    });
    if (weightedVibes.length === 0) return;
    const rolledVibe = weightedVibes[Math.floor(Math.random() * weightedVibes.length)];
    const bucket = packsByVibe[rolledVibe] || [];
    if (bucket.length === 0) return;
    const pick = bucket[Math.floor(Math.random() * bucket.length)];
    setCrossVibeActive(rolledVibe);
    setMimicViewMode("vibe");
    applyAndGo(pick.artist, pick.pack);
  };

  // Access guard — if somehow a non-admin lands here (URL tinkering),
  // show a minimal 403 rather than the admin console. Shouldn't happen
  // in normal flow because the nav link is admin-gated.
  if (tier !== "admin") {
    return (
      <div style={{
        minHeight: "80vh",
        display: "flex", alignItems: "center", justifyContent: "center",
        padding: T.s6,
      }}>
        <div style={{
          maxWidth: 440, textAlign: "center",
          padding: T.s6,
          background: "#0A0A0A",
          border: `1px solid rgba(0, 255, 65, 0.22)`,
          borderRadius: T.r_lg,
          fontFamily: T.font_mono,
          color: "rgba(0, 255, 65, 0.72)",
        }}>
          <div style={{ fontSize: 36, marginBottom: T.s3 }}>◢</div>
          <div style={{ fontSize: 14, fontWeight: 700, letterSpacing: "0.2em", marginBottom: T.s2 }}>
            ACCESS DENIED
          </div>
          <div style={{ fontSize: 12, color: "rgba(0, 255, 65, 0.5)", lineHeight: 1.6 }}>
            This surface is restricted to admin accounts.
            <br />Return to{" "}
            <button type="button" onClick={() => onNavigate && onNavigate("engine")}
              style={{
                background: "transparent", border: "none",
                color: "#00FF41", cursor: "pointer",
                textDecoration: "underline", fontFamily: "inherit",
                padding: 0,
              }}
            >engine</button>.
          </div>
        </div>
      </div>
    );
  }

  const GREEN = "#00FF41";
  const GREEN_DIM = "rgba(0, 255, 65, 0.45)";
  const GREEN_FAINT = "rgba(0, 255, 65, 0.12)";
  const GREEN_BG = "rgba(0, 255, 65, 0.04)";

  return (
    <div style={{
      minHeight: "100vh",
      background: "#050505",
      color: GREEN,
      fontFamily: T.font_mono,
      position: "relative",
      overflow: "hidden",
    }}>
      {/* ── SCAN-LINE OVERLAY — subtle CRT feel ─────────────────────
          Fine horizontal lines tiled across the page. Low contrast so
          it doesn't fight the content but adds a terminal-display
          texture to the backdrop. */}
      <div aria-hidden="true" style={{
        position: "fixed", inset: 0, zIndex: 0,
        backgroundImage: "repeating-linear-gradient(0deg, rgba(0,255,65,0.03) 0px, rgba(0,255,65,0.03) 1px, transparent 1px, transparent 3px)",
        pointerEvents: "none",
      }} />
      {/* ── AMBIENT GREEN GLOW — subtle vignette from the bottom ──── */}
      <div aria-hidden="true" style={{
        position: "fixed", bottom: "-40%", left: "50%",
        width: "90%", height: "80%",
        transform: "translateX(-50%)",
        background: "radial-gradient(ellipse at center, rgba(0, 255, 65, 0.05) 0%, transparent 60%)",
        pointerEvents: "none", zIndex: 0,
      }} />

      <div style={{
        position: "relative", zIndex: 1,
        maxWidth: 1400, margin: "0 auto",
        padding: isMobile ? T.s4 : `${T.s7}px ${T.s8}px`,
      }}>
        {/* ── HEADER — terminal-prompt branding ─────────────────────
            Simulates a CLI session: prompt char + command + cursor.
            Makes Bubble feel like she's operating inside a dev shell
            rather than a consumer app. */}
        <div style={{
          marginBottom: isMobile ? T.s5 : T.s7,
          paddingBottom: T.s4,
          borderBottom: `1px solid rgba(0, 255, 65, 0.18)`,
        }}>
          <div style={{
            fontSize: 11,
            color: GREEN_DIM,
            letterSpacing: "0.2em",
            marginBottom: T.s2,
          }}>
            bubble@hit-engine:~$ <span style={{ color: GREEN }}>./tools --admin --unlock</span>
          </div>
          <div style={{
            fontSize: isMobile ? 28 : 42,
            fontWeight: 800,
            letterSpacing: "0.08em",
            color: GREEN,
            textShadow: `0 0 20px ${GREEN_DIM}, 0 0 40px rgba(0, 255, 65, 0.18)`,
            lineHeight: 1.1,
            marginBottom: T.s3,
          }}>
            ◢ BUBBLE TOOLS
          </div>
          <div style={{
            fontSize: 12,
            color: GREEN_DIM,
            letterSpacing: "0.08em",
            fontFamily: T.font_mono,
            lineHeight: 1.6,
          }}>
            admin backdoor · {MIMIC_PACKS.length} artists indexed · {allPacksFlat.length} curated packs · recipe engine online
          </div>
          <div style={{
            marginTop: T.s3,
            fontSize: 10,
            color: "rgba(0, 255, 65, 0.35)",
            letterSpacing: "0.1em",
          }}>
            [ session authenticated · dev-tier ]
          </div>
        </div>

        {/* ── SECTION — SUNO MASTER CONSOLE ───────────────────────
            Purpose-built workstation for producers turning Suno AI
            output into finished tracks for Israeli artists. Not a
            clone of the Engine — it's a different workflow:
              1. Pick an Israeli artist from the roster
              2. See their sonic DNA (expandable on demand)
              3. Build a Suno prompt around that DNA using terminal
                 slot controls
              4. Copy, iterate, produce
            Full CRT/hacker aesthetic — matches the surrounding
            BubbleTools page, no context-switching between indigo
            and green zones like the old embedded Engine did. */}
        <SunoMasterConsole />

        {/* ── SECTION — EXTRA POPPY ─────────────────────────────────
            Admin-exclusive pop-maximizer. Golden treasure chest
            opened-state since admin always has permission + infinite
            fuel. Clicking it writes a pending flag to sessionStorage
            and navigates to Engine, where a mount effect reads the
            flag and fires applyMaxPoppy with the current state. */}
        <div style={{
          display: "flex", alignItems: "center", gap: T.s2,
          marginBottom: T.s3,
        }}>
          <span style={{
            fontSize: 10, fontWeight: 700, letterSpacing: "0.3em",
            color: GREEN,
            padding: "4px 8px",
            background: GREEN_BG,
            border: `1px solid ${GREEN_FAINT}`,
            borderRadius: 3,
          }}>
            § EXTRA_POPPY
          </span>
          <span style={{ flex: 1, height: 1, background: GREEN_FAINT }} />
          <span style={{
            color: GREEN_DIM, fontSize: 10,
            padding: "2px 6px",
            background: GREEN_BG,
            border: `1px dashed ${GREEN_FAINT}`,
            borderRadius: 3,
            letterSpacing: "0.1em",
          }}>
            ADMIN ONLY
          </span>
        </div>
        <button
          type="button"
          onClick={() => {
            playSwitchSound();
            try {
              sessionStorage.setItem("he-pending-max-poppy", JSON.stringify({ ts: Date.now() }));
              // Same pattern as applyAndGo — fire event for the
              // embedded EngineWorkspace to react immediately
              // without a page navigation.
              window.dispatchEvent(new CustomEvent("he-pending-change", {
                detail: { kind: "max-poppy" },
              }));
            } catch {}
            // No navigation — embedded Engine reacts via event.
          }}
          title="Open the chest — maximize the current config for pop appeal"
          style={{
            width: "100%",
            position: "relative",
            marginBottom: T.s7,
            display: "flex", alignItems: "center", justifyContent: "center",
            gap: 12,
            padding: "20px 20px",
            // Opened-chest styling — full-saturation gold since admin
            // has unconditional access. No locked variant here because
            // this page literally doesn't render for non-admin.
            background: `linear-gradient(180deg,
              rgba(255, 215, 0, 0.28) 0%,
              rgba(255, 200, 60, 0.20) 50%,
              rgba(255, 165, 0, 0.24) 100%)`,
            border: "1.5px solid #FFD700",
            borderRadius: T.r_lg,
            color: "#FFD700",
            fontFamily: T.font_mono, fontSize: 13, fontWeight: 800,
            letterSpacing: "0.18em",
            cursor: "pointer",
            boxShadow: "inset 0 1px 0 rgba(255,255,255,0.2), 0 0 20px rgba(255,215,0,0.35), 0 3px 10px rgba(255,165,0,0.2)",
            overflow: "hidden",
            transition: `all ${T.dur_fast} ${T.ease}`,
          }}
          onMouseEnter={e => {
            e.currentTarget.style.boxShadow = "inset 0 1px 0 rgba(255,255,255,0.3), 0 0 30px rgba(255,215,0,0.55), 0 4px 14px rgba(255,165,0,0.3)";
            e.currentTarget.style.transform = "translateY(-2px)";
          }}
          onMouseLeave={e => {
            e.currentTarget.style.boxShadow = "inset 0 1px 0 rgba(255,255,255,0.2), 0 0 20px rgba(255,215,0,0.35), 0 3px 10px rgba(255,165,0,0.2)";
            e.currentTarget.style.transform = "translateY(0)";
          }}
        >
          {/* Ambient shimmer sweep */}
          <span
            aria-hidden="true"
            style={{
              position: "absolute", top: 0, left: "-40%", width: "40%", height: "100%",
              background: `linear-gradient(105deg,
                transparent 0%,
                rgba(255,255,255,0.18) 40%,
                rgba(255,255,255,0.32) 50%,
                rgba(255,255,255,0.18) 60%,
                transparent 100%)`,
              animation: "chestShimmer 3.5s ease-in-out infinite",
              pointerEvents: "none",
            }}
          />
          <span style={{
            fontSize: 24, lineHeight: 1,
            textShadow: "0 0 10px rgba(255,215,0,0.7)",
          }}>💎</span>
          <span style={{ display: "flex", flexDirection: "column", alignItems: "flex-start", gap: 2 }}>
            <span>EXTRA POPPY</span>
            <span style={{
              fontSize: 9, letterSpacing: "0.2em",
              color: "#FFE48A", fontWeight: 700,
              opacity: 0.8,
            }}>
              &gt; pop-maximize current config
            </span>
          </span>
          <span style={{ flex: 1 }} />
          <span style={{
            fontSize: 10, letterSpacing: "0.12em",
            color: "#FFE48A", fontWeight: 700,
            padding: "4px 10px",
            background: "rgba(255,228,138,0.15)",
            border: "1px solid rgba(255,215,0,0.4)",
            borderRadius: 3,
          }}>
            OPENED
          </span>
        </button>

        {/* ── SECTION HEADER — MIMIC PACK BROWSER ─────────────────── */}
        <div style={{
          display: "flex", alignItems: "center", gap: T.s2,
          marginBottom: T.s4,
        }}>
          <span style={{
            fontSize: 10, fontWeight: 700, letterSpacing: "0.3em",
            color: GREEN,
            padding: "4px 8px",
            background: GREEN_BG,
            border: `1px solid ${GREEN_FAINT}`,
            borderRadius: 3,
          }}>
            § ARTIST_MIMIC_BROWSER
          </span>
          <span style={{ flex: 1, height: 1, background: GREEN_FAINT }} />
          <span style={{
            color: GREEN_DIM, fontSize: 10,
            padding: "2px 6px",
            background: GREEN_BG,
            border: `1px dashed ${GREEN_FAINT}`,
            borderRadius: 3,
            letterSpacing: "0.1em",
          }}>
            {MIMIC_PACKS.length} × 10
          </span>
        </div>

        {/* ── VIEW MODE + SHUFFLE + USAGE + BLEND ROW ───────────────── */}
        <div style={{
          display: "flex", alignItems: "center",
          gap: T.s2, flexWrap: "wrap",
          marginBottom: T.s3,
        }}>
          <div style={{
            display: "inline-flex",
            background: "#000000",
            border: `1px solid ${GREEN_FAINT}`,
            borderRadius: T.r_sm,
            padding: 2,
          }}>
            {[
              { id: "artist", label: "By Artist" },
              { id: "vibe",   label: "By Vibe"   },
            ].map(m => {
              const active = mimicViewMode === m.id;
              return (
                <button key={m.id} type="button"
                  onClick={() => { playSwitchSound(); setMimicViewMode(m.id); }}
                  style={{
                    padding: "6px 14px",
                    background: active ? "rgba(0, 255, 65, 0.12)" : "transparent",
                    border: `1px solid ${active ? GREEN : "transparent"}`,
                    borderRadius: T.r_sm - 1,
                    color: active ? GREEN : GREEN_DIM,
                    fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
                    letterSpacing: "0.12em",
                    cursor: "pointer",
                    transition: `all ${T.dur_fast} ${T.ease}`,
                    textShadow: active ? `0 0 6px ${GREEN_DIM}` : "none",
                  }}
                >{m.label}</button>
              );
            })}
          </div>
          <button type="button"
            onClick={shuffleVibe}
            title="Shuffle: roll random vibe + random pack"
            style={{
              display: "inline-flex", alignItems: "center", gap: 6,
              padding: "7px 14px",
              background: "rgba(0, 255, 65, 0.06)",
              border: `1px solid ${GREEN_DIM}`,
              borderRadius: T.r_sm,
              color: GREEN,
              fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
              letterSpacing: "0.12em",
              cursor: "pointer",
              transition: `all ${T.dur_fast} ${T.ease}`,
            }}
            onMouseEnter={e => {
              e.currentTarget.style.borderColor = GREEN;
              e.currentTarget.style.boxShadow = `0 0 12px rgba(0, 255, 65, 0.25)`;
            }}
            onMouseLeave={e => {
              e.currentTarget.style.borderColor = GREEN_DIM;
              e.currentTarget.style.boxShadow = "none";
            }}
          >
            ◆ SHUFFLE_VIBE
          </button>
          <span style={{ flex: 1 }} />
          {mostUsedVibe && (() => {
            const meta = VIBE_META.find(v => v.id === mostUsedVibe);
            if (!meta) return null;
            const total = vibeUsageCounts[mostUsedVibe] || 0;
            return (
              <span
                title={`Most-used vibe this session: ${meta.label} (${total}×)`}
                style={{
                  display: "inline-flex", alignItems: "center", gap: 5,
                  padding: "4px 9px",
                  background: GREEN_BG,
                  border: `1px dashed ${GREEN_DIM}`,
                  borderRadius: T.r_sm,
                  color: GREEN,
                  fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
                  letterSpacing: "0.1em",
                }}
              >
                <span>{meta.icon}</span>
                <span style={{ opacity: 0.7 }}>MOST_USED ·</span>
                <span>{meta.label.toUpperCase()}</span>
                <span style={{
                  fontSize: 8,
                  padding: "1px 4px",
                  background: "rgba(0, 255, 65, 0.12)",
                  borderRadius: 2,
                }}>{total}×</span>
              </span>
            );
          })()}
        </div>

        {/* ── BLEND ROW ───────────────────────────────────────────── */}
        <div style={{
          display: "flex", alignItems: "center",
          gap: T.s2, flexWrap: "wrap",
          marginBottom: T.s4,
          padding: `${T.s2}px ${T.s3}px`,
          background: GREEN_BG,
          border: `1px dashed ${GREEN_FAINT}`,
          borderRadius: T.r_sm,
        }}>
          <span style={{
            fontFamily: T.font_mono, fontSize: 9, fontWeight: 700,
            color: GREEN, letterSpacing: "0.12em",
          }}>&gt; BLEND ×</span>
          <select
            value={mimicBlendVibe || ""}
            onChange={e => setMimicBlendVibe(e.target.value || null)}
            style={{
              padding: "5px 10px",
              background: "#000000",
              border: `1px solid ${mimicBlendVibe ? GREEN : GREEN_FAINT}`,
              borderRadius: T.r_sm,
              color: GREEN,
              fontFamily: T.font_mono, fontSize: isMobile ? 16 : 10, fontWeight: 700,
              letterSpacing: "0.08em",
              cursor: "pointer",
              outline: "none",
            }}
          >
            <option value="" style={{ background: "#000", color: GREEN }}>— none (pure pack) —</option>
            {VIBE_META.map(v => (
              <option key={v.id} value={v.id} style={{ background: "#000", color: GREEN }}>
                {v.icon} {v.label} blend
              </option>
            ))}
          </select>
          {mimicBlendVibe && (
            <span style={{
              fontFamily: T.font_mono, fontSize: 10,
              color: GREEN_DIM, flex: 1,
            }}>
              // sonics preserved, mood/energy → {mimicBlendVibe}
            </span>
          )}
        </div>

        {/* ── BY VIBE VIEW ────────────────────────────────────────── */}
        {mimicViewMode === "vibe" && (
          <>
            <div style={{
              display: "flex", flexWrap: "wrap", gap: 4,
              marginBottom: T.s4,
            }}>
              {VIBE_META.map(v => {
                const count = (packsByVibe[v.id] || []).length;
                const active = crossVibeActive === v.id;
                return (
                  <button key={v.id} type="button"
                    onClick={() => { playSwitchSound(); setCrossVibeActive(v.id); }}
                    title={v.tagline}
                    style={{
                      display: "inline-flex", alignItems: "center", gap: 5,
                      padding: "6px 11px",
                      background: active ? `${v.color}1A` : "transparent",
                      border: `1px solid ${active ? v.color : GREEN_FAINT}`,
                      borderRadius: T.r_sm,
                      color: active ? v.color : GREEN_DIM,
                      fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
                      letterSpacing: "0.08em",
                      cursor: "pointer",
                      transition: `all ${T.dur_fast} ${T.ease}`,
                      boxShadow: active ? `0 0 10px ${v.color}44` : "none",
                    }}
                  >
                    <span>{v.icon}</span>
                    <span>{v.label}</span>
                    <span style={{
                      fontSize: 8, color: active ? v.color : "rgba(0, 255, 65, 0.35)",
                      padding: "1px 4px",
                      background: active ? `${v.color}22` : "rgba(0, 255, 65, 0.06)",
                      borderRadius: 2,
                    }}>{count}</span>
                  </button>
                );
              })}
            </div>
            <div style={{
              display: "grid",
              gridTemplateColumns: isMobile ? "1fr 1fr" : "repeat(5, 1fr)",
              gap: T.s2,
            }}>
              {(packsByVibe[crossVibeActive] || []).map(({ artist, pack }) => {
                const vm = VIBE_META.find(v => v.id === pack.vibe);
                const glow = vm?.color || GREEN;
                return (
                  <button key={`${artist.artistId}-${pack.id}`} type="button"
                    onClick={() => applyAndGo(artist, pack)}
                    title={`${artist.artistName} · ${pack.name} · ${pack.vibe}`}
                    style={{
                      display: "flex", flexDirection: "column",
                      alignItems: "flex-start", justifyContent: "space-between",
                      gap: 6,
                      padding: T.s3,
                      minHeight: isMobile ? 80 : 96,
                      background: `linear-gradient(180deg, ${glow}0F 0%, #000000 100%)`,
                      border: `1px solid ${GREEN_FAINT}`,
                      borderRadius: T.r_md,
                      color: GREEN,
                      fontFamily: T.font_mono,
                      cursor: "pointer",
                      textAlign: "left",
                      transition: `all ${T.dur_fast} ${T.ease}`,
                    }}
                    onMouseEnter={e => {
                      e.currentTarget.style.borderColor = glow;
                      e.currentTarget.style.transform = "translateY(-1px)";
                      e.currentTarget.style.boxShadow = `0 0 14px ${glow}33`;
                    }}
                    onMouseLeave={e => {
                      e.currentTarget.style.borderColor = GREEN_FAINT;
                      e.currentTarget.style.transform = "translateY(0)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  >
                    <span style={{ fontSize: 20, lineHeight: 1 }}>{pack.emoji}</span>
                    <div style={{ fontSize: 11, fontWeight: 700, color: GREEN, lineHeight: 1.2 }}>
                      {pack.name}
                    </div>
                    <div style={{
                      fontSize: 9, color: GREEN_DIM,
                      fontWeight: 700, letterSpacing: "0.08em",
                      display: "flex", alignItems: "center", gap: 4,
                    }}>
                      <span>{artist.artistName}</span>
                      <span style={{
                        fontSize: 7,
                        padding: "1px 3px",
                        background: artist.region === "israeli" ? "rgba(0, 255, 65, 0.12)" : "rgba(0, 255, 65, 0.06)",
                        color: artist.region === "israeli" ? GREEN : GREEN_DIM,
                        borderRadius: 2,
                      }}>{artist.region === "israeli" ? "IL" : "INT"}</span>
                    </div>
                  </button>
                );
              })}
            </div>
          </>
        )}

        {/* ── BY ARTIST VIEW ──────────────────────────────────────── */}
        {mimicViewMode === "artist" && (
          <>
            {/* Region filter + search */}
            <div style={{
              display: "flex", alignItems: "center",
              gap: T.s3, flexWrap: "wrap",
              marginBottom: T.s4,
            }}>
              <div style={{ display: "inline-flex", gap: 4 }}>
                {[
                  { id: "all", label: "ALL" },
                  { id: "international", label: "INT" },
                  { id: "israeli", label: "IL" },
                ].map(f => {
                  const count = f.id === "all"
                    ? MIMIC_PACKS.length
                    : MIMIC_PACKS.filter(a => a.region === f.id).length;
                  const active = mimicRegionFilter === f.id;
                  return (
                    <button key={f.id} type="button"
                      onClick={() => { playSwitchSound(); setMimicRegionFilter(f.id); }}
                      style={{
                        padding: "5px 11px",
                        background: active ? GREEN_BG : "transparent",
                        border: `1px solid ${active ? GREEN : GREEN_FAINT}`,
                        borderRadius: T.r_sm,
                        color: active ? GREEN : GREEN_DIM,
                        fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
                        letterSpacing: "0.12em",
                        cursor: "pointer",
                        transition: `all ${T.dur_fast} ${T.ease}`,
                      }}
                    >
                      {f.label}
                      <span style={{
                        marginLeft: 5, fontSize: 8,
                        padding: "1px 4px",
                        background: "rgba(0, 255, 65, 0.08)",
                        borderRadius: 2,
                      }}>{count}</span>
                    </button>
                  );
                })}
              </div>
              <div style={{ position: "relative", flex: 1, minWidth: 160 }}>
                <input type="text" value={mimicSearch}
                  onChange={e => setMimicSearch(e.target.value)}
                  placeholder="/ search artist"
                  style={{
                    width: "100%",
                    padding: isMobile ? "9px 30px 9px 12px" : "7px 30px 7px 12px",
                    background: "#000000",
                    border: `1px solid ${mimicSearch ? GREEN : GREEN_FAINT}`,
                    borderRadius: T.r_sm,
                    color: GREEN,
                    fontFamily: T.font_mono, fontSize: isMobile ? 16 : 11,
                    outline: "none",
                  }}
                />
                {mimicSearch && (
                  <button type="button"
                    onClick={() => setMimicSearch("")}
                    style={{
                      position: "absolute", right: 6, top: "50%",
                      transform: "translateY(-50%)",
                      width: 22, height: 22,
                      background: "transparent", border: "none",
                      color: GREEN_DIM, cursor: "pointer",
                      fontSize: 14, lineHeight: 1,
                    }}
                  >×</button>
                )}
              </div>
              <span style={{
                fontFamily: T.font_mono, fontSize: 10,
                color: GREEN_DIM, letterSpacing: "0.08em",
              }}>
                {filteredMimicArtists.length} shown
              </span>
            </div>

            {/* Artist pill row */}
            {filteredMimicArtists.length === 0 ? (
              <div style={{
                textAlign: "center",
                padding: `${T.s5}px ${T.s3}px`,
                color: GREEN_DIM, fontFamily: T.font_mono, fontSize: 11,
                border: `1px dashed ${GREEN_FAINT}`,
                borderRadius: T.r_md,
                marginBottom: T.s4,
              }}>
                &gt; no artists match the current filter
              </div>
            ) : (
              <div style={{
                display: "flex", flexWrap: "wrap", gap: 6,
                marginBottom: T.s4,
              }}>
                {filteredMimicArtists.map(artist => {
                  const isActive = mimicArtistId === artist.artistId;
                  const isIL = artist.region === "israeli";
                  return (
                    <button key={artist.artistId} type="button"
                      onClick={() => { playSwitchSound(); setMimicArtistId(artist.artistId); }}
                      style={{
                        padding: "7px 12px",
                        background: isActive ? "rgba(0, 255, 65, 0.12)" : "transparent",
                        border: `1px solid ${isActive ? GREEN : GREEN_FAINT}`,
                        borderRadius: T.r_sm,
                        color: isActive ? GREEN : GREEN_DIM,
                        fontFamily: T.font_mono, fontSize: 11, fontWeight: 700,
                        letterSpacing: "0.06em",
                        cursor: "pointer",
                        display: "inline-flex", alignItems: "center", gap: 6,
                        transition: `all ${T.dur_fast} ${T.ease}`,
                        textShadow: isActive ? `0 0 6px ${GREEN_DIM}` : "none",
                      }}
                      onMouseEnter={e => {
                        if (!isActive) {
                          e.currentTarget.style.borderColor = GREEN_DIM;
                          e.currentTarget.style.color = GREEN;
                        }
                      }}
                      onMouseLeave={e => {
                        if (!isActive) {
                          e.currentTarget.style.borderColor = GREEN_FAINT;
                          e.currentTarget.style.color = GREEN_DIM;
                        }
                      }}
                    >
                      {artist.artistName}
                      <span style={{
                        fontSize: 8, fontWeight: 700,
                        letterSpacing: "0.1em",
                        padding: "2px 5px",
                        background: isIL ? "rgba(0, 255, 65, 0.1)" : "rgba(120, 120, 120, 0.12)",
                        color: isIL ? GREEN : "rgba(180, 180, 180, 0.7)",
                        borderRadius: 3, lineHeight: 1,
                      }}>{isIL ? "IL" : "INT"}</span>
                    </button>
                  );
                })}
              </div>
            )}

            {/* Vibe filter */}
            <div style={{
              display: "flex", flexWrap: "wrap", gap: 4,
              marginBottom: T.s3,
            }}>
              <button type="button"
                onClick={() => { playSwitchSound(); setMimicVibeFilter("all"); }}
                style={{
                  display: "inline-flex", alignItems: "center", gap: 5,
                  padding: "5px 10px",
                  background: mimicVibeFilter === "all" ? GREEN_BG : "transparent",
                  border: `1px solid ${mimicVibeFilter === "all" ? GREEN : GREEN_FAINT}`,
                  borderRadius: T.r_sm,
                  color: mimicVibeFilter === "all" ? GREEN : GREEN_DIM,
                  fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
                  letterSpacing: "0.08em", cursor: "pointer",
                  transition: `all ${T.dur_fast} ${T.ease}`,
                }}
              >
                All
                <span style={{
                  fontSize: 8, padding: "1px 4px",
                  background: "rgba(0, 255, 65, 0.1)", borderRadius: 2,
                }}>{activeMimicArtist.packs.length}</span>
              </button>
              {VIBE_META.map(v => {
                const count = activeMimicArtist.packs.filter(p => p.vibe === v.id).length;
                if (count === 0) return null;
                const active = mimicVibeFilter === v.id;
                return (
                  <button key={v.id} type="button"
                    onClick={() => { playSwitchSound(); setMimicVibeFilter(v.id); }}
                    title={v.tagline}
                    style={{
                      display: "inline-flex", alignItems: "center", gap: 5,
                      padding: "5px 10px",
                      background: active ? `${v.color}1A` : "transparent",
                      border: `1px solid ${active ? v.color : GREEN_FAINT}`,
                      borderRadius: T.r_sm,
                      color: active ? v.color : GREEN_DIM,
                      fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
                      letterSpacing: "0.08em", cursor: "pointer",
                      transition: `all ${T.dur_fast} ${T.ease}`,
                    }}
                  >
                    <span>{v.icon}</span>
                    <span>{v.label}</span>
                    <span style={{
                      fontSize: 8, padding: "1px 4px",
                      background: active ? `${v.color}22` : "rgba(0, 255, 65, 0.08)",
                      borderRadius: 2,
                    }}>{count}</span>
                  </button>
                );
              })}
            </div>

            {/* Pack grid */}
            <div style={{
              display: "grid",
              gridTemplateColumns: isMobile ? "1fr 1fr" : "repeat(5, 1fr)",
              gap: T.s2,
            }}>
              {filteredPacks.length === 0 ? (
                <div style={{
                  gridColumn: "1 / -1", textAlign: "center",
                  padding: `${T.s5}px ${T.s3}px`,
                  color: GREEN_DIM, fontFamily: T.font_mono, fontSize: 11,
                  border: `1px dashed ${GREEN_FAINT}`,
                  borderRadius: T.r_md,
                }}>
                  &gt; no packs for {activeMimicArtist.artistName} in {mimicVibeFilter}
                </div>
              ) : filteredPacks.map(pack => (
                <button key={pack.id} type="button"
                  onClick={() => applyAndGo(activeMimicArtist, pack)}
                  title={`${activeMimicArtist.artistName} · ${pack.name} · ${pack.vibe || ""}`}
                  style={{
                    display: "flex", flexDirection: "column",
                    alignItems: "flex-start", justifyContent: "space-between",
                    gap: 6,
                    padding: T.s3,
                    minHeight: isMobile ? 76 : 92,
                    background: "linear-gradient(180deg, rgba(0, 255, 65, 0.04) 0%, #000000 100%)",
                    border: `1px solid ${GREEN_FAINT}`,
                    borderRadius: T.r_md,
                    color: GREEN,
                    fontFamily: T.font_mono,
                    cursor: "pointer",
                    textAlign: "left",
                    transition: `all ${T.dur_fast} ${T.ease}`,
                  }}
                  onMouseEnter={e => {
                    e.currentTarget.style.borderColor = GREEN;
                    e.currentTarget.style.transform = "translateY(-1px)";
                    e.currentTarget.style.boxShadow = `0 0 14px rgba(0, 255, 65, 0.2)`;
                  }}
                  onMouseLeave={e => {
                    e.currentTarget.style.borderColor = GREEN_FAINT;
                    e.currentTarget.style.transform = "translateY(0)";
                    e.currentTarget.style.boxShadow = "none";
                  }}
                >
                  <span style={{ fontSize: 20, lineHeight: 1 }}>{pack.emoji}</span>
                  <span style={{ fontSize: 11, fontWeight: 700, color: GREEN, lineHeight: 1.25 }}>
                    {pack.name}
                  </span>
                  <span style={{
                    fontSize: 9, color: GREEN_DIM, letterSpacing: "0.08em",
                  }}>
                    {pack.state.bpm ? `${pack.state.bpm} BPM` : ""}
                    {pack.state.slots && pack.state.slots[0]?.sub ? ` · ${pack.state.slots[0].sub}` : ""}
                  </span>
                </button>
              ))}
            </div>
          </>
        )}

        {/* ── FOOTER — exit prompt ───────────────────────────────── */}
        <div style={{
          marginTop: T.s8,
          paddingTop: T.s4,
          borderTop: `1px solid ${GREEN_FAINT}`,
          display: "flex", alignItems: "center", justifyContent: "space-between",
          flexWrap: "wrap", gap: T.s3,
        }}>
          <div style={{
            fontSize: 10, color: "rgba(0, 255, 65, 0.3)",
            letterSpacing: "0.12em",
          }}>
            [ end of module · more tools coming: era_picker, future_prompts, dna_editor, credit_grant ]
          </div>
          <button type="button"
            onClick={() => onNavigate && onNavigate("engine")}
            style={{
              padding: "6px 14px",
              background: "transparent",
              border: `1px solid ${GREEN_FAINT}`,
              borderRadius: T.r_sm,
              color: GREEN_DIM,
              fontFamily: T.font_mono, fontSize: 10, fontWeight: 700,
              letterSpacing: "0.12em",
              cursor: "pointer",
              transition: `all ${T.dur_fast} ${T.ease}`,
            }}
            onMouseEnter={e => {
              e.currentTarget.style.borderColor = GREEN;
              e.currentTarget.style.color = GREEN;
            }}
            onMouseLeave={e => {
              e.currentTarget.style.borderColor = GREEN_FAINT;
              e.currentTarget.style.color = GREEN_DIM;
            }}
          >
            &lt; RETURN_TO_ENGINE
          </button>
        </div>
      </div>
    </div>
  );
}

function ShopPage() {
  const { tier, ownedTiers, purchaseTier } = useTier();
  const { refillForTier } = useFuel();
  const { layout } = useLayout();
  const isMobile = layout === "mobile";
  const [feedback, setFeedback] = useState(null);
  const [payModal, setPayModal] = useState(null); // { tierId, billing }
  const [billing, setBilling] = useState("monthly"); // monthly | yearly

  const showFeedback = (ok, text) => {
    setFeedback({ ok, text });
    setTimeout(() => setFeedback(null), 3500);
  };

  const handleSubscribe = (tierId) => {
    setPayModal({ tierId, billing });
  };

  const completePayment = (tierId, bill) => {
    const result = purchaseTier(tierId, bill);
    if (result.ok) {
      refillForTier(tierId);
      const tierLabel = TIERS[tierId].label;
      showFeedback(true, `Welcome to ${tierLabel}! Your subscription is active.`);
      setPayModal(null);
    } else {
      showFeedback(false, result.error);
    }
  };

  const currentHighestRank = Math.max(...[...ownedTiers].map(x => TIER_RANK[x] ?? 0));
  const shopOrder = ["free", "pro", "vip"];

  // Feature lists — hand-authored for each tier, ordered by importance
  const getFeatureList = (tierId) => {
    const f = TIER_FEATURES[tierId];
    if (tierId === "free") {
      return [
        { text: "10 Hits per day", highlight: true },
        { text: "Simple & Moderated modes" },
        { text: "Basic genre slots (1)" },
        { text: "5 options per section" },
        { text: "No locks or favorites", muted: true },
        { text: "No Pop profile meter", muted: true },
      ];
    }
    if (tierId === "pro") {
      return [
        { text: "Unlimited daily Hits", highlight: true },
        { text: "All 5 prompt modes (incl. Chaos)" },
        { text: "3 genre slots" },
        { text: "Full option library" },
        { text: "Locks & favorites" },
        { text: "Pop profile meter" },
        { text: "Shareable prompt links" },
      ];
    }
    if (tierId === "vip") {
      return [
        { text: "Everything in Pro", highlight: true },
        { text: "Unlimited daily Hits" },
        { text: "Batch generation (5 variants)" },
        { text: "JSON export for power users" },
        { text: "The Playbook (deep guides)" },
        { text: "Monthly genre graphs" },
        { text: "Priority feature drops" },
      ];
    }
    return [];
  };

  return (
    <div style={{
      maxWidth: 1100, margin: "0 auto",
      padding: isMobile
        ? `${T.s5}px ${T.s3}px ${T.s8}px`
        : `${T.s9}px ${T.s7}px ${T.s10}px`,
    }}>
      {/* ─ HEADER ─────────────────────────────────────────────── */}
      <div style={{ marginBottom: isMobile ? T.s5 : T.s6 }}>
        <Label color={T.textTer} style={{ display: "block", marginBottom: T.s3 }}>
          Membership · demo pricing · no real charges
        </Label>
        <h1 style={{
          fontSize: isMobile ? "32px" : "clamp(36px, 5vw, 64px)",
          lineHeight: 1.02, letterSpacing: "-0.025em",
          margin: 0, marginBottom: T.s3,
          fontFamily: T.font_display, fontWeight: 400,
          fontStyle: "italic",
        }}>
          Choose your plan.
        </h1>
        <p style={{
          color: T.textSec, fontSize: T.fs_lg, lineHeight: 1.55,
          maxWidth: 640, fontFamily: T.font_sans, margin: 0,
        }}>
          Unlock unlimited Hits, power-user tools, and deeper options.
          Cancel anytime.
        </p>
      </div>

      {/* ─ BILLING TOGGLE (monthly / yearly) ───────────────────── */}
      <div style={{
        display: "inline-flex",
        background: T.surface, border: `1px solid ${T.border}`,
        borderRadius: 10, padding: 4, marginBottom: T.s5,
        position: "relative",
      }}>
        {[
          { id: "monthly", label: "Monthly" },
          { id: "yearly",  label: "Yearly", badge: "SAVE 20%" },
        ].map(b => {
          const active = billing === b.id;
          return (
            <button key={b.id} type="button"
              onClick={() => { playSwitchSound(); setBilling(b.id); }}
              style={{
                display: "inline-flex", alignItems: "center", gap: 8,
                padding: isMobile ? "8px 14px" : "10px 20px",
                background: active ? T.elevated : "transparent",
                border: "none",
                color: active ? T.text : T.textSec,
                fontSize: 13, fontFamily: T.font_sans, fontWeight: 500,
                borderRadius: 8, cursor: "pointer",
                transition: "all 160ms ease-out",
              }}>
              {b.label}
              {b.badge && (
                <span style={{
                  padding: "2px 6px",
                  background: `${V.neonGold}22`,
                  border: `1px solid ${V.neonGold}66`,
                  color: V.neonGold,
                  fontSize: 9, fontFamily: T.font_mono, fontWeight: 700,
                  letterSpacing: "0.15em", borderRadius: 3,
                  textShadow: `0 0 4px ${V.neonGold}66`,
                }}>{b.badge}</span>
              )}
            </button>
          );
        })}
      </div>

      {/* ─ FEEDBACK TOAST ─────────────────────────────────────── */}
      {feedback && (
        <div style={{
          padding: `${T.s3}px ${T.s4}px`,
          marginBottom: T.s5,
          background: feedback.ok ? `${T.success}11` : `${T.danger}11`,
          border: `1px solid ${feedback.ok ? T.success : T.danger}44`,
          borderRadius: T.r_md,
          color: feedback.ok ? T.success : T.danger,
          fontSize: T.fs_md, fontFamily: T.font_sans, fontWeight: 500,
        }}>
          {feedback.text}
        </div>
      )}

      {/* ─ TIER CARDS ─────────────────────────────────────────── */}
      <div style={{
        display: "grid",
        gridTemplateColumns: isMobile ? "1fr" : "repeat(3, 1fr)",
        gap: isMobile ? T.s3 : T.s4,
        marginBottom: T.s7,
      }}>
        {shopOrder.map(tierId => {
          const t = TIERS[tierId];
          const priceData = TIER_PRICE[tierId] || { monthly: 0, yearly: 0 };
          const owned = ownedTiers.has(tierId);
          const tierRank = TIER_RANK[tierId];
          const blockedByHigher = tierRank < currentHighestRank;
          const isFeatured = tierId === "pro"; // highlight Pro as the "most popular" pick
          const disabled = owned || blockedByHigher || tierId === "free";

          // Compute price display based on billing toggle
          const isYearly = billing === "yearly";
          const displayPrice = isYearly
            ? (priceData.yearly / 12).toFixed(2)
            : priceData.monthly.toFixed(2);
          const fullYearlyPrice = priceData.yearly;

          let buttonLabel = isYearly
            ? `SUBSCRIBE — $${fullYearlyPrice}/yr`
            : `SUBSCRIBE — $${priceData.monthly}/mo`;
          if (tierId === "free") buttonLabel = "YOUR PLAN";
          else if (owned) buttonLabel = "● ACTIVE";
          else if (blockedByHigher) buttonLabel = "LOWER THAN CURRENT";

          return (
            <div key={tierId} style={{
              padding: isMobile ? T.s4 : T.s5,
              background: isFeatured
                ? `linear-gradient(180deg, ${t.color}14 0%, transparent 60%), ${T.surface}`
                : `linear-gradient(180deg, ${t.color}0a 0%, transparent 60%), ${T.surface}`,
              border: `1px solid ${owned ? t.color + "88" : isFeatured ? t.color + "55" : T.border}`,
              borderRadius: T.r_lg,
              boxShadow: owned
                ? `0 0 30px ${t.color}22, inset 0 0 20px ${t.color}0a`
                : isFeatured ? `0 0 20px ${t.color}11` : "none",
              position: "relative",
              transition: `all ${T.dur_norm} ${T.ease}`,
            }}>
              {/* Badges */}
              {owned && (
                <div style={{
                  position: "absolute", top: -10, right: T.s3,
                  padding: "3px 8px",
                  background: `${t.color}`, color: T.bg,
                  borderRadius: 4,
                  fontSize: 9, fontFamily: T.font_mono, fontWeight: 700,
                  letterSpacing: "0.2em",
                  boxShadow: `0 0 10px ${t.color}aa`,
                }}>● ACTIVE</div>
              )}
              {!owned && isFeatured && (
                <div style={{
                  position: "absolute", top: -10, right: T.s3,
                  padding: "3px 8px",
                  background: T.accent, color: T.text,
                  borderRadius: 4,
                  fontSize: 9, fontFamily: T.font_mono, fontWeight: 700,
                  letterSpacing: "0.2em",
                  boxShadow: `0 0 10px ${T.accent}aa`,
                }}>MOST POPULAR</div>
              )}

              {/* Tier label */}
              <div style={{
                fontSize: 11, fontFamily: T.font_mono, fontWeight: 700,
                letterSpacing: "0.25em", color: t.color,
                textShadow: `0 0 6px ${t.color}66`, marginBottom: 10,
              }}>
                {t.label.toUpperCase()}
              </div>

              {/* Price */}
              <div style={{ marginBottom: T.s3, display: "flex", alignItems: "baseline", gap: 6 }}>
                {tierId === "free" ? (
                  <span style={{
                    fontSize: 44, fontFamily: T.font_display, fontStyle: "italic",
                    color: T.text, lineHeight: 1,
                  }}>Free</span>
                ) : (
                  <>
                    <span style={{
                      fontSize: 44, fontFamily: T.font_display, fontStyle: "italic",
                      color: T.text, lineHeight: 1, fontWeight: 400,
                    }}>${displayPrice}</span>
                    <span style={{
                      fontSize: 13, color: T.textTer,
                      fontFamily: T.font_sans, fontStyle: "normal",
                    }}>/month</span>
                  </>
                )}
              </div>

              {/* Yearly billing note */}
              {tierId !== "free" && (
                <div style={{
                  fontSize: 11, color: T.textMuted, fontFamily: T.font_mono,
                  marginBottom: T.s4, minHeight: 16,
                  letterSpacing: "0.05em",
                }}>
                  {isYearly
                    ? `Billed $${fullYearlyPrice}/year · save ${yearlySavingsPct(tierId)}%`
                    : "Billed monthly · cancel anytime"}
                </div>
              )}
              {tierId === "free" && (
                <div style={{
                  fontSize: 11, color: T.textMuted, fontFamily: T.font_mono,
                  marginBottom: T.s4, minHeight: 16,
                  letterSpacing: "0.05em",
                }}>Forever free · no card required</div>
              )}

              {/* Description */}
              <div style={{
                color: T.textSec, fontSize: T.fs_md, lineHeight: 1.5,
                marginBottom: T.s4, fontFamily: T.font_sans,
              }}>
                {t.description}
              </div>

              {/* Feature list */}
              <ul style={{
                listStyle: "none", padding: 0, margin: 0, marginBottom: T.s5,
                display: "flex", flexDirection: "column", gap: 7,
              }}>
                {getFeatureList(tierId).map((feat, i) => (
                  <li key={i} style={{
                    display: "flex", alignItems: "flex-start", gap: 8,
                    color: feat.muted ? T.textTer : T.textSec,
                    fontSize: T.fs_sm, fontFamily: T.font_sans,
                    fontWeight: feat.highlight ? 500 : 400,
                  }}>
                    <span style={{
                      color: feat.muted ? T.textMuted : t.color,
                      flexShrink: 0,
                      fontSize: 14, lineHeight: 1.3,
                    }}>{feat.muted ? "○" : "✓"}</span>
                    <span style={feat.highlight ? { color: T.text, fontWeight: 500 } : {}}>
                      {feat.text}
                    </span>
                  </li>
                ))}
              </ul>

              {/* Subscribe button */}
              <button type="button"
                onClick={() => { if (!disabled) { playSwitchSound(); handleSubscribe(tierId); } }}
                disabled={disabled}
                style={{
                  width: "100%",
                  padding: `${T.s3}px ${T.s4}px`,
                  minHeight: 44,
                  background: owned ? `${t.color}22`
                    : disabled ? T.surface
                    : isFeatured
                      ? `linear-gradient(135deg, ${t.color} 0%, ${t.color}dd 100%)`
                      : `linear-gradient(135deg, ${t.color}33 0%, ${t.color}11 100%)`,
                  border: `1px solid ${owned ? t.color + "66" : disabled ? T.border : t.color + "aa"}`,
                  color: owned ? t.color : disabled ? T.textTer : isFeatured ? T.bg : t.color,
                  fontSize: 11, fontFamily: T.font_mono, fontWeight: 700,
                  letterSpacing: "0.18em",
                  cursor: disabled ? "not-allowed" : "pointer",
                  borderRadius: 6,
                  textShadow: disabled || owned || isFeatured ? "none" : `0 0 6px ${t.color}66`,
                  boxShadow: isFeatured && !disabled ? `0 0 16px ${t.color}66` : "none",
                  transition: "all 120ms ease-out",
                }}
                onMouseEnter={e => {
                  if (disabled) return;
                  e.currentTarget.style.background = isFeatured
                    ? `linear-gradient(135deg, ${t.color} 0%, ${t.color} 100%)`
                    : `linear-gradient(135deg, ${t.color}55 0%, ${t.color}22 100%)`;
                }}
                onMouseLeave={e => {
                  if (disabled) return;
                  e.currentTarget.style.background = isFeatured
                    ? `linear-gradient(135deg, ${t.color} 0%, ${t.color}dd 100%)`
                    : `linear-gradient(135deg, ${t.color}33 0%, ${t.color}11 100%)`;
                }}>
                {buttonLabel}
              </button>
            </div>
          );
        })}
      </div>

      {/* ─ COMPARISON / FAQ FOOTER ────────────────────────────── */}
      <div style={{
        padding: T.s5,
        background: T.surface,
        border: `1px solid ${T.border}`,
        borderRadius: T.r_lg,
        marginBottom: T.s5,
      }}>
        <Label color={T.text} style={{ display: "block", marginBottom: T.s3 }}>
          Why subscribe?
        </Label>
        <div style={{
          color: T.textSec, fontSize: T.fs_md, lineHeight: 1.6,
          fontFamily: T.font_sans,
        }}>
          HIT-ENGINE generates deterministic prompt structures that get better results
          from modern AI music generators — less trial-and-error, fewer
          wasted credits on those platforms. Pro pays for itself after a handful of
          cleaner prompts.
        </div>
      </div>

      {/* PAYMENT MODAL */}
      {payModal && (
        <PaymentModal
          tierId={payModal.tierId}
          billing={payModal.billing}
          onClose={() => setPayModal(null)}
          onComplete={(bill) => completePayment(payModal.tierId, bill)}
        />
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// PAYMENT MODAL — simulated prod-ready checkout flow
// Three tabs: Credits (in-app), Card (Stripe-style), PayPal
// Card form has validation + processing spinner + success animation
// ════════════════════════════════════════════════════════════════════════════
function PaymentModal({ tierId, billing, onClose, onComplete }) {
  const t = TIERS[tierId];
  const priceData = TIER_PRICE[tierId] || { monthly: 0, yearly: 0 };
  const isYearly = billing === "yearly";
  const chargeAmount = isYearly ? priceData.yearly : priceData.monthly;
  const displayAmount = chargeAmount.toFixed(2);
  const [method, setMethod] = useState("card");
  const [stage, setStage] = useState("form"); // form | processing | success

  // Card form fields
  const [cardNumber, setCardNumber] = useState("");
  const [cardExpiry, setCardExpiry] = useState("");
  const [cardCvc, setCardCvc] = useState("");
  const [cardName, setCardName] = useState("");
  const [email, setEmail] = useState("");
  const [errors, setErrors] = useState({});

  // Auto-format card number in groups of 4
  const formatCardNumber = (v) => v.replace(/\s/g, "").replace(/(.{4})/g, "$1 ").trim().slice(0, 19);
  const formatExpiry = (v) => {
    const digits = v.replace(/\D/g, "").slice(0, 4);
    return digits.length > 2 ? `${digits.slice(0,2)}/${digits.slice(2)}` : digits;
  };

  const validate = () => {
    const e = {};
    const numClean = cardNumber.replace(/\s/g, "");
    if (numClean.length < 13 || numClean.length > 19) e.cardNumber = "Invalid card number";
    if (!/^\d{2}\/\d{2}$/.test(cardExpiry)) e.cardExpiry = "MM/YY";
    if (!/^\d{3,4}$/.test(cardCvc)) e.cardCvc = "Invalid";
    if (!cardName.trim()) e.cardName = "Required";
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) e.email = "Invalid email";
    return e;
  };

  const handleSubmit = () => {
    if (method === "card") {
      const e = validate();
      if (Object.keys(e).length) { setErrors(e); return; }
    }
    setErrors({});
    setStage("processing");
    setTimeout(() => {
      setStage("success");
      setTimeout(() => onComplete(billing), 1100);
    }, 1400);
  };

  // Close on ESC
  useEffect(() => {
    const h = (e) => { if (e.key === "Escape" && stage === "form") onClose(); };
    window.addEventListener("keydown", h);
    return () => window.removeEventListener("keydown", h);
  }, [stage, onClose]);

  return (
    <div
      onClick={stage === "form" ? onClose : undefined}
      style={{
        position: "fixed", inset: 0,
        background: "rgba(0,0,0,0.72)",
        backdropFilter: "blur(12px)",
        display: "grid", placeItems: "center",
        padding: 12,
        zIndex: 10000,
        animation: "payModalBgIn 240ms ease-out",
        overflowY: "auto",
      }}>
      <style>{`
        @keyframes payModalBgIn { from { opacity: 0; } to { opacity: 1; } }
        @keyframes payModalCardIn {
          from { opacity: 0; transform: translateY(16px) scale(0.97); }
          to   { opacity: 1; transform: translateY(0) scale(1); }
        }
        @keyframes paySpin { to { transform: rotate(360deg); } }
        @keyframes paySuccessPop {
          0%   { transform: scale(0.3); opacity: 0; }
          60%  { transform: scale(1.12); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
      `}</style>
      <div
        onClick={e => e.stopPropagation()}
        style={{
          width: "100%", maxWidth: 440,
          maxHeight: "calc(100vh - 24px)",
          overflowY: "auto",
          background: "linear-gradient(180deg, #0f1014 0%, #0a0b0e 100%)",
          border: `1px solid ${T.border}`,
          borderRadius: 14,
          padding: 0,
          boxShadow: "0 40px 80px rgba(0,0,0,0.7), 0 0 0 1px rgba(255,255,255,0.04)",
          animation: "payModalCardIn 320ms cubic-bezier(0.16, 1, 0.3, 1)",
          position: "relative",
        }}>
        {/* Accent strip */}
        <div style={{
          height: 3,
          background: `linear-gradient(90deg, ${t.color} 0%, ${t.color}aa 50%, ${t.color} 100%)`,
          boxShadow: `0 0 14px ${t.color}88`,
        }} />

        {stage === "form" && (
          <>
            {/* Header */}
            <div style={{ padding: "20px 24px 16px", borderBottom: `1px solid ${T.border}` }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                <div>
                  <div style={{
                    fontSize: 9, fontFamily: T.font_mono, fontWeight: 700,
                    letterSpacing: "0.22em", color: T.textMuted, marginBottom: 6,
                  }}>SECURE CHECKOUT</div>
                  <div style={{
                    fontSize: 20, fontFamily: T.font_sans, fontWeight: 600,
                    color: T.text, lineHeight: 1.1,
                  }}>
                    Subscribe to <span style={{ color: t.color }}>{t.label}</span>
                  </div>
                  <div style={{
                    fontSize: 13, fontFamily: T.font_sans, color: T.textSec, marginTop: 4,
                  }}>
                    {isYearly ? "Annual plan · save " + yearlySavingsPct(tierId) + "%" : "Monthly plan · cancel anytime"}
                  </div>
                </div>
                <button type="button" onClick={() => { playSwitchSound(); onClose(); }}
                  aria-label="Close"
                  style={{
                    background: "transparent", border: "none", color: T.textTer,
                    fontSize: 20, lineHeight: 1, cursor: "pointer", padding: 4,
                  }}>×</button>
              </div>
              <div style={{
                marginTop: 14, padding: "12px 14px",
                background: T.surface, border: `1px solid ${T.border}`,
                borderRadius: 8,
              }}>
                <div style={{
                  display: "flex", justifyContent: "space-between",
                  alignItems: "baseline", marginBottom: isYearly ? 6 : 0,
                }}>
                  <span style={{ fontSize: 13, color: T.textSec, fontFamily: T.font_sans }}>
                    {isYearly ? "Annual subscription" : "Monthly subscription"}
                  </span>
                  <span style={{ fontSize: 20, fontWeight: 600, color: t.color, fontFamily: T.font_sans }}>
                    ${displayAmount}
                  </span>
                </div>
                {isYearly && (
                  <div style={{
                    fontSize: 11, color: T.textMuted, fontFamily: T.font_mono,
                    letterSpacing: "0.05em",
                  }}>
                    ${(priceData.yearly / 12).toFixed(2)}/month · billed annually
                  </div>
                )}
              </div>
            </div>

            {/* Method tabs — Card + PayPal only */}
            <div style={{
              display: "grid", gridTemplateColumns: "1fr 1fr",
              borderBottom: `1px solid ${T.border}`,
            }}>
              {[
                { id: "card",    label: "Card",    icon: "▮" },
                { id: "paypal",  label: "PayPal",  icon: "P" },
              ].map(m => (
                <button key={m.id} type="button"
                  onClick={() => { playSwitchSound(); setMethod(m.id); }}
                  style={{
                    padding: "12px 8px",
                    background: method === m.id ? T.surface : "transparent",
                    border: "none",
                    borderBottom: `2px solid ${method === m.id ? t.color : "transparent"}`,
                    color: method === m.id ? T.text : T.textSec,
                    fontSize: 12, fontFamily: T.font_sans, fontWeight: 500,
                    cursor: "pointer",
                    transition: "all 160ms ease-out",
                    display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
                  }}>
                  <span style={{ fontSize: 11 }}>{m.icon}</span> {m.label}
                </button>
              ))}
            </div>

            {/* Form body */}
            <div style={{ padding: "20px 24px" }}>
              {method === "card" && (
                <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                  <PayField label="Email receipt" value={email} onChange={setEmail}
                    placeholder="you@example.com" error={errors.email} />
                  <PayField label="Card number" value={cardNumber}
                    onChange={v => setCardNumber(formatCardNumber(v))}
                    placeholder="4242 4242 4242 4242" error={errors.cardNumber}
                    suffix={<span style={{ fontSize: 9, color: T.textMuted, letterSpacing: "0.1em" }}>VISA · MC · AMEX</span>} />
                  <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                    <PayField label="Expiry" value={cardExpiry}
                      onChange={v => setCardExpiry(formatExpiry(v))}
                      placeholder="MM/YY" error={errors.cardExpiry} />
                    <PayField label="CVC" value={cardCvc}
                      onChange={v => setCardCvc(v.replace(/\D/g,"").slice(0,4))}
                      placeholder="123" error={errors.cardCvc} />
                  </div>
                  <PayField label="Name on card" value={cardName} onChange={setCardName}
                    placeholder="Full name" error={errors.cardName} />
                </div>
              )}

              {method === "paypal" && (
                <div style={{ textAlign: "center", padding: "12px 0 8px" }}>
                  <div style={{
                    fontSize: 13, color: T.textSec, fontFamily: T.font_sans,
                    marginBottom: 16, lineHeight: 1.5,
                  }}>
                    You'll be redirected to PayPal to complete the subscription of <strong style={{ color: T.text }}>${displayAmount}</strong>
                    {isYearly ? " for the first year." : " for your first month."}
                  </div>
                </div>
              )}

              {/* Submit button */}
              <button type="button"
                onClick={() => { playSwitchSound(); handleSubmit(); }}
                style={{
                  marginTop: 18, width: "100%",
                  padding: "14px",
                  minHeight: 48,
                  background: `linear-gradient(180deg, ${t.color} 0%, ${t.color}cc 100%)`,
                  border: `1px solid ${t.color}`,
                  color: "#000",
                  fontFamily: T.font_sans, fontSize: 14, fontWeight: 700,
                  letterSpacing: "0.02em",
                  cursor: "pointer",
                  borderRadius: 8,
                  boxShadow: `0 4px 14px ${t.color}55, inset 0 1px 0 rgba(255,255,255,0.3)`,
                  transition: "transform 100ms ease-out",
                }}
                onMouseDown={e => e.currentTarget.style.transform = "translateY(1px)"}
                onMouseUp={e => e.currentTarget.style.transform = "translateY(0)"}
              >
                {method === "paypal"
                  ? `Continue to PayPal · $${displayAmount}`
                  : `Subscribe · $${displayAmount}`}
              </button>

              {/* Billing note */}
              <div style={{
                marginTop: 10,
                fontSize: 11, color: T.textMuted, fontFamily: T.font_sans,
                textAlign: "center", lineHeight: 1.5,
              }}>
                {isYearly
                  ? `You'll be charged $${displayAmount} today, then $${displayAmount} each year. Cancel anytime.`
                  : `You'll be charged $${displayAmount} today, then $${displayAmount} each month. Cancel anytime.`}
              </div>

              {/* Trust row */}
              <div style={{
                marginTop: 14, display: "flex", justifyContent: "center",
                alignItems: "center", gap: 14,
                fontSize: 10, color: T.textMuted, fontFamily: T.font_mono, letterSpacing: "0.12em",
              }}>
                <span>🔒 SSL</span>
                <span>·</span>
                <span>PCI DSS</span>
                <span>·</span>
                <span>CANCEL ANYTIME</span>
              </div>
              <div style={{
                marginTop: 10, padding: "6px 10px",
                background: `${T.warning}08`,
                border: `1px dashed ${T.warning}33`,
                borderRadius: 6,
                fontSize: 10, fontFamily: T.font_mono,
                color: T.warning, textAlign: "center", letterSpacing: "0.1em",
              }}>
                DEMO — NO REAL PAYMENT PROCESSED
              </div>
            </div>
          </>
        )}

        {stage === "processing" && (
          <div style={{ padding: "60px 24px", textAlign: "center" }}>
            <div style={{
              width: 48, height: 48, margin: "0 auto 20px",
              border: `3px solid ${T.border}`,
              borderTopColor: t.color,
              borderRadius: "50%",
              animation: "paySpin 0.8s linear infinite",
              boxShadow: `0 0 20px ${t.color}44`,
            }} />
            <div style={{
              fontSize: 14, fontFamily: T.font_sans, fontWeight: 500,
              color: T.text, marginBottom: 6,
            }}>Processing subscription…</div>
            <div style={{ fontSize: 11, color: T.textTer, fontFamily: T.font_mono, letterSpacing: "0.1em" }}>
              DO NOT CLOSE THIS WINDOW
            </div>
          </div>
        )}

        {stage === "success" && (
          <div style={{ padding: "60px 24px", textAlign: "center" }}>
            <div style={{
              width: 64, height: 64, margin: "0 auto 20px",
              borderRadius: "50%",
              background: `${t.color}22`,
              border: `2px solid ${t.color}`,
              display: "grid", placeItems: "center",
              fontSize: 32, color: t.color,
              animation: "paySuccessPop 500ms cubic-bezier(0.34, 1.56, 0.64, 1)",
              boxShadow: `0 0 30px ${t.color}66`,
            }}>✓</div>
            <div style={{
              fontSize: 18, fontFamily: T.font_sans, fontWeight: 600,
              color: t.color, marginBottom: 6,
            }}>Subscription active</div>
            <div style={{ fontSize: 13, color: T.textSec, fontFamily: T.font_sans }}>
              Welcome to {t.label}…
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// Helper: a single labeled field for PaymentModal. Keeps the modal readable.
function PayField({ label, value, onChange, placeholder, error, suffix }) {
  return (
    <label style={{ display: "block" }}>
      <div style={{
        fontSize: 10, fontFamily: T.font_mono, fontWeight: 600,
        letterSpacing: "0.14em", color: T.textTer, marginBottom: 5,
        display: "flex", justifyContent: "space-between", alignItems: "center",
      }}>
        <span>{label.toUpperCase()}</span>
        {suffix}
      </div>
      <input
        type="text" value={value} onChange={e => onChange(e.target.value)}
        placeholder={placeholder}
        style={{
          width: "100%",
          padding: "12px 12px",
          background: T.bg,
          border: `1px solid ${error ? T.danger : T.border}`,
          color: T.text,
          fontSize: 16, fontFamily: T.font_sans, // 16px prevents iOS zoom on focus
          borderRadius: 6,
          outline: "none",
          boxSizing: "border-box",
          transition: "border-color 140ms ease-out",
          WebkitAppearance: "none",
        }}
        onFocus={e => e.currentTarget.style.borderColor = error ? T.danger : T.borderFocus}
        onBlur={e => e.currentTarget.style.borderColor = error ? T.danger : T.border}
      />
      {error && (
        <div style={{ fontSize: 11, color: T.danger, fontFamily: T.font_sans, marginTop: 4 }}>
          {error}
        </div>
      )}
    </label>
  );
}


